/* AUTO-GENERATED — New Mexico Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["NM"] = {"code":"NM","name":"New Mexico","agency":"New Mexico MVD","agencyShort":"MVD","handbook":"https://www.mvd.newmexico.gov/wp-content/uploads/2025/08/000-Combined-CDL-Driver-Manual-with-Supp-3-2025.pdf","links":{},"en":[{"q":"On New Mexico highways, what is the maximum legal width of a commercial vehicle or its load (excluding mirrors and certain safety devices) without an oversize permit?","options":["8 feet 6 inches (102 inches)","8 feet (96 inches)","9 feet (108 inches)","10 feet (120 inches)"],"answer":0,"explanation":"New Mexico limits total outside width of a vehicle or load to 8 feet 6 inches (102 inches), excluding mirrors and approved safety appliances. A wider load requires an oversize permit. Source: NMSA 1978, Section 66-7-402 (Width of vehicles); NM CDL Manual.","handbook":"","hbref":""},{"q":"What is the maximum legal height of a vehicle and its load on New Mexico highways without a permit?","options":["14 feet","13 feet 6 inches","15 feet","13 feet"],"answer":0,"explanation":"New Mexico sets the maximum vehicle-and-load height at 14 feet. Loads above 14 feet require an oversize (over-height) permit. Source: NMSA 1978, Section 66-7-404 (Height and length of vehicles and loads).","handbook":"","hbref":""},{"q":"What is the maximum gross weight on any one single axle of a commercial vehicle under New Mexico statute?","options":["21,600 pounds","20,000 pounds","22,400 pounds","18,000 pounds"],"answer":0,"explanation":"New Mexico's single-axle limit is 21,600 pounds, which is higher than the 20,000-pound federal Interstate single-axle limit. Source: NMSA 1978, Section 66-7-409 (Load limits on single axles, wheels and tires).","handbook":"","hbref":""},{"q":"Under New Mexico law, what is the maximum allowed weight on a tandem axle set (two axles spaced 4 feet apart)?","options":["34,320 pounds","34,000 pounds","36,000 pounds","32,000 pounds"],"answer":0,"explanation":"New Mexico's axle-group weight table allows 34,320 pounds on a tandem (two axles spaced about 4 feet apart), slightly above the 34,000-pound federal Interstate tandem limit. Source: NMSA 1978, Section 66-7-410 (Gross weight of vehicles and loads).","handbook":"","hbref":""},{"q":"What is the maximum overall length of a truck-trailer combination on New Mexico highways without a permit?","options":["65 feet","60 feet","70 feet","75 feet"],"answer":0,"explanation":"New Mexico limits an overall combination (truck plus trailer) to 65 feet on highways generally; longer combinations need an oversize permit. Source: NMSA 1978, Section 66-7-404 (Height and length of vehicles and loads).","handbook":"","hbref":""},{"q":"On New Mexico's Interstate (federal-aid) highway system, what is the maximum gross vehicle weight allowed without an overweight permit?","options":["80,000 pounds","86,400 pounds","84,000 pounds","90,000 pounds"],"answer":0,"explanation":"On the Interstate system, New Mexico applies the federal cap of 80,000 pounds gross. The state's own statutory table allows somewhat more on certain non-Interstate state highways, but 80,000 pounds is the Interstate maximum without a permit. Source: 23 U.S.C. 127 as applied in New Mexico; NMSA 1978, Section 66-7-410.","handbook":"","hbref":""},{"q":"Under New Mexico's statutory gross-weight table, what is the maximum gross weight allowed (with sufficient axle spacing of about 56 feet or more) on a non-Interstate state highway without a special permit?","options":["86,400 pounds","80,000 pounds","94,000 pounds","84,000 pounds"],"answer":0,"explanation":"New Mexico's gross-weight table tops out at 86,400 pounds when the distance between the first and last axles is roughly 56 feet or more on non-Interstate state highways. The Interstate system remains capped at the federal 80,000 pounds. Source: NMSA 1978, Section 66-7-410 (Gross weight of vehicles and loads).","handbook":"","hbref":""},{"q":"What is the maximum length of a semitrailer operating on designated New Mexico highways (the National Network) without a permit?","options":["57 feet 6 inches","53 feet","48 feet","60 feet"],"answer":0,"explanation":"New Mexico allows a semitrailer up to 57 feet 6 inches on designated National Network routes. Source: NMSA 1978, Section 66-7-404 (Height and length of vehicles and loads); NM CDL Manual.","handbook":"","hbref":""},{"q":"In New Mexico, which formula is used on the Interstate system to determine the maximum allowable gross weight on a group of consecutive axles?","options":["The Federal Bridge Formula","The Net-Tonnage Rule","The Axle-Spacing Quotient","The Gross-Combination Ratio"],"answer":0,"explanation":"On the Interstate system, New Mexico applies the Federal Bridge Formula, W = 500[(LN/(N-1)) + 12N + 36], which limits weight on any group of axles based on the spacing (L) and number (N) of axles. Source: 23 U.S.C. 127 / FBF as applied in New Mexico; NM CDL Manual.","handbook":"","hbref":""},{"q":"Who issues oversize/overweight permits for commercial vehicles operating on New Mexico state highways?","options":["The New Mexico Department of Transportation (NMDOT)","The county sheriff's office","The Federal Motor Carrier Safety Administration","The local city public works department"],"answer":0,"explanation":"Oversize and overweight permits in New Mexico are issued by the New Mexico Department of Transportation (NMDOT), administered through its Ports of Entry / permitting unit and online permitting system. Source: NMDOT Permits / Ports of Entry; NMSA 1978, Section 66-7-413.","handbook":"","hbref":""},{"q":"A carrier needs to move a single indivisible load that exceeds New Mexico's legal weight limits. What must the carrier obtain before the trip?","options":["An NMDOT overweight (special) permit","A new CDL endorsement","A federal Interstate waiver from FMCSA","Only proof of cargo insurance"],"answer":0,"explanation":"Moving a load above New Mexico's legal size or weight limits requires a special (oversize/overweight) permit from NMDOT, generally for non-divisible loads. Source: NMSA 1978, Section 66-7-413; NMDOT Permits.","handbook":"","hbref":""},{"q":"Under New Mexico's single-axle rules, what is the maximum weight allowed on any single wheel?","options":["11,000 pounds","10,000 pounds","12,500 pounds","9,000 pounds"],"answer":0,"explanation":"New Mexico limits the load on any single wheel to 11,000 pounds, as part of its single-axle, wheel, and tire load rules. Source: NMSA 1978, Section 66-7-409 (Load limits on single axles, wheels and tires).","handbook":"","hbref":""},{"q":"New Mexico's tire-load rule limits weight to how much per inch of tire width?","options":["600 pounds per inch of tire width","500 pounds per inch of tire width","800 pounds per inch of tire width","1,000 pounds per inch of tire width"],"answer":0,"explanation":"New Mexico limits tire loading to 600 pounds per inch of tire width as part of its axle, wheel, and tire load limits. Source: NMSA 1978, Section 66-7-409 (Load limits on single axles, wheels and tires).","handbook":"","hbref":""},{"q":"An oversize/overweight permit in New Mexico is most commonly issued for which durations?","options":["A single trip or an annual period","A single trip only, never longer","A maximum of 30 days only","Permanently, with no expiration"],"answer":0,"explanation":"New Mexico oversize/overweight permits are typically issued either as single-trip permits or as annual permits, depending on the movement. Source: NMDOT Permits / Ports of Entry; NMSA 1978, Section 66-7-413.","handbook":"","hbref":""},{"q":"Under the Federal Bridge Formula as applied on New Mexico Interstates, what do the variables L and N represent?","options":["L = distance in feet between outer axles of a group; N = number of axles in the group","L = load in pounds; N = number of tires","L = trailer length; N = net weight in tons","L = legal limit; N = number of permits held"],"answer":0,"explanation":"In the Federal Bridge Formula, L is the distance in feet between the extremes (first and last axles) of any group of two or more consecutive axles, and N is the number of axles in that group. Source: 23 U.S.C. 127 / FBF as applied in New Mexico; NM CDL Manual.","handbook":"","hbref":""},{"q":"A semitrailer load measures 8 feet 8 inches wide. What is required to move it legally on New Mexico highways?","options":["An NMDOT oversize (over-width) permit","Nothing; it is within the legal width","Only a wide-load flag, no permit","A change to a Class A CDL"],"answer":0,"explanation":"New Mexico's legal width limit is 8 feet 6 inches; at 8 feet 8 inches the load exceeds it, so an NMDOT over-width oversize permit is required. Source: NMSA 1978, Section 66-7-402; NMDOT Permits.","handbook":"","hbref":""},{"q":"When width or length thresholds are exceeded, New Mexico may require escort (pilot) vehicles. Above what width does New Mexico generally require escorts for a moving load?","options":["More than 14 feet wide","More than 10 feet wide","More than 8 feet 6 inches wide","More than 20 feet wide"],"answer":0,"explanation":"New Mexico generally requires escort/pilot vehicles for loads exceeding 14 feet in width (and for loads exceeding about 90 feet in length). Source: NMDOT oversize permit movement requirements.","handbook":"","hbref":""},{"q":"How does a carrier most commonly apply for an oversize/overweight permit in New Mexico today?","options":["Through NMDOT's online permitting system","By mailing a paper form to the Governor's office","By calling FMCSA in Washington, D.C.","Only in person at a county courthouse"],"answer":0,"explanation":"New Mexico oversize/overweight permits are obtained primarily through NMDOT's online permitting system, where carriers enter load dimensions, weight, route, and travel dates. Source: NMDOT Permits / Ports of Entry.","handbook":"","hbref":""},{"q":"New Mexico's gross-weight figures differ from the federal Interstate standard. Compared with the 20,000-pound federal Interstate single-axle limit, New Mexico's statutory single-axle limit is:","options":["Higher, at 21,600 pounds","Lower, at 18,000 pounds","Identical, at 20,000 pounds","Higher, at 25,000 pounds"],"answer":0,"explanation":"New Mexico's statutory single-axle limit is 21,600 pounds, higher than the 20,000-pound federal Interstate single-axle limit. The lower federal figure still governs on the Interstate system itself. Source: NMSA 1978, Section 66-7-409; 23 U.S.C. 127.","handbook":"","hbref":""},{"q":"In New Mexico, a Class A CDL is required to operate any combination of vehicles with a Gross Combination Weight Rating (GCWR) of at least what value, when the towed unit(s) exceed 10,000 lbs GVWR?","options":["26,001 or more pounds","10,001 or more pounds","18,001 or more pounds","33,001 or more pounds"],"answer":0,"explanation":"A New Mexico Class A CDL authorizes driving any combination of vehicles with a GCWR of 26,001 or more pounds, provided the GVWR of the unit(s) being towed exceeds 10,000 pounds. Source: NM MVD Driver Manual Chapter 5 (Commercial Driver License).","handbook":"","hbref":""},{"q":"Which New Mexico CDL class authorizes driving a single vehicle with a GVWR of 26,001 or more pounds, or such a vehicle towing a unit not over 10,000 lbs GVWR?","options":["Class B","Class A","Class C","Class D"],"answer":0,"explanation":"A New Mexico Class B CDL covers any single vehicle with a GVWR of 26,001 or more pounds, or such a vehicle towing a unit not in excess of 10,000 pounds GVWR. A combination over 26,001 GCWR towing more than 10,000 lbs requires Class A. Source: NM MVD Driver Manual Chapter 5.","handbook":"","hbref":""},{"q":"A New Mexico Class C CDL applies to a vehicle under 26,001 lbs GVWR only when it is used for which purpose?","options":["Carrying 16 or more passengers (including driver) or placarded hazardous materials","Towing any trailer over 5,000 lbs","Carrying 9 or more passengers for hire","Operating across state lines for any cargo"],"answer":0,"explanation":"A New Mexico Class C CDL applies to a single vehicle less than 26,001 lbs GVWR (or towing a unit not over 10,000 lbs) only when designed to transport 16 or more passengers including the driver, or when placarded for hazardous materials. Source: NM MVD Driver Manual Chapter 5.","handbook":"","hbref":""},{"q":"Under federal rules adopted by New Mexico, a Commercial Learner Permit (CLP) holder may NOT take the CDL skills test until at least how many days after the CLP is initially issued?","options":["14 days","7 days","30 days","10 days"],"answer":0,"explanation":"The CLP holder is not eligible to take the CDL skills test in the first 14 days after initial issuance of the CLP. New Mexico applies this federal 14-day hold. Source: NM MVD Driver Manual Chapter 5; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"What is the minimum age to be issued a New Mexico CDL restricted to intrastate (within New Mexico) commerce only?","options":["18 years old","21 years old","16 years old","19 years old"],"answer":0,"explanation":"An applicant must be at least 18 to hold a New Mexico CDL limited to intrastate commerce. A driver who is 18-20 receives a 'K' restriction limiting them to driving only within New Mexico. Source: NM MVD Driver Manual Chapter 5.","handbook":"","hbref":""},{"q":"What is the minimum age to be issued a New Mexico CDL for interstate (across state lines) commerce?","options":["21 years old","18 years old","23 years old","25 years old"],"answer":0,"explanation":"A driver must be at least 21 to operate a commercial motor vehicle in interstate commerce. New Mexico drivers aged 18-20 are limited to intrastate operation. Source: NM MVD Driver Manual Chapter 5; 49 CFR 391.11.","handbook":"","hbref":""},{"q":"On a New Mexico CDL, what does the 'K' restriction indicate about the driver?","options":["Limited to intrastate commerce only","Restricted to vehicles without air brakes","Restricted to automatic-transmission vehicles","May not carry passengers"],"answer":0,"explanation":"New Mexico places a 'K' restriction on CDLs issued to applicants aged 18-20, limiting the driver to intrastate (within New Mexico) commerce only. Source: NM MVD Driver Manual Chapter 5.","handbook":"","hbref":""},{"q":"Which endorsement is required on a New Mexico CDL to operate a tank vehicle hauling liquid or gaseous materials in bulk?","options":["N (Tank Vehicle)","T (Doubles/Triples)","H (Hazardous Materials)","P (Passenger)"],"answer":0,"explanation":"The N endorsement authorizes operation of a tank vehicle used to transport liquid or gaseous materials in bulk. The N endorsement may be added on a CLP after passing the required knowledge test. Source: NM MVD Driver Manual Chapter 5.","handbook":"","hbref":""},{"q":"Which New Mexico CDL endorsement is required to pull two or three trailers behind a single power unit?","options":["T (Doubles/Triples)","N (Tank Vehicle)","S (School Bus)","X (Combination)"],"answer":0,"explanation":"The T endorsement authorizes pulling double or triple trailers and requires passing a knowledge test. Source: NM MVD Driver Manual Chapter 5; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"Which endorsement does a New Mexico CDL holder need to drive a commercial vehicle designed to carry 16 or more people, including the driver?","options":["P (Passenger)","S (School Bus)","N (Tank Vehicle)","T (Doubles/Triples)"],"answer":0,"explanation":"The P (Passenger) endorsement is required to drive a vehicle designed to transport 16 or more passengers including the driver. The skills test must be taken in a vehicle representative of that class. Source: NM MVD Driver Manual Chapter 5; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"Before being issued the H (Hazardous Materials) endorsement, a New Mexico applicant must clear which security screening?","options":["A TSA fingerprint-based background/threat assessment via Universal Enroll","An FBI most-wanted list comparison only","A state-police-only criminal records check","A New Mexico MVD interview with no fingerprints"],"answer":0,"explanation":"New Mexico MVD may not issue the HazMat (H) endorsement until the applicant completes a TSA fingerprint-based background check (Hazardous Materials Endorsement Threat Assessment) through the Universal Enroll system and TSA determines the applicant is not a security threat. Source: NM MVD Hazardous Material Endorsement page; 49 CFR 1572.","handbook":"","hbref":""},{"q":"For a first-time HazMat (H) endorsement in New Mexico, ELDT requires the applicant to complete which training before the knowledge test?","options":["Hazardous materials theory training with a provider on the FMCSA Training Provider Registry","Behind-the-wheel range training only","A 40-hour in-person HazMat road course","No training; only the TSA background check"],"answer":0,"explanation":"First-time H endorsement applicants must complete HazMat theory training (no behind-the-wheel component is required for H) from a provider listed on the FMCSA Training Provider Registry before taking the knowledge test. Source: NM MVD Driver Manual Chapter 5; 49 CFR 380.725.","handbook":"","hbref":""},{"q":"ELDT requirements apply to first-time New Mexico applicants who applied for an initial CLP on or after which date?","options":["February 7, 2022","January 1, 2020","September 30, 2021","July 1, 2023"],"answer":0,"explanation":"All applicants for a first-time CLP on or after February 7, 2022 must comply with the federal Entry-Level Driver Training (ELDT) rules in 49 CFR 380.600-380.603. Source: NM MVD Driver Manual Chapter 5.","handbook":"","hbref":""},{"q":"Where must a New Mexico ELDT applicant obtain the required entry-level driver training to count toward CDL/endorsement eligibility?","options":["From a provider listed on the FMCSA Training Provider Registry (TPR)","From any commercial driving school of the applicant's choice","From the New Mexico MVD field office directly","From an employer's in-house program, with no registry required"],"answer":0,"explanation":"ELDT must be completed with a provider listed on the FMCSA Training Provider Registry (TPR) at tpr.fmcsa.dot.gov; the provider submits the certification to FMCSA. Source: NM MVD Driver Manual Chapter 5; FMCSA TPR.","handbook":"","hbref":""},{"q":"A New Mexico self-certification of 'Non-Excepted Interstate' (NI) means the driver operates in interstate commerce and:","options":["Must meet the federal DOT medical card requirements","Does not have to meet any medical requirements","Only meets New Mexico state medical requirements","Is exempt because they drive a farm vehicle"],"answer":0,"explanation":"Selecting Non-Excepted Interstate (NI) certifies the driver operates in interstate commerce and is required to meet the federal DOT medical examiner's certificate requirements. Source: NM MVD Driver Manual Chapter 5 (Medical Self-Certification).","handbook":"","hbref":""},{"q":"Which New Mexico medical self-certification category applies to a driver who operates only within New Mexico and is NOT required to meet New Mexico's medical requirements?","options":["EA (Excepted Intrastate)","NA (Non-Excepted Intrastate)","NI (Non-Excepted Interstate)","EI (Excepted Interstate)"],"answer":0,"explanation":"Excepted Intrastate (EA) means the driver operates only within New Mexico and does not have to meet the State of New Mexico medical requirements. NA would require meeting NM medical requirements. Source: NM MVD Driver Manual Chapter 5.","handbook":"","hbref":""},{"q":"Besides identity and lawful presence, which document set must a New Mexico CDL applicant present to prove residency?","options":["Two proofs of physical residency showing a New Mexico address","One utility bill older than one year","A single out-of-state lease agreement","A voter registration card from any state"],"answer":0,"explanation":"New Mexico requires two proofs of physical residency showing a New Mexico address, along with proof of identity, lawful presence/U.S. citizenship, and a Social Security number. Source: NM MVD Driver Manual Chapter 5; NM CDL Acceptable Documents list.","handbook":"","hbref":""},{"q":"To document a Social Security Number for a New Mexico CDL, an applicant should provide which of the following?","options":["A Social Security card or valid proof of the SSN","A passport photo page only","Two utility bills","A birth certificate alone"],"answer":0,"explanation":"New Mexico requires a Social Security card or other valid proof of the Social Security Number as part of CDL application documents (along with identity, lawful presence, and two residency proofs). Source: NM MVD Driver Manual Chapter 5; NM CDL Acceptable Documents.","handbook":"","hbref":""},{"q":"What is the minimum passing score on each New Mexico CDL knowledge (written) test?","options":["80%","70%","75%","90%"],"answer":0,"explanation":"An applicant must score at least 80% to pass each New Mexico CDL knowledge exam. An applicant may take a knowledge test up to twice a week, but the system blocks a third attempt after two failures within a 7-day period. Source: NM MVD Driver Manual Chapter 5.","handbook":"","hbref":""},{"q":"Which endorsement can a first-time applicant NOT have added to a New Mexico Commercial Learner Permit (CLP)?","options":["H (Hazardous Materials)","N (Tank Vehicle)","P (Passenger)","S (School Bus)"],"answer":0,"explanation":"The H (HazMat) endorsement cannot be obtained on a CLP; it requires a TSA threat assessment and is only added to a full CDL. N, P, and S endorsements may be carried on a CLP (with applicable restrictions). Source: NM MVD Driver Manual Chapter 5; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"In New Mexico, what is the maximum legal blood alcohol concentration (BAC) for a driver operating a commercial motor vehicle (CMV)?","options":["0.08%","0.04%","0.02%","0.00%"],"answer":1,"explanation":"New Mexico follows the federal CMV standard: it is illegal to operate a CMV with a BAC of 0.04% or more (half the 0.08% limit for non-commercial drivers). Source: NM CDL Manual section 1.3.2; NMSA 66-5-68.","handbook":"","hbref":""},{"q":"Under New Mexico's implied consent rule, what happens to a CDL holder who operates a CMV?","options":["They must carry a separate breath-test permit","They are deemed to have given consent to alcohol testing","They may refuse testing without any penalty","They consent only if formally arrested first"],"answer":1,"explanation":"The NM CDL Manual states that by operating a CMV, you 'shall be deemed to have given your consent to alcohol testing.' Refusal carries the same disqualification as a major offense. Source: NM CDL Manual section 1.3.2; NMSA 66-5-68 / Implied Consent Act.","handbook":"","hbref":""},{"q":"In New Mexico, how long will a driver lose their CDL for a FIRST major offense, such as a 0.04% BAC violation, in a non-placarded CMV?","options":["60 days","120 days","At least 1 year","At least 3 years"],"answer":2,"explanation":"New Mexico imposes a minimum one-year CDL disqualification for a first major offense (e.g., 0.04% BAC, DUI, test refusal, leaving an accident scene). Source: NM CDL Manual section 1.3.2; NMSA 66-5-68.","handbook":"","hbref":""},{"q":"If a New Mexico CDL holder commits a first major offense while operating a CMV that is placarded for hazardous materials, how long is the disqualification?","options":["At least 1 year","At least 2 years","At least 3 years","Lifetime"],"answer":2,"explanation":"New Mexico raises the first-offense disqualification to at least 3 years if the major offense occurs while operating a CMV placarded for hazardous materials. Source: NM CDL Manual section 1.3.2; NMSA 66-5-68.","handbook":"","hbref":""},{"q":"What is the New Mexico CDL disqualification period for a SECOND major offense (such as a second DUI in a CMV)?","options":["3 years","5 years","10 years","Lifetime"],"answer":3,"explanation":"New Mexico disqualifies a driver from holding a CDL for life upon a second major offense. (A reinstatement after 10 years may be possible by rule, but the disqualification itself is a lifetime ban.) Source: NM CDL Manual section 1.3.2; NMSA 66-5-68.","handbook":"","hbref":""},{"q":"In New Mexico, refusing to submit to blood alcohol testing while operating a CMV is treated as which of the following?","options":["A minor paperwork violation","A serious traffic violation (60-day type)","A major offense (1-year disqualification)","An out-of-service order violation"],"answer":2,"explanation":"New Mexico treats refusal to undergo blood alcohol testing as a major offense, carrying the same minimum one-year CDL disqualification as a 0.04% BAC conviction. Source: NM CDL Manual section 1.3.2; NMSA 66-5-68.","handbook":"","hbref":""},{"q":"A New Mexico CMV driver registers a detectable amount of alcohol that is BELOW 0.04%. What is the immediate consequence?","options":["No consequence below 0.04%","Placed out-of-service for 24 hours","1-year CDL disqualification","60-day CDL disqualification"],"answer":1,"explanation":"New Mexico places a CMV driver out-of-service for 24 hours for any detectable alcohol amount under 0.04%. A reading of 0.04% or more is instead a disqualifying major offense. Source: NM CDL Manual section 1.3.2.","handbook":"","hbref":""},{"q":"Which of the following is classified as a 'serious traffic violation' for a New Mexico CDL holder?","options":["Driving 5 mph over the limit","Excessive speeding at 15 mph or more over the posted limit","A parking violation in a CMV","An expired registration sticker"],"answer":1,"explanation":"New Mexico lists excessive speeding (15 mph or more over the posted limit) as a serious traffic violation, along with reckless driving, improper lane changes, and following too closely. Source: NM CDL Manual section 1.3.3.","handbook":"","hbref":""},{"q":"Which of the following is NOT one of New Mexico's listed serious traffic violations for CDL holders?","options":["Reckless driving","Following a vehicle too closely","Improper or erratic lane changes","Driving a CMV with a burned-out headlight"],"answer":3,"explanation":"New Mexico's serious-traffic-violation list includes reckless driving, following too closely, and improper/erratic lane changes; a burned-out headlight is an equipment issue, not a listed serious violation. Source: NM CDL Manual section 1.3.3.","handbook":"","hbref":""},{"q":"In New Mexico, how long will a driver lose their CDL for committing TWO serious traffic violations in a CMV within a three-year period?","options":["At least 30 days","At least 60 days","At least 120 days","At least 1 year"],"answer":1,"explanation":"New Mexico disqualifies a CDL holder for at least 60 days for two serious traffic violations committed in a CMV within a three-year period. Source: NM CDL Manual section 1.3.3; NMSA 66-5-68.","handbook":"","hbref":""},{"q":"In New Mexico, how long will a driver lose their CDL for committing THREE or more serious traffic violations in a CMV within a three-year period?","options":["60 days","90 days","At least 120 days","At least 1 year"],"answer":2,"explanation":"New Mexico disqualifies a CDL holder for at least 120 days for three or more serious traffic violations committed in a CMV within a three-year period. Source: NM CDL Manual section 1.3.3; NMSA 66-5-68.","handbook":"","hbref":""},{"q":"Driving a CMV in New Mexico without the proper class of CDL and/or required endorsements is considered what?","options":["A serious traffic violation","A major offense (1 year)","An out-of-service violation","Only a warning, not a violation"],"answer":0,"explanation":"New Mexico lists driving a CMV without the proper class of CDL and/or endorsements (or without having a CDL in possession) as a serious traffic violation. Source: NM CDL Manual section 1.3.3.","handbook":"","hbref":""},{"q":"What is the minimum CDL disqualification in New Mexico for a driver's FIRST violation of an out-of-service order?","options":["At least 30 days","At least 60 days","At least 90 days","At least 1 year"],"answer":2,"explanation":"New Mexico disqualifies a CDL holder for at least 90 days for a first out-of-service order violation. Source: NM CDL Manual section 1.3.4; NMSA 66-5-68.","handbook":"","hbref":""},{"q":"In New Mexico, how long is the CDL disqualification for a SECOND out-of-service order violation within a ten-year period?","options":["At least 90 days","At least 1 year","At least 3 years","At least 5 years"],"answer":1,"explanation":"New Mexico disqualifies a CDL holder for at least 1 year for two out-of-service order violations within a ten-year period. Source: NM CDL Manual section 1.3.4; NMSA 66-5-68.","handbook":"","hbref":""},{"q":"In New Mexico, what is the minimum CDL disqualification for THREE or more out-of-service order violations within a ten-year period?","options":["1 year","At least 3 years","5 years","Lifetime"],"answer":1,"explanation":"New Mexico disqualifies a CDL holder for at least 3 years for three or more out-of-service order violations within a ten-year period. Source: NM CDL Manual section 1.3.4; NMSA 66-5-68.","handbook":"","hbref":""},{"q":"In New Mexico, what is the minimum CDL disqualification for a driver's FIRST railroad-highway grade crossing violation?","options":["At least 30 days","At least 60 days","At least 120 days","At least 1 year"],"answer":1,"explanation":"New Mexico disqualifies a CDL holder for at least 60 days for a first railroad-highway grade crossing violation. Source: NM CDL Manual section 1.3.5; NMSA 66-5-68.","handbook":"","hbref":""},{"q":"What is the New Mexico CDL disqualification for a THIRD railroad-highway grade crossing violation within a three-year period?","options":["120 days","180 days","At least 1 year","3 years"],"answer":2,"explanation":"New Mexico disqualifies a CDL holder for at least 1 year for a third railroad-highway grade crossing violation within a three-year period (60 days first, 120 days second). Source: NM CDL Manual section 1.3.5; NMSA 66-5-68.","handbook":"","hbref":""},{"q":"Under New Mexico/federal rules, when does a CMV driver's CDL become subject to disqualification for using a hand-held mobile phone while driving?","options":["After a single first conviction","After two or more convictions","Only after an at-fault crash","Hand-held use is never disqualifying"],"answer":1,"explanation":"A New Mexico CDL is disqualified after two or more convictions for hand-held mobile phone use while operating a CMV: 60 days for a second offense within 3 years and 120 days for three or more within 3 years. Source: NM CDL Manual section 2.9.4.","handbook":"","hbref":""},{"q":"What is the maximum civil penalty a CMV driver in New Mexico may face for violating the hand-held mobile phone / texting prohibition?","options":["Up to $750","Up to $2,750","Up to $5,000","Up to $11,000"],"answer":1,"explanation":"Under the federal restriction applied in New Mexico, a driver violating the hand-held phone/texting prohibition is subject to a civil penalty of up to $2,750; an employer who allows or requires it faces up to $11,000. Source: NM CDL Manual section 2.9.4.","handbook":"","hbref":""},{"q":"In New Mexico, a court may fine a person up to what amount for driving a commercial motor vehicle without a CDL or for holding more than one license?","options":["Up to $1,000","Up to $2,750","Up to $5,000","Up to $11,000"],"answer":2,"explanation":"New Mexico provides that a court may fine a driver up to $5,000 (or impose jail) for driving a CMV without a CDL or for holding more than one license. Source: NM CDL Manual sections 1.3.7 and 1.4.","handbook":"","hbref":""},{"q":"Under New Mexico law, when a school bus is stopped on the roadway with its special school-bus signals operating to load or unload children, how far before the bus must an approaching driver stop?","options":["At least 10 feet before reaching the bus","At least 25 feet before reaching the bus","At least 20 feet before reaching the bus","At least 15 feet before reaching the bus"],"answer":0,"explanation":"NMSA 1978, Section 66-7-347(A) requires a driver approaching or overtaking a stopped school bus with signals in operation to stop the vehicle at least ten feet before reaching the bus and not proceed until the signals are off, the bus moves, or the driver signals to proceed.","handbook":"","hbref":""},{"q":"In New Mexico, which exact condition lets a driver continue past a stopped school bus that is loading children WITHOUT stopping?","options":["There are two or more lanes in the driver's direction","The bus is more than 100 feet away when first seen","The school bus is on a different roadway of a highway with separate roadways","The driver is traveling under 25 mph"],"answer":2,"explanation":"NMSA 1978, Section 66-7-347(C) provides the only divided-highway exception: a driver on a highway with separate roadways need not stop for a bus on a different roadway (or on a controlled-access highway where the bus is in a loading zone and pedestrians are not permitted to cross). Mere extra lanes or low speed do not excuse stopping.","handbook":"","hbref":""},{"q":"On a New Mexico highway, a school bus carrying children, a bus carrying passengers for hire, or a placarded hazardous-materials vehicle must stop before a railroad-highway grade crossing at what distance from the nearest rail?","options":["Not less than 25 feet and not more than 75 feet","Not less than 10 feet and not more than 40 feet","Not less than 15 feet and not more than 50 feet","Not less than 5 feet and not more than 25 feet"],"answer":2,"explanation":"NMSA 1978, Section 66-7-343(A) requires these vehicles to stop no less than 15 feet and no more than 50 feet from the nearest rail before entering the crossing. The New Mexico CDL Manual (Sec. 2.15) states the same 15-to-50-foot rule.","handbook":"","hbref":""},{"q":"New Mexico's railroad-crossing stop law (66-7-343) requires a covered driver, while stopped at the crossing, to place the vehicle in a gear low enough that:","options":["Reverse can be selected if a train approaches","Gears will not need to be shifted before clearing the crossing","The engine brake can be engaged on the far side","The vehicle can restart on a 5% grade"],"answer":1,"explanation":"NMSA 1978, Section 66-7-343(B)(3) requires selecting a gear sufficiently low that gears will not need to be shifted before exiting the crossing, and Subsection (C) prohibits shifting gears while in the crossing. The New Mexico CDL Manual repeats: 'Do not shift gears while crossing railroad tracks.'","handbook":"","hbref":""},{"q":"Which of these is NOT one of New Mexico's listed exceptions that excuse a bus or placarded hazmat vehicle from stopping at a railroad-highway grade crossing?","options":["A crossing where a flashing red light and bell are active","A crossing where a police officer directs traffic to proceed","A crossing controlled by a stop-and-go traffic light","A crossing marked with an 'exempt crossing' sign"],"answer":0,"explanation":"NMSA 1978, Section 66-7-343(D) lists the exceptions: an officer directing traffic, a stop-and-go traffic light, an industrial-switching crossing within a business district, an abandoned crossing so signed, and an 'exempt crossing' sign. An active flashing-red-light-and-bell crossing is NOT an exception; the vehicle must still stop.","handbook":"","hbref":""},{"q":"What is the general maximum speed limit set by New Mexico statute for any vehicle on a highway where no lower limit is posted?","options":["65 miles per hour","75 miles per hour","80 miles per hour","70 miles per hour"],"answer":1,"explanation":"NMSA 1978, Section 66-7-301(A)(3) sets the general statutory maximum at seventy-five miles per hour. This figure applies absent a posted lower limit or a designated double-fine zone.","handbook":"","hbref":""},{"q":"Does New Mexico impose a lower statutory maximum speed limit on truck tractors (large trucks) than on cars?","options":["Yes - trucks are limited to 60 mph by statute","No - the same 75 mph statutory maximum applies to trucks and cars","Yes - trucks are limited to 55 mph at night by statute","Yes - trucks are limited to 65 mph by statute"],"answer":1,"explanation":"New Mexico is not a split-speed-limit state. The 75 mph maximum in NMSA 1978, Section 66-7-301 applies to all vehicles. A 2025 bill (SB226) proposing a 65 mph truck-tractor limit died in committee and never became law, so no truck-specific statutory speed cap exists.","handbook":"","hbref":""},{"q":"Per New Mexico statute, what is the maximum speed limit when passing a school while children are going to or leaving school and the school zone is properly posted?","options":["25 miles per hour","20 miles per hour","30 miles per hour","15 miles per hour"],"answer":3,"explanation":"NMSA 1978, Section 66-7-301(A)(1) sets a 15 mph limit on all highways when passing a school while children are going to or leaving school and the zone is properly posted.","handbook":"","hbref":""},{"q":"Absent a posted limit, what speed does New Mexico statute set for driving in a business or residence district?","options":["20 miles per hour","35 miles per hour","30 miles per hour","25 miles per hour"],"answer":2,"explanation":"NMSA 1978, Section 66-7-301(A)(2) sets a 30 mph limit in a business or residence district where no other limit is posted.","handbook":"","hbref":""},{"q":"Effective July 1, 2023, New Mexico's lane-travel law (66-7-376) generally restricts use of the left lane on a multilane roadway to which situation?","options":["Only between sunrise and sunset","Only when carrying placarded hazmat","Only when overtaking and passing another vehicle","Only when traveling above 65 mph"],"answer":2,"explanation":"NMSA 1978, Section 66-7-376(A)(4), enacted by SB102 (Laws 2023) effective July 1, 2023, prohibits driving in the left lane of a roadway except when overtaking and passing, unless traffic, flow, or road configuration (such as merging traffic) requires the left lane.","handbook":"","hbref":""},{"q":"New Mexico's left-lane restriction in 66-7-376 does NOT apply in which of these locations?","options":["On any state highway with three lanes each way","Within the city limits of a municipality, on a road that is not an interstate","On a four-lane divided U.S. highway between cities","On a rural stretch of Interstate 40"],"answer":1,"explanation":"NMSA 1978, Section 66-7-376(A)(4) expressly states the left-lane prohibition does not apply within the city limits of a municipality or on a county road, as long as the roadway is not part of the national system of interstate and defense highways.","handbook":"","hbref":""},{"q":"Under New Mexico's lane-use law, a driver changing lanes must signal the intention to change lanes for at least the last how many feet traveled?","options":["100 feet","150 feet","200 feet","50 feet"],"answer":0,"explanation":"NMSA 1978, Section 66-7-376(A)(2) requires that, before moving from a lane, the driver signal the intention to change lanes for not less than the last one hundred feet traveled by the vehicle.","handbook":"","hbref":""},{"q":"New Mexico marks a two-way left-turn lane with parallel double yellow lines (interior dashed, exterior solid). A vehicle preparing for or making a left turn may not be driven in that lane for more than how far?","options":["300 feet","500 feet","200 feet","100 feet"],"answer":2,"explanation":"NMSA 1978, Section 66-7-376(B) provides that vehicles turning left from the roadway shall not be driven in the two-way left-turn lane for more than two hundred feet while preparing for and making the turn.","handbook":"","hbref":""},{"q":"Under New Mexico's Move Over law, when an authorized emergency vehicle is approaching with flashing lights or siren, the driver of every other vehicle must:","options":["Move one lane left and maintain speed","Slow to 20 mph and stay in the current lane","Stop immediately in the current lane regardless of position","Pull as close as possible to the right edge or curb and stop until it passes"],"answer":3,"explanation":"NMSA 1978, Section 66-7-332(A) requires drivers, on the immediate approach of an authorized emergency vehicle, to yield and immediately drive parallel to and as close as possible to the right-hand edge or curb, clear of any intersection, and stop until it has passed, unless directed otherwise by an officer.","handbook":"","hbref":""},{"q":"New Mexico's Move Over law applies to a stationary vehicle displaying flashing emergency or hazard lights. Besides authorized emergency vehicles, which vehicles are specifically covered?","options":["School buses at a bus stop","Postal delivery vehicles","Farm equipment on the shoulder","Recovery or repair (tow/wrecker) vehicles"],"answer":3,"explanation":"NMSA 1978, Section 66-7-332(B) extends the stationary-vehicle 'move over and slow down' duty to a stationary authorized emergency vehicle or a recovery or repair vehicle displaying flashing emergency or hazard lights.","handbook":"","hbref":""},{"q":"Under New Mexico's Move Over law, when a driver approaches a stationary emergency or recovery vehicle but it is NOT reasonably safe to move out of the adjacent lane, the driver must:","options":["Come to a complete stop in the travel lane","Slow to a speed reasonable and prudent under the circumstances, proceed with caution, and be prepared to stop","Accelerate past the scene to clear it quickly","Continue at the posted speed limit through the area"],"answer":1,"explanation":"NMSA 1978, Section 66-7-332(B)(2) provides that if it is not reasonably safe to drive in a lane not adjacent to the stationary vehicle, the driver shall decrease speed to a speed reasonable and prudent under the circumstances, proceed with caution, and be prepared to stop.","handbook":"","hbref":""},{"q":"If a New Mexico commercial vehicle must stop on a one-way or divided highway, where does the CDL Manual require the three warning devices (reflective triangles) to be placed?","options":["Only directly behind the vehicle at 100 feet","10 feet, 50 feet, and 150 feet toward approaching traffic","100 feet ahead and 100 feet behind only","10 feet, 100 feet, and 200 feet toward the approaching traffic"],"answer":3,"explanation":"The New Mexico CDL Manual (Sec. 2.5) follows the federal CMV standard (49 CFR 392.22): on a one-way or divided highway, place warning devices at 10 feet, 100 feet, and 200 feet toward the approaching traffic, within 10 minutes of stopping.","handbook":"","hbref":""},{"q":"On a two-lane, two-way (undivided) road in New Mexico, where does the CDL Manual require a stopped commercial vehicle's warning triangles to be placed?","options":["Within 10 feet of the vehicle, and 100 feet behind and 100 feet ahead of the vehicle","At 10, 100, and 200 feet behind the vehicle only","At 50 feet behind and 50 feet ahead only","At 200 feet behind and 200 feet ahead only"],"answer":0,"explanation":"The New Mexico CDL Manual (Sec. 2.5) instructs that on a two-lane road carrying traffic in both directions or an undivided highway, place one device within 10 feet of the front or rear, and one 100 feet behind and one 100 feet ahead of the vehicle.","handbook":"","hbref":""},{"q":"In New Mexico, if a commercial vehicle is stopped where a hill, curve, or other obstruction keeps the warning triangles from being seen within 500 feet, the driver should:","options":["Place all three triangles within 50 feet of the rear bumper","Leave all triangles at the standard 10, 100, and 200 feet","Use only the four-way flashers instead of triangles","Move the rear-most triangle back beyond the obstruction, up to 500 feet from the vehicle"],"answer":3,"explanation":"The New Mexico CDL Manual (Sec. 2.5) directs that if a hill, curve, or obstruction blocks the line of sight within 500 feet, the rear-most triangle should be moved back down the road, up to 500 feet, so other drivers get warning. NMSA 1978, Section 66-3-853 similarly requires placement 100 to 500 feet out near such obstructions.","handbook":"","hbref":""},{"q":"New Mexico statute 66-3-849 requires buses and large trucks to CARRY which set of emergency warning equipment?","options":["Three red emergency reflectors (or flares/fusees) plus two red cloth flags","A single red lantern and one flag","Two amber strobes and a fire extinguisher only","Four orange cones and a reflective vest"],"answer":0,"explanation":"NMSA 1978, Section 66-3-849 requires covered vehicles (buses, trucks, truck tractors, etc.) to carry warning devices such as three red emergency reflectors, two red cloth flags, and three fusees (or the equivalent flares/lanterns). The New Mexico CDL Manual likewise lists three reflective triangles, six fusees, or three liquid-burning flares as the required parked-vehicle warning devices.","handbook":"","hbref":""},{"q":"Which state agency issues Commercial Driver Licenses (CDLs) in New Mexico?","options":["The Motor Vehicle Division (MVD)","The New Mexico Department of Transportation (NMDOT)","The Commercial Vehicle Bureau of the State Police","The Public Regulation Commission (PRC)"],"answer":0,"explanation":"In New Mexico, CDLs are issued by the Motor Vehicle Division (MVD), which is part of the Taxation and Revenue Department. NMDOT handles roads and oversize/overweight permits, not driver licensing. Source: MVD New Mexico, Commercial Driver's Licenses (CDL) page and Chapter 5: Commercial Driver License.","handbook":"","hbref":""},{"q":"When applying for a New Mexico CDL, applicants must self-certify into one of how many driver categories?","options":["Four categories","Two categories","Three categories","Six categories"],"answer":0,"explanation":"New Mexico CDL applicants must self-certify into one of four categories describing the type of commerce they expect to operate in: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), and Excepted Intrastate (EA). Source: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.71.","handbook":"","hbref":""},{"q":"A New Mexico CDL driver who operates across state lines and is NOT exempt from the federal physical-qualification rules must self-certify as which category?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"answer":0,"explanation":"A driver operating in interstate commerce who is required to meet the federal DOT medical standards self-certifies as Non-Excepted Interstate (NI) and must maintain a current Medical Examiner's Certificate on file with MVD. Source: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Who is authorized to perform the physical exam for a New Mexico CDL Medical Examiner's Certificate?","options":["A medical professional listed on the National Registry of Certified Medical Examiners","Any licensed physician in New Mexico","A nurse practitioner at any urgent-care clinic","The MVD field office medical officer"],"answer":0,"explanation":"All Commercial Driver Medical Certifications in New Mexico must be completed by a medical professional listed on the FMCSA National Registry of Certified Medical Examiners. A general medical license alone is not sufficient. Source: MVD New Mexico, Commercial Driver's Licenses (CDL) page; FMCSA National Registry.","handbook":"","hbref":""},{"q":"How does a New Mexico CDL holder get the DOT Medical Examiner's Certificate on record with the state?","options":["By submitting a copy of the certificate to MVD, which posts the medical status to the driving record","By mailing it directly to FMCSA in Washington, D.C.","By keeping the original card only in the vehicle; no copy is given to MVD","By filing it with the New Mexico Department of Health"],"answer":0,"explanation":"New Mexico CDL holders must provide MVD (the State Driver Licensing Agency) with a copy of their Medical Examiner's Certificate; MVD then posts the medical certification status to the commercial driving record (CDLIS). The card carried in the vehicle alone does not satisfy the state filing requirement. Source: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.71(h).","handbook":"","hbref":""},{"q":"Before testing for a CDL, a first-time New Mexico applicant generally must complete which federally required training?","options":["Entry-Level Driver Training (ELDT) from a provider on the FMCSA Training Provider Registry","A 40-hour OSHA commercial vehicle safety course","A New Mexico defensive-driving classroom course","An apprenticeship of at least 90 days with a licensed carrier"],"answer":0,"explanation":"First-time CDL applicants (and certain upgrades/endorsements) must complete Entry-Level Driver Training (ELDT) through a provider listed on the FMCSA Training Provider Registry before taking the skills or knowledge test. The rule applies to applicants on or after February 7, 2022. Source: MVD New Mexico Chapter 5; FMCSA ELDT rule, 49 CFR Part 380.","handbook":"","hbref":""},{"q":"How long after the initial issuance of a New Mexico Commercial Learner's Permit (CLP) must the holder wait before being eligible to take the CDL skills test?","options":["At least 14 days","At least 30 days","At least 10 days","At least 60 days"],"answer":0,"explanation":"A CLP holder is not eligible to take the CDL skills test until at least 14 days after the initial issuance of the CLP. This federal minimum is enforced by New Mexico MVD. Source: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.25(a)(3).","handbook":"","hbref":""},{"q":"For how long is a New Mexico Commercial Learner's Permit (CLP) valid?","options":["1 year (with one renewal allowed without retesting)","90 days","6 months","2 years"],"answer":0,"explanation":"The New Mexico CLP is issued for 1 year. Under the federal standard it may be renewed once within that period without retaking the general knowledge test. Source: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.25(c).","handbook":"","hbref":""},{"q":"The New Mexico CDL skills test consists of how many parts, and what are they?","options":["Three parts: pre-trip vehicle inspection, basic vehicle control, and on-road driving","Two parts: a written exam and an on-road drive","Three parts: air-brake test, backing test, and night driving","Four parts: inspection, backing, highway, and parallel parking"],"answer":0,"explanation":"The CDL skills test has three parts that must be passed in order: the pre-trip vehicle inspection, the basic vehicle control (low-speed maneuvers), and the on-road driving test. Source: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.113.","handbook":"","hbref":""},{"q":"What is the minimum passing score on the New Mexico CDL knowledge (written) tests?","options":["80 percent","70 percent","75 percent","90 percent"],"answer":0,"explanation":"New Mexico CDL knowledge tests must be passed with a score of at least 80 percent, consistent with the federal standard. Source: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.135.","handbook":"","hbref":""},{"q":"Which prerequisite must a person already hold before applying for a New Mexico CDL?","options":["A valid New Mexico Class D (regular) driver license or a valid out-of-state CDL","A passenger (P) endorsement obtained in any state","A federal hazmat clearance from TSA","A motorcycle endorsement on a New Mexico license"],"answer":0,"explanation":"To apply for a New Mexico CDL you must already hold a valid non-commercial (Class D) New Mexico driver license or a valid out-of-state CDL. Source: MVD New Mexico, requirements to get a New Mexico CDL.","handbook":"","hbref":""},{"q":"Under New Mexico MVD rules, how many proofs of physical residency in New Mexico must a CDL applicant present?","options":["Two proofs of physical residency","One proof of physical residency","Three proofs of physical residency","No residency proof is required"],"answer":0,"explanation":"A New Mexico CDL applicant must present two proofs of physical residency in the state. Monthly documents such as utility bills or bank statements used as proof must be dated within 60 days of the application. Source: MVD New Mexico, Commercial Driver's Licenses (CDL) page.","handbook":"","hbref":""},{"q":"Which renewal cycle options does New Mexico offer for a CDL?","options":["A 4-year or an 8-year credential","A 1-year or a 5-year credential","Only a 5-year credential","A 2-year or a 6-year credential"],"answer":0,"explanation":"New Mexico offers CDLs on a 4-year or an 8-year renewal cycle. Source: MVD New Mexico FAQ and Chapter 5.","handbook":"","hbref":""},{"q":"Why might a New Mexico CDL holder be limited to the 4-year (rather than the 8-year) credential?","options":["Because they hold a Hazardous Materials (Hazmat) endorsement","Because they hold a passenger (P) endorsement","Because they drive only intrastate","Because they are under age 30"],"answer":0,"explanation":"Drivers holding the Hazardous Materials (Hazmat) endorsement cannot obtain the 8-year CDL; the periodic TSA background check tied to Hazmat limits them to the 4-year cycle. Source: MVD New Mexico FAQ; TSA/FMCSA Hazmat endorsement rules.","handbook":"","hbref":""},{"q":"How are New Mexico CDL knowledge tests scheduled with respect to retakes?","options":["Applicants may take the CDL written tests up to twice a week","Applicants may take the written tests only once every 30 days","Applicants get unlimited same-day retakes","Applicants may take the written tests only once per calendar year"],"answer":0,"explanation":"New Mexico allows CDL applicants to take the CDL written (knowledge) tests up to twice per week. Source: MVD New Mexico, Commercial Driver's Licenses (CDL) page.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a New Mexico CDL restricted to intrastate (in-state) driving only?","options":["18 years old","16 years old","21 years old","19 years old"],"answer":0,"explanation":"A person may obtain a New Mexico CDL for intrastate driving at age 18; an applicant aged 18-20 is restricted to in-state operation. Operating in interstate commerce requires age 21. Source: MVD New Mexico Chapter 5; FMCSA 49 CFR 391.11.","handbook":"","hbref":""},{"q":"When a driver exchanges a valid out-of-state CDL for a New Mexico CDL of the same class and endorsements, what testing is generally required?","options":["No written tests are required for the equivalent class and endorsements","Both the written and skills tests must be retaken","Only the on-road skills test must be retaken","Only the pre-trip inspection must be repeated"],"answer":0,"explanation":"New Mexico does not require written tests to exchange a valid out-of-state CDL for a New Mexico CDL of the same class and endorsements. (The Hazmat endorsement still requires its own test and TSA background check.) Source: MVD New Mexico, requirements to get a New Mexico CDL.","handbook":"","hbref":""},{"q":"In addition to a written knowledge test, a New Mexico CDL applicant seeking a Hazardous Materials (Hazmat) endorsement must also complete what?","options":["Fingerprinting and a TSA security threat assessment (background check)","A separate on-road night driving test","A 10-day defensive driving course","An eye exam at a state-run clinic"],"answer":0,"explanation":"A New Mexico driver seeking the Hazmat endorsement must pass the Hazmat knowledge test and be fingerprinted for a TSA security threat assessment (background check) before the endorsement is granted. Source: MVD New Mexico, requirements to get a New Mexico CDL; TSA Hazmat Endorsement Threat Assessment Program.","handbook":"","hbref":""},{"q":"When a New Mexico CDL applicant goes back to MVD to receive the CDL after passing the skills test, the test results are typically provided in what form?","options":["A sealed envelope containing the skills test scores, presented with the CLP and required documents","An email sent directly from the examiner to FMCSA","A verbal report given only to the examiner's supervisor","A score printed on the back of the road test vehicle's registration"],"answer":0,"explanation":"After passing the skills test administered by an approved CDL examiner, the applicant returns to MVD with their driver license, the CLP, and a sealed envelope containing the skills test scores to be issued the CDL. Source: MVD New Mexico, requirements to get a New Mexico CDL.","handbook":"","hbref":""}],"ru":{"0":{"q":"На автодорогах Нью-Мексико какова максимальная допустимая ширина коммерческого транспортного средства или его груза (без учёта зеркал и отдельных устройств безопасности) без разрешения на негабарит?","options":["8 футов 6 дюймов (102 inches)","8 футов (96 inches)","9 футов (108 inches)","10 футов (120 inches)"],"explanation":"Нью-Мексико ограничивает общую наружную ширину транспортного средства или груза до 8 футов 6 дюймов (102 inches), без учёта зеркал и одобренных приспособлений безопасности. Для более широкого груза требуется разрешение на негабарит. Источник: NMSA 1978, Section 66-7-402 (Width of vehicles); NM CDL Manual."},"1":{"q":"Какова максимальная допустимая высота транспортного средства и его груза на автодорогах Нью-Мексико без разрешения?","options":["14 футов","13 футов 6 дюймов","15 футов","13 футов"],"explanation":"Нью-Мексико устанавливает максимальную высоту транспортного средства с грузом в 14 футов. Для грузов выше 14 футов требуется разрешение на негабарит (превышение высоты). Источник: NMSA 1978, Section 66-7-404 (Height and length of vehicles and loads)."},"2":{"q":"Каков максимальный полный вес на любую одиночную ось коммерческого транспортного средства согласно закону Нью-Мексико?","options":["21,600 pounds","20,000 pounds","22,400 pounds","18,000 pounds"],"explanation":"Лимит на одиночную ось в Нью-Мексико составляет 21,600 pounds, что выше федерального лимита для межштатных трасс в 20,000 pounds. Источник: NMSA 1978, Section 66-7-409 (Load limits on single axles, wheels and tires)."},"3":{"q":"Согласно закону Нью-Мексико, каков максимально допустимый вес на сдвоенную ось (две оси, расположенные на расстоянии 4 feet друг от друга)?","options":["34,320 pounds","34,000 pounds","36,000 pounds","32,000 pounds"],"explanation":"Таблица весов по группам осей Нью-Мексико допускает 34,320 pounds на сдвоенную ось (две оси на расстоянии около 4 feet друг от друга), что немного выше федерального лимита для межштатных трасс в 34,000 pounds. Источник: NMSA 1978, Section 66-7-410 (Gross weight of vehicles and loads)."},"4":{"q":"Какова максимальная общая длина автопоезда (грузовик с прицепом) на автодорогах Нью-Мексико без разрешения?","options":["65 футов","60 футов","70 футов","75 футов"],"explanation":"Нью-Мексико ограничивает общую длину автопоезда (грузовик плюс прицеп) до 65 футов на дорогах в целом; для более длинных составов требуется разрешение на негабарит. Источник: NMSA 1978, Section 66-7-404 (Height and length of vehicles and loads)."},"5":{"q":"На системе межштатных автодорог Нью-Мексико (трассы федерального значения) каков максимальный полный вес транспортного средства, допустимый без разрешения на перевес?","options":["80,000 pounds","86,400 pounds","84,000 pounds","90,000 pounds"],"explanation":"На системе межштатных автодорог Нью-Мексико применяет федеральный предел полного веса в 80,000 pounds. Собственная нормативная таблица штата допускает несколько больший вес на отдельных автодорогах штата вне системы межштатных трасс, но 80,000 pounds — это максимум для межштатных трасс без разрешения. Источник: 23 U.S.C. 127 в применении к Нью-Мексико; NMSA 1978, Section 66-7-410."},"6":{"q":"Согласно нормативной таблице полного веса Нью-Мексико, каков максимально допустимый полный вес (при достаточном расстоянии между осями около 56 feet или более) на автодороге штата вне системы межштатных трасс без специального разрешения?","options":["86,400 pounds","80,000 pounds","94,000 pounds","84,000 pounds"],"explanation":"Таблица полного веса Нью-Мексико достигает максимума в 86,400 pounds, когда расстояние между первой и последней осью составляет примерно 56 feet или более на автодорогах штата вне системы межштатных трасс. Система межштатных автодорог остаётся ограниченной федеральным пределом в 80,000 pounds. Источник: NMSA 1978, Section 66-7-410 (Gross weight of vehicles and loads)."},"7":{"q":"Какова максимальная длина полуприцепа, эксплуатируемого на установленных автодорогах Нью-Мексико (National Network), без разрешения?","options":["57 футов 6 дюймов","53 фута","48 футов","60 футов"],"explanation":"Нью-Мексико допускает полуприцеп длиной до 57 футов 6 дюймов на установленных маршрутах National Network. Источник: NMSA 1978, Section 66-7-404 (Height and length of vehicles and loads); NM CDL Manual."},"8":{"q":"Какая формула используется в Нью-Мексико на системе межштатных автодорог для определения максимально допустимого полного веса на группу последовательных осей?","options":["Federal Bridge Formula","Правило чистого тоннажа (Net-Tonnage Rule)","Коэффициент межосевого расстояния (Axle-Spacing Quotient)","Соотношение полной массы автопоезда (Gross-Combination Ratio)"],"explanation":"На системе межштатных автодорог Нью-Мексико применяет Federal Bridge Formula, W = 500[(LN/(N-1)) + 12N + 36], которая ограничивает вес на любую группу осей в зависимости от расстояния (L) и числа (N) осей. Источник: 23 U.S.C. 127 / FBF в применении к Нью-Мексико; NM CDL Manual."},"9":{"q":"Кто выдаёт разрешения на негабарит/перевес для коммерческих транспортных средств, эксплуатируемых на автодорогах штата Нью-Мексико?","options":["New Mexico Department of Transportation (NMDOT)","Управление шерифа округа","Federal Motor Carrier Safety Administration","Местный городской отдел общественных работ"],"explanation":"Разрешения на негабарит и перевес в Нью-Мексико выдаёт New Mexico Department of Transportation (NMDOT), которое управляет этим через подразделение Ports of Entry / выдачи разрешений и онлайн-систему разрешений. Источник: NMDOT Permits / Ports of Entry; NMSA 1978, Section 66-7-413."},"10":{"q":"Перевозчику нужно переместить единый неделимый груз, превышающий допустимые весовые лимиты Нью-Мексико. Что перевозчик должен получить до рейса?","options":["Разрешение NMDOT на перевес (специальное)","Новый эндорсмент CDL","Федеральное межштатное освобождение от FMCSA","Только подтверждение страховки груза"],"explanation":"Перевозка груза, превышающего допустимые габаритные или весовые лимиты Нью-Мексико, требует специального разрешения (на негабарит/перевес) от NMDOT, как правило для неделимых грузов. Источник: NMSA 1978, Section 66-7-413; NMDOT Permits."},"11":{"q":"Согласно правилам по одиночной оси Нью-Мексико, каков максимально допустимый вес на любое одиночное колесо?","options":["11,000 pounds","10,000 pounds","12,500 pounds","9,000 pounds"],"explanation":"Нью-Мексико ограничивает нагрузку на любое одиночное колесо до 11,000 pounds в рамках своих правил нагрузки на одиночную ось, колесо и шину. Источник: NMSA 1978, Section 66-7-409 (Load limits on single axles, wheels and tires)."},"12":{"q":"Правило нагрузки на шину в Нью-Мексико ограничивает вес до какого значения на дюйм ширины шины?","options":["600 pounds на дюйм ширины шины","500 pounds на дюйм ширины шины","800 pounds на дюйм ширины шины","1,000 pounds на дюйм ширины шины"],"explanation":"Нью-Мексико ограничивает нагрузку на шину до 600 pounds на дюйм ширины шины в рамках своих лимитов нагрузки на ось, колесо и шину. Источник: NMSA 1978, Section 66-7-409 (Load limits on single axles, wheels and tires)."},"13":{"q":"Разрешение на негабарит/перевес в Нью-Мексико чаще всего выдаётся на какой срок?","options":["На одну поездку или на годовой период","Только на одну поездку, не дольше","Только максимум на 30 дней","Бессрочно, без срока окончания"],"explanation":"Разрешения на негабарит/перевес в Нью-Мексико обычно выдаются либо как разрешения на одну поездку, либо как годовые разрешения, в зависимости от характера перемещения. Источник: NMDOT Permits / Ports of Entry; NMSA 1978, Section 66-7-413."},"14":{"q":"Согласно Federal Bridge Formula в применении на межштатных трассах Нью-Мексико, что обозначают переменные L и N?","options":["L = расстояние в футах между крайними осями группы; N = число осей в группе","L = нагрузка в фунтах; N = число шин","L = длина прицепа; N = чистый вес в тоннах","L = допустимый предел; N = число имеющихся разрешений"],"explanation":"В Federal Bridge Formula L — это расстояние в футах между крайними точками (первой и последней осью) любой группы из двух или более последовательных осей, а N — число осей в этой группе. Источник: 23 U.S.C. 127 / FBF в применении к Нью-Мексико; NM CDL Manual."},"15":{"q":"Груз полуприцепа имеет ширину 8 feet 8 inches. Что требуется для его законной перевозки по автодорогам Нью-Мексико?","options":["Разрешение NMDOT на негабарит (превышение ширины)","Ничего; это в пределах допустимой ширины","Только флажок широкого груза, без разрешения","Переход на CDL класса A"],"explanation":"Допустимый предел ширины в Нью-Мексико составляет 8 feet 6 inches; при 8 feet 8 inches груз превышает его, поэтому требуется разрешение NMDOT на негабарит по ширине. Источник: NMSA 1978, Section 66-7-402; NMDOT Permits."},"16":{"q":"При превышении пороговых значений по ширине или длине Нью-Мексико может требовать сопровождающие (пилотные) машины. Выше какой ширины Нью-Мексико обычно требует сопровождение для перемещаемого груза?","options":["Более 14 feet в ширину","Более 10 feet в ширину","Более 8 feet 6 inches в ширину","Более 20 feet в ширину"],"explanation":"Нью-Мексико обычно требует сопровождающие/пилотные машины для грузов шириной более 14 feet (и для грузов длиной более примерно 90 feet). Источник: NMDOT oversize permit movement requirements."},"17":{"q":"Как чаще всего перевозчик подаёт заявку на разрешение на негабарит/перевес в Нью-Мексико сегодня?","options":["Через онлайн-систему разрешений NMDOT","Отправив бумажную форму по почте в офис губернатора","Позвонив в FMCSA в Вашингтоне, округ Колумбия","Только лично в здании окружного суда"],"explanation":"Разрешения на негабарит/перевес в Нью-Мексико получают преимущественно через онлайн-систему разрешений NMDOT, где перевозчики вводят габариты груза, вес, маршрут и даты поездки. Источник: NMDOT Permits / Ports of Entry."},"18":{"q":"Показатели полного веса Нью-Мексико отличаются от федерального стандарта для межштатных трасс. По сравнению с федеральным лимитом для межштатных трасс на одиночную ось в 20,000 pounds, нормативный лимит Нью-Мексико на одиночную ось:","options":["Выше, 21,600 pounds","Ниже, 18,000 pounds","Идентичен, 20,000 pounds","Выше, 25,000 pounds"],"explanation":"Нормативный лимит Нью-Мексико на одиночную ось составляет 21,600 pounds, что выше федерального лимита для межштатных трасс на одиночную ось в 20,000 pounds. Более низкий федеральный показатель всё же действует на самой системе межштатных автодорог. Источник: NMSA 1978, Section 66-7-409; 23 U.S.C. 127."},"19":{"q":"В Нью-Мексико CDL класса A требуется для управления любым составом транспортных средств с полной массой автопоезда (GCWR) не менее какого значения, когда буксируемое(ые) звено(я) превышает 10,000 lbs GVWR?","options":["26,001 или более pounds","10,001 или более pounds","18,001 или более pounds","33,001 или более pounds"],"explanation":"CDL класса A в Нью-Мексико даёт право управлять любым составом транспортных средств с GCWR 26,001 или более pounds при условии, что GVWR буксируемого(ых) звена(ьев) превышает 10,000 pounds. Источник: NM MVD Driver Manual Chapter 5 (Commercial Driver License)."},"20":{"q":"Какой класс CDL Нью-Мексико даёт право управлять одиночным транспортным средством с GVWR 26,001 или более pounds, либо таким транспортным средством, буксирующим звено не более 10,000 lbs GVWR?","options":["Класс B","Класс A","Класс C","Класс D"],"explanation":"CDL класса B в Нью-Мексико охватывает любое одиночное транспортное средство с GVWR 26,001 или более pounds, либо такое транспортное средство, буксирующее звено не более 10,000 pounds GVWR. Состав с GCWR более 26,001, буксирующий более 10,000 lbs, требует класса A. Источник: NM MVD Driver Manual Chapter 5."},"21":{"q":"CDL класса C в Нью-Мексико применяется к транспортному средству менее 26,001 lbs GVWR только когда оно используется для какой цели?","options":["Перевозка 16 или более пассажиров (включая водителя) или маркированных табличками опасных грузов","Буксировка любого прицепа более 5,000 lbs","Перевозка 9 или более пассажиров за плату","Эксплуатация через границы штатов для любого груза"],"explanation":"CDL класса C в Нью-Мексико применяется к одиночному транспортному средству менее 26,001 lbs GVWR (или буксирующему звено не более 10,000 lbs) только когда оно рассчитано на перевозку 16 или более пассажиров, включая водителя, либо когда оно маркировано табличками для опасных грузов. Источник: NM MVD Driver Manual Chapter 5."},"22":{"q":"Согласно федеральным правилам, принятым в Нью-Мексико, держатель Commercial Learner Permit (CLP) НЕ может сдавать экзамен по навыкам CDL ранее чем через сколько дней после первоначальной выдачи CLP?","options":["14 days","7 days","30 days","10 days"],"explanation":"Держатель CLP не имеет права сдавать экзамен по навыкам CDL в течение первых 14 days после первоначальной выдачи CLP. Нью-Мексико применяет это федеральное 14-дневное ограничение. Источник: NM MVD Driver Manual Chapter 5; 49 CFR 383.25."},"23":{"q":"Каков минимальный возраст для выдачи CDL Нью-Мексико, ограниченного только внутриштатной (в пределах Нью-Мексико) коммерческой деятельностью?","options":["18 лет","21 год","16 лет","19 лет"],"explanation":"Заявителю должно быть не менее 18 лет, чтобы иметь CDL Нью-Мексико, ограниченный внутриштатной коммерческой деятельностью. Водитель в возрасте 18-20 лет получает ограничение 'K', разрешающее ему ездить только в пределах Нью-Мексико. Источник: NM MVD Driver Manual Chapter 5."},"24":{"q":"Каков минимальный возраст для выдачи CDL Нью-Мексико для межштатной (через границы штатов) коммерческой деятельности?","options":["21 год","18 лет","23 года","25 лет"],"explanation":"Водителю должно быть не менее 21 года, чтобы управлять коммерческим транспортным средством в межштатной коммерческой деятельности. Водители Нью-Мексико в возрасте 18-20 лет ограничены внутриштатной эксплуатацией. Источник: NM MVD Driver Manual Chapter 5; 49 CFR 391.11."},"25":{"q":"Что обозначает ограничение 'K' на CDL Нью-Мексико относительно водителя?","options":["Ограничен только внутриштатной коммерческой деятельностью","Ограничен транспортными средствами без пневматических тормозов","Ограничен транспортными средствами с автоматической трансмиссией","Не может перевозить пассажиров"],"explanation":"Нью-Мексико ставит ограничение 'K' на CDL, выданные заявителям в возрасте 18-20 лет, ограничивая водителя только внутриштатной (в пределах Нью-Мексико) коммерческой деятельностью. Источник: NM MVD Driver Manual Chapter 5."},"26":{"q":"Какой эндорсмент требуется на CDL Нью-Мексико для управления автоцистерной, перевозящей жидкие или газообразные материалы наливом/насыпью?","options":["N (Tank Vehicle)","T (Doubles/Triples)","H (Hazardous Materials)","P (Passenger)"],"explanation":"Эндорсмент N даёт право управлять автоцистерной, используемой для перевозки жидких или газообразных материалов наливом/насыпью. Эндорсмент N может быть добавлен на CLP после сдачи требуемого теоретического экзамена. Источник: NM MVD Driver Manual Chapter 5."},"27":{"q":"Какой эндорсмент CDL Нью-Мексико требуется, чтобы тянуть два или три прицепа за одной тяговой единицей?","options":["T (Doubles/Triples)","N (Tank Vehicle)","S (School Bus)","X (Combination)"],"explanation":"Эндорсмент T даёт право тянуть двойные или тройные прицепы и требует сдачи теоретического экзамена. Источник: NM MVD Driver Manual Chapter 5; 49 CFR 383.93."},"28":{"q":"Какой эндорсмент нужен держателю CDL Нью-Мексико для управления коммерческим транспортным средством, рассчитанным на перевозку 16 или более человек, включая водителя?","options":["P (Passenger)","S (School Bus)","N (Tank Vehicle)","T (Doubles/Triples)"],"explanation":"Эндорсмент P (Passenger) требуется для управления транспортным средством, рассчитанным на перевозку 16 или более пассажиров, включая водителя. Экзамен по навыкам должен сдаваться на транспортном средстве, представляющем этот класс. Источник: NM MVD Driver Manual Chapter 5; 49 CFR 383.93."},"29":{"q":"Перед выдачей эндорсмента H (Hazardous Materials) заявитель в Нью-Мексико должен пройти какую проверку безопасности?","options":["Дактилоскопическую проверку благонадёжности/угроз TSA через Universal Enroll","Только сравнение со списком самых разыскиваемых FBI","Проверку судимости только полицией штата","Собеседование в New Mexico MVD без дактилоскопии"],"explanation":"New Mexico MVD не может выдать эндорсмент HazMat (H), пока заявитель не пройдёт дактилоскопическую проверку благонадёжности TSA (Hazardous Materials Endorsement Threat Assessment) через систему Universal Enroll и пока TSA не установит, что заявитель не представляет угрозы безопасности. Источник: NM MVD Hazardous Material Endorsement page; 49 CFR 1572."},"30":{"q":"Для получения эндорсмента HazMat (H) впервые в Нью-Мексико ELDT требует от заявителя пройти какое обучение перед теоретическим экзаменом?","options":["Теоретическое обучение по опасным грузам у провайдера из FMCSA Training Provider Registry","Только тренировку за рулём на полигоне","40-часовой очный дорожный курс по HazMat","Никакого обучения; только проверку благонадёжности TSA"],"explanation":"Заявители, впервые получающие эндорсмент H, должны пройти теоретическое обучение по HazMat (компонент за рулём для H не требуется) у провайдера из FMCSA Training Provider Registry перед сдачей теоретического экзамена. Источник: NM MVD Driver Manual Chapter 5; 49 CFR 380.725."},"31":{"q":"Требования ELDT применяются к заявителям в Нью-Мексико, впервые подавшим заявление на первоначальный CLP начиная с какой даты?","options":["February 7, 2022","January 1, 2020","September 30, 2021","July 1, 2023"],"explanation":"Все заявители на первоначальный CLP начиная с February 7, 2022 должны соблюдать федеральные правила Entry-Level Driver Training (ELDT) в 49 CFR 380.600-380.603. Источник: NM MVD Driver Manual Chapter 5."},"32":{"q":"Где заявитель ELDT в Нью-Мексико должен пройти требуемое обучение водителя начального уровня, чтобы оно засчитывалось для права на CDL/эндорсмент?","options":["У провайдера из FMCSA Training Provider Registry (TPR)","В любой автошколе по выбору заявителя","Напрямую в полевом офисе New Mexico MVD","По внутренней программе работодателя, без необходимости регистрации в реестре"],"explanation":"ELDT должно быть пройдено у провайдера из FMCSA Training Provider Registry (TPR) на tpr.fmcsa.dot.gov; провайдер подаёт сертификацию в FMCSA. Источник: NM MVD Driver Manual Chapter 5; FMCSA TPR."},"33":{"q":"Самосертификация 'Non-Excepted Interstate' (NI) в Нью-Мексико означает, что водитель работает в межштатной коммерческой деятельности и:","options":["Должен соответствовать федеральным требованиям к медицинской справке DOT","Не обязан соответствовать никаким медицинским требованиям","Соответствует только медицинским требованиям штата Нью-Мексико","Освобождён, потому что управляет фермерским транспортным средством"],"explanation":"Выбор Non-Excepted Interstate (NI) удостоверяет, что водитель работает в межштатной коммерческой деятельности и обязан соответствовать требованиям к медицинской справке федерального DOT. Источник: NM MVD Driver Manual Chapter 5 (Medical Self-Certification)."},"34":{"q":"Какая категория медицинской самосертификации в Нью-Мексико применяется к водителю, который работает только в пределах Нью-Мексико и НЕ обязан соответствовать медицинским требованиям Нью-Мексико?","options":["EA (Excepted Intrastate)","NA (Non-Excepted Intrastate)","NI (Non-Excepted Interstate)","EI (Excepted Interstate)"],"explanation":"Excepted Intrastate (EA) означает, что водитель работает только в пределах Нью-Мексико и не обязан соответствовать медицинским требованиям штата Нью-Мексико. NA потребовала бы соответствия медицинским требованиям NM. Источник: NM MVD Driver Manual Chapter 5."},"35":{"q":"Помимо удостоверения личности и законного присутствия, какой набор документов должен предъявить заявитель на CDL в Нью-Мексико для подтверждения места жительства?","options":["Два подтверждения фактического проживания с адресом в Нью-Мексико","Один счёт за коммунальные услуги старше одного года","Один договор аренды из другого штата","Карточку регистрации избирателя из любого штата"],"explanation":"Нью-Мексико требует два подтверждения фактического проживания с адресом в Нью-Мексико, наряду с подтверждением личности, законного присутствия/гражданства США и номера социального страхования. Источник: NM MVD Driver Manual Chapter 5; NM CDL Acceptable Documents list."},"36":{"q":"Для документального подтверждения номера социального страхования для CDL в Нью-Мексико заявитель должен предоставить что из следующего?","options":["Карточку социального страхования или действительное подтверждение SSN","Только страницу с фото из паспорта","Два счёта за коммунальные услуги","Только свидетельство о рождении"],"explanation":"Нью-Мексико требует карточку социального страхования или иное действительное подтверждение номера социального страхования как часть документов на CDL (наряду с личностью, законным присутствием и двумя подтверждениями проживания). Источник: NM MVD Driver Manual Chapter 5; NM CDL Acceptable Documents."},"37":{"q":"Каков минимальный проходной балл по каждому теоретическому (письменному) экзамену CDL в Нью-Мексико?","options":["80%","70%","75%","90%"],"explanation":"Заявитель должен набрать не менее 80%, чтобы сдать каждый теоретический экзамен CDL в Нью-Мексико. Заявитель может сдавать теоретический экзамен до двух раз в неделю, но система блокирует третью попытку после двух провалов в течение 7-дневного периода. Источник: NM MVD Driver Manual Chapter 5."},"38":{"q":"Какой эндорсмент НЕ может быть добавлен впервые подающему заявление на Commercial Learner Permit (CLP) Нью-Мексико?","options":["H (Hazardous Materials)","N (Tank Vehicle)","P (Passenger)","S (School Bus)"],"explanation":"Эндорсмент H (HazMat) нельзя получить на CLP; он требует проверки угроз TSA и добавляется только к полному CDL. Эндорсменты N, P и S могут иметься на CLP (с применимыми ограничениями). Источник: NM MVD Driver Manual Chapter 5; 49 CFR 383.25."},"39":{"q":"В Нью-Мексико каков максимально допустимый уровень содержания алкоголя в крови (BAC) для водителя, управляющего коммерческим транспортным средством (CMV)?","options":["0.08%","0.04%","0.02%","0.00%"],"explanation":"Нью-Мексико следует федеральному стандарту для CMV: незаконно управлять CMV с BAC 0.04% или более (половина лимита 0.08% для некоммерческих водителей). Источник: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"40":{"q":"Согласно правилу подразумеваемого согласия Нью-Мексико, что происходит с держателем CDL, который управляет CMV?","options":["Он должен иметь отдельное разрешение на тест дыхания","Считается, что он дал согласие на проверку на алкоголь","Он может отказаться от проверки без каких-либо последствий","Он соглашается только если сначала официально арестован"],"explanation":"NM CDL Manual гласит, что, управляя CMV, вы 'считаетесь давшим согласие на проверку на алкоголь'. Отказ влечёт ту же дисквалификацию, что и тяжкое нарушение. Источник: NM CDL Manual section 1.3.2; NMSA 66-5-68 / Implied Consent Act."},"41":{"q":"В Нью-Мексико на какой срок водитель лишится CDL за ПЕРВОЕ тяжкое нарушение, например нарушение с BAC 0.04%, в CMV без табличек опасного груза?","options":["60 days","120 days","Не менее 1 года","Не менее 3 лет"],"explanation":"Нью-Мексико устанавливает минимальную дисквалификацию CDL на один год за первое тяжкое нарушение (например, BAC 0.04%, DUI, отказ от проверки, оставление места ДТП). Источник: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"42":{"q":"Если держатель CDL Нью-Мексико совершает первое тяжкое нарушение, управляя CMV, маркированным табличками для опасных грузов, на какой срок дисквалификация?","options":["Не менее 1 года","Не менее 2 лет","Не менее 3 лет","Пожизненно"],"explanation":"Нью-Мексико повышает дисквалификацию за первое нарушение до не менее 3 лет, если тяжкое нарушение происходит при управлении CMV, маркированным табличками для опасных грузов. Источник: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"43":{"q":"Каков срок дисквалификации CDL в Нью-Мексико за ВТОРОЕ тяжкое нарушение (например, второе DUI в CMV)?","options":["3 года","5 лет","10 лет","Пожизненно"],"explanation":"Нью-Мексико дисквалифицирует водителя от владения CDL пожизненно при втором тяжком нарушении. (Восстановление через 10 лет может быть возможно по правилам, но сама дисквалификация является пожизненным запретом.) Источник: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"44":{"q":"В Нью-Мексико отказ пройти проверку крови на алкоголь при управлении CMV рассматривается как что из следующего?","options":["Мелкое нарушение по документам","Серьёзное нарушение ПДД (тип на 60 дней)","Тяжкое нарушение (дисквалификация на 1 год)","Нарушение приказа о выводе из эксплуатации (out-of-service)"],"explanation":"Нью-Мексико рассматривает отказ пройти проверку крови на алкоголь как тяжкое нарушение, влекущее ту же минимальную дисквалификацию CDL на один год, что и осуждение за BAC 0.04%. Источник: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"45":{"q":"Водитель CMV в Нью-Мексико показывает обнаруживаемое количество алкоголя НИЖЕ 0.04%. Каково непосредственное последствие?","options":["Никаких последствий ниже 0.04%","Вывод из эксплуатации (out-of-service) на 24 часа","Дисквалификация CDL на 1 год","Дисквалификация CDL на 60 дней"],"explanation":"Нью-Мексико выводит водителя CMV из эксплуатации (out-of-service) на 24 часа при любом обнаруживаемом количестве алкоголя ниже 0.04%. Показатель 0.04% или более вместо этого является дисквалифицирующим тяжким нарушением. Источник: NM CDL Manual section 1.3.2."},"46":{"q":"Что из следующего классифицируется как 'серьёзное нарушение ПДД' для держателя CDL Нью-Мексико?","options":["Движение на 5 mph выше лимита","Чрезмерное превышение скорости на 15 mph или более выше установленного лимита","Нарушение правил парковки в CMV","Просроченная наклейка регистрации"],"explanation":"Нью-Мексико относит чрезмерное превышение скорости (15 mph или более выше установленного лимита) к серьёзным нарушениям ПДД, наряду с опасным вождением, неправильной сменой полосы и слишком близким следованием. Источник: NM CDL Manual section 1.3.3."},"47":{"q":"Что из следующего НЕ является одним из перечисленных в Нью-Мексико серьёзных нарушений ПДД для держателей CDL?","options":["Опасное вождение","Слишком близкое следование за транспортным средством","Неправильная или беспорядочная смена полосы","Управление CMV с перегоревшей фарой"],"explanation":"Перечень серьёзных нарушений ПДД Нью-Мексико включает опасное вождение, слишком близкое следование и неправильную/беспорядочную смену полосы; перегоревшая фара — это неисправность оборудования, а не перечисленное серьёзное нарушение. Источник: NM CDL Manual section 1.3.3."},"48":{"q":"В Нью-Мексико на какой срок водитель лишится CDL за совершение ДВУХ серьёзных нарушений ПДД в CMV в течение трёхлетнего периода?","options":["Не менее 30 days","Не менее 60 days","Не менее 120 days","Не менее 1 года"],"explanation":"Нью-Мексико дисквалифицирует держателя CDL не менее чем на 60 days за два серьёзных нарушения ПДД, совершённых в CMV в течение трёхлетнего периода. Источник: NM CDL Manual section 1.3.3; NMSA 66-5-68."},"49":{"q":"В Нью-Мексико на какой срок водитель лишится CDL за совершение ТРЁХ или более серьёзных нарушений ПДД в CMV в течение трёхлетнего периода?","options":["60 days","90 days","Не менее 120 days","Не менее 1 года"],"explanation":"Нью-Мексико дисквалифицирует держателя CDL не менее чем на 120 days за три или более серьёзных нарушений ПДД, совершённых в CMV в течение трёхлетнего периода. Источник: NM CDL Manual section 1.3.3; NMSA 66-5-68."},"50":{"q":"Управление CMV в Нью-Мексико без надлежащего класса CDL и/или требуемых эндорсментов считается чем?","options":["Серьёзным нарушением ПДД","Тяжким нарушением (1 год)","Нарушением приказа о выводе из эксплуатации (out-of-service)","Только предупреждением, а не нарушением"],"explanation":"Нью-Мексико относит управление CMV без надлежащего класса CDL и/или эндорсментов (или без наличия CDL при себе) к серьёзным нарушениям ПДД. Источник: NM CDL Manual section 1.3.3."},"51":{"q":"Какова минимальная дисквалификация CDL в Нью-Мексико за ПЕРВОЕ нарушение водителем приказа о выводе из эксплуатации (out-of-service)?","options":["Не менее 30 days","Не менее 60 days","Не менее 90 days","Не менее 1 года"],"explanation":"Нью-Мексико дисквалифицирует держателя CDL не менее чем на 90 days за первое нарушение приказа о выводе из эксплуатации (out-of-service). Источник: NM CDL Manual section 1.3.4; NMSA 66-5-68."},"52":{"q":"В Нью-Мексико на какой срок дисквалификация CDL за ВТОРОЕ нарушение приказа о выводе из эксплуатации (out-of-service) в течение десятилетнего периода?","options":["Не менее 90 days","Не менее 1 года","Не менее 3 лет","Не менее 5 лет"],"explanation":"Нью-Мексико дисквалифицирует держателя CDL не менее чем на 1 год за два нарушения приказа о выводе из эксплуатации (out-of-service) в течение десятилетнего периода. Источник: NM CDL Manual section 1.3.4; NMSA 66-5-68."},"53":{"q":"В Нью-Мексико какова минимальная дисквалификация CDL за ТРИ или более нарушений приказа о выводе из эксплуатации (out-of-service) в течение десятилетнего периода?","options":["1 год","Не менее 3 лет","5 лет","Пожизненно"],"explanation":"Нью-Мексико дисквалифицирует держателя CDL не менее чем на 3 года за три или более нарушений приказа о выводе из эксплуатации (out-of-service) в течение десятилетнего периода. Источник: NM CDL Manual section 1.3.4; NMSA 66-5-68."},"54":{"q":"В Нью-Мексико какова минимальная дисквалификация CDL за ПЕРВОЕ нарушение водителем правил на железнодорожном переезде?","options":["Не менее 30 days","Не менее 60 days","Не менее 120 days","Не менее 1 года"],"explanation":"Нью-Мексико дисквалифицирует держателя CDL не менее чем на 60 days за первое нарушение правил на железнодорожном переезде. Источник: NM CDL Manual section 1.3.5; NMSA 66-5-68."},"55":{"q":"Какова дисквалификация CDL в Нью-Мексико за ТРЕТЬЕ нарушение правил на железнодорожном переезде в течение трёхлетнего периода?","options":["120 days","180 days","Не менее 1 года","3 года"],"explanation":"Нью-Мексико дисквалифицирует держателя CDL не менее чем на 1 год за третье нарушение правил на железнодорожном переезде в течение трёхлетнего периода (60 days за первое, 120 days за второе). Источник: NM CDL Manual section 1.3.5; NMSA 66-5-68."},"56":{"q":"Согласно правилам Нью-Мексико/федеральным правилам, когда CDL водителя CMV становится подлежащим дисквалификации за использование портативного мобильного телефона во время вождения?","options":["После единственного первого осуждения","После двух или более осуждений","Только после ДТП по своей вине","Использование портативного телефона никогда не влечёт дисквалификации"],"explanation":"CDL Нью-Мексико дисквалифицируется после двух или более осуждений за использование портативного мобильного телефона при управлении CMV: 60 days за второе нарушение в течение 3 лет и 120 days за три или более в течение 3 лет. Источник: NM CDL Manual section 2.9.4."},"57":{"q":"Какой максимальный гражданский штраф может грозить водителю CMV в Нью-Мексико за нарушение запрета на использование портативного мобильного телефона / отправку сообщений?","options":["До $750","До $2,750","До $5,000","До $11,000"],"explanation":"Согласно федеральному ограничению, применяемому в Нью-Мексико, водитель, нарушивший запрет на использование портативного телефона/отправку сообщений, подлежит гражданскому штрафу до $2,750; работодатель, который это допускает или требует, сталкивается со штрафом до $11,000. Источник: NM CDL Manual section 2.9.4."},"58":{"q":"В Нью-Мексико суд может оштрафовать лицо на сумму до скольки за управление коммерческим транспортным средством без CDL или за владение более чем одним водительским удостоверением?","options":["До $1,000","До $2,750","До $5,000","До $11,000"],"explanation":"Нью-Мексико предусматривает, что суд может оштрафовать водителя на сумму до $5,000 (или назначить тюремное заключение) за управление CMV без CDL или за владение более чем одним водительским удостоверением. Источник: NM CDL Manual sections 1.3.7 and 1.4."},"59":{"q":"Согласно законодательству Нью-Мексико, когда школьный автобус остановился на проезжей части с включёнными специальными сигналами школьного автобуса для посадки или высадки детей, на каком расстоянии до автобуса должен остановиться приближающийся водитель?","options":["Не менее чем за 10 футов до автобуса","Не менее чем за 25 футов до автобуса","Не менее чем за 20 футов до автобуса","Не менее чем за 15 футов до автобуса"],"explanation":"NMSA 1978, Section 66-7-347(A) требует, чтобы водитель, приближающийся к остановленному школьному автобусу с включёнными сигналами или обгоняющий его, остановил транспортное средство не менее чем за десять футов до автобуса и не продолжал движение, пока сигналы не выключатся, автобус не тронется или водитель автобуса не подаст сигнал продолжать движение."},"60":{"q":"В Нью-Мексико какое именно условие позволяет водителю проехать мимо остановленного школьного автобуса, осуществляющего посадку детей, БЕЗ остановки?","options":["Есть две или более полосы в направлении движения водителя","Автобус находился более чем в 100 футах, когда его впервые заметили","Школьный автобус находится на другой проезжей части автомагистрали с раздельными проезжими частями","Водитель движется со скоростью менее 25 миль/ч"],"explanation":"NMSA 1978, Section 66-7-347(C) предусматривает единственное исключение для разделённых автомагистралей: водитель на автомагистрали с раздельными проезжими частями не обязан останавливаться перед автобусом, находящимся на другой проезжей части (или на автомагистрали с контролируемым доступом, где автобус находится в зоне посадки и пешеходам не разрешён переход). Простое наличие дополнительных полос или низкая скорость не освобождают от обязанности остановиться."},"61":{"q":"На автомагистрали Нью-Мексико школьный автобус, перевозящий детей, автобус, перевозящий пассажиров за плату, или транспортное средство с табличками опасных грузов должны остановиться перед железнодорожным переездом на каком расстоянии от ближайшего рельса?","options":["Не менее 25 футов и не более 75 футов","Не менее 10 футов и не более 40 футов","Не менее 15 футов и не более 50 футов","Не менее 5 футов и не более 25 футов"],"explanation":"NMSA 1978, Section 66-7-343(A) требует, чтобы эти транспортные средства останавливались не менее чем за 15 футов и не более чем за 50 футов от ближайшего рельса перед въездом на переезд. Руководство CDL Нью-Мексико (Sec. 2.15) устанавливает то же правило 15–50 футов."},"62":{"q":"Закон Нью-Мексико об остановке на железнодорожном переезде (66-7-343) требует, чтобы водитель соответствующего транспортного средства во время остановки на переезде включил настолько низкую передачу, чтобы:","options":["Можно было включить задний ход, если приближается поезд","Не пришлось переключать передачи до полного проезда переезда","Можно было задействовать моторный тормоз на дальней стороне","Транспортное средство могло тронуться на уклоне 5%"],"explanation":"NMSA 1978, Section 66-7-343(B)(3) требует выбора достаточно низкой передачи, чтобы не пришлось переключать передачи до выезда с переезда, а Subsection (C) запрещает переключение передач, находясь на переезде. Руководство CDL Нью-Мексико повторяет: «Не переключайте передачи при пересечении железнодорожных путей»."},"63":{"q":"Что из перечисленного НЕ является одним из исключений Нью-Мексико, освобождающих автобус или транспортное средство с табличками опасных грузов от остановки на железнодорожном переезде?","options":["Переезд, где работают мигающий красный сигнал и звонок","Переезд, где полицейский регулирует движение и разрешает проезд","Переезд, регулируемый светофором","Переезд, обозначенный знаком «exempt crossing» (переезд без обязательной остановки)"],"explanation":"NMSA 1978, Section 66-7-343(D) перечисляет исключения: регулировщик, направляющий движение, светофор, переезд для маневровых работ в пределах делового района, заброшенный переезд с соответствующим знаком и знак «exempt crossing». Действующий переезд с мигающим красным сигналом и звонком НЕ является исключением; транспортное средство всё равно должно остановиться."},"64":{"q":"Каково общее максимальное ограничение скорости, установленное законом Нью-Мексико для любого транспортного средства на автомагистрали, где не установлено более низкое ограничение?","options":["65 миль в час","75 миль в час","80 миль в час","70 миль в час"],"explanation":"NMSA 1978, Section 66-7-301(A)(3) устанавливает общий законодательный максимум в семьдесят пять миль в час. Эта величина применяется при отсутствии установленного более низкого ограничения или обозначенной зоны двойного штрафа."},"65":{"q":"Устанавливает ли Нью-Мексико более низкое законодательное максимальное ограничение скорости для седельных тягачей (крупных грузовиков), чем для легковых автомобилей?","options":["Да — для грузовиков законом установлено ограничение 60 миль/ч","Нет — единый законодательный максимум 75 миль/ч применяется и к грузовикам, и к легковым автомобилям","Да — для грузовиков законом установлено ограничение 55 миль/ч в ночное время","Да — для грузовиков законом установлено ограничение 65 миль/ч"],"explanation":"Нью-Мексико не является штатом с раздельными ограничениями скорости. Максимум 75 миль/ч в NMSA 1978, Section 66-7-301 применяется ко всем транспортным средствам. Законопроект 2025 года (SB226), предлагавший ограничение 65 миль/ч для седельных тягачей, был отклонён в комитете и так и не стал законом, поэтому отдельного законодательного ограничения скорости для грузовиков не существует."},"66":{"q":"Согласно закону Нью-Мексико, каково максимальное ограничение скорости при проезде мимо школы, когда дети идут в школу или из неё, а школьная зона надлежащим образом обозначена?","options":["25 миль в час","20 миль в час","30 миль в час","15 миль в час"],"explanation":"NMSA 1978, Section 66-7-301(A)(1) устанавливает ограничение 15 миль/ч на всех автомагистралях при проезде мимо школы, когда дети идут в школу или из неё, а зона надлежащим образом обозначена."},"67":{"q":"При отсутствии установленного ограничения какую скорость закон Нью-Мексико устанавливает для движения в деловом или жилом районе?","options":["20 миль в час","35 миль в час","30 миль в час","25 миль в час"],"explanation":"NMSA 1978, Section 66-7-301(A)(2) устанавливает ограничение 30 миль/ч в деловом или жилом районе, где не установлено иное ограничение."},"68":{"q":"С 1 июля 2023 года закон Нью-Мексико о движении по полосам (66-7-376) в общем случае ограничивает использование левой полосы на многополосной дороге какой ситуацией?","options":["Только между восходом и заходом солнца","Только при перевозке опасных грузов с табличками","Только при обгоне и опережении другого транспортного средства","Только при движении со скоростью выше 65 миль/ч"],"explanation":"NMSA 1978, Section 66-7-376(A)(4), принятый законопроектом SB102 (Laws 2023) и вступивший в силу 1 июля 2023 года, запрещает движение по левой полосе дороги, за исключением случаев обгона и опережения, если только условия движения, поток или конфигурация дороги (например, вливающийся транспорт) не требуют использования левой полосы."},"69":{"q":"Ограничение на использование левой полосы в Нью-Мексико по 66-7-376 НЕ применяется в каком из этих мест?","options":["На любой автомагистрали штата с тремя полосами в каждую сторону","В пределах городской черты муниципалитета, на дороге, не являющейся межштатной","На четырёхполосной разделённой автомагистрали США между городами","На сельском участке Interstate 40"],"explanation":"NMSA 1978, Section 66-7-376(A)(4) прямо указывает, что запрет на использование левой полосы не применяется в пределах городской черты муниципалитета или на окружной дороге, при условии что дорога не является частью национальной системы межштатных и оборонных автомагистралей."},"70":{"q":"Согласно закону Нью-Мексико об использовании полос, водитель, меняющий полосу, должен подавать сигнал о намерении сменить полосу не менее чем на протяжении последних скольких футов пути?","options":["100 футов","150 футов","200 футов","50 футов"],"explanation":"NMSA 1978, Section 66-7-376(A)(2) требует, чтобы перед перестроением из полосы водитель подавал сигнал о намерении сменить полосу не менее чем на протяжении последних ста футов пути транспортного средства."},"71":{"q":"Нью-Мексико обозначает полосу для левого поворота в обоих направлениях параллельными двойными жёлтыми линиями (внутренняя прерывистая, внешняя сплошная). Транспортное средство, готовящееся к левому повороту или совершающее его, не может двигаться по этой полосе на расстояние более скольких?","options":["300 футов","500 футов","200 футов","100 футов"],"explanation":"NMSA 1978, Section 66-7-376(B) предусматривает, что транспортные средства, поворачивающие налево с проезжей части, не должны двигаться по полосе для левого поворота в обоих направлениях на расстояние более двухсот футов при подготовке к повороту и его выполнении."},"72":{"q":"Согласно закону Нью-Мексико «Move Over», когда уполномоченное транспортное средство экстренных служб приближается с мигающими огнями или сиреной, водитель каждого другого транспортного средства должен:","options":["Перестроиться на одну полосу левее и сохранять скорость","Снизить скорость до 20 миль/ч и оставаться в текущей полосе","Немедленно остановиться в текущей полосе независимо от положения","Прижаться как можно ближе к правому краю или бордюру и остановиться, пока оно не проедет"],"explanation":"NMSA 1978, Section 66-7-332(A) требует, чтобы водители при непосредственном приближении уполномоченного транспортного средства экстренных служб уступали дорогу и немедленно направляли своё транспортное средство параллельно и как можно ближе к правому краю проезжей части или бордюру, вне зоны любого перекрёстка, и останавливались, пока оно не проедет, если только сотрудник не даст иных указаний."},"73":{"q":"Закон Нью-Мексико «Move Over» применяется к стоящему транспортному средству с мигающими аварийными огнями или огнями экстренных служб. Помимо уполномоченных транспортных средств экстренных служб, какие транспортные средства конкретно охватываются?","options":["Школьные автобусы на остановке","Транспортные средства почтовой доставки","Сельскохозяйственная техника на обочине","Транспортные средства эвакуации или ремонта (буксиры/тягачи)"],"explanation":"NMSA 1978, Section 66-7-332(B) распространяет обязанность «перестроиться и снизить скорость» при стоящем транспортном средстве на стоящее уполномоченное транспортное средство экстренных служб или транспортное средство эвакуации или ремонта с включёнными мигающими аварийными огнями или огнями экстренных служб."},"74":{"q":"Согласно закону Нью-Мексико «Move Over», когда водитель приближается к стоящему транспортному средству экстренных служб или эвакуации, но перестроиться из соседней полосы небезопасно, водитель должен:","options":["Полностью остановиться в полосе движения","Снизить скорость до разумной и осмотрительной в данных обстоятельствах, двигаться с осторожностью и быть готовым остановиться","Ускориться и быстро проехать место происшествия","Продолжать движение с установленной скоростью через этот участок"],"explanation":"NMSA 1978, Section 66-7-332(B)(2) предусматривает, что если перестроиться в полосу, не соседствующую со стоящим транспортным средством, разумно безопасно невозможно, водитель должен снизить скорость до разумной и осмотрительной в данных обстоятельствах, двигаться с осторожностью и быть готовым остановиться."},"75":{"q":"Если коммерческое транспортное средство в Нью-Мексико вынуждено остановиться на дороге с односторонним движением или на разделённой автомагистрали, где Руководство CDL требует размещать три предупреждающих устройства (светоотражающие треугольники)?","options":["Только непосредственно позади транспортного средства на расстоянии 100 футов","На 10 футов, 50 футов и 150 футов в сторону приближающегося транспорта","Только на 100 футов впереди и 100 футов позади","На 10 футов, 100 футов и 200 футов в сторону приближающегося транспорта"],"explanation":"Руководство CDL Нью-Мексико (Sec. 2.5) следует федеральному стандарту для CMV (49 CFR 392.22): на дороге с односторонним движением или разделённой автомагистрали размещайте предупреждающие устройства на расстоянии 10 футов, 100 футов и 200 футов в сторону приближающегося транспорта в течение 10 минут после остановки."},"76":{"q":"На двухполосной дороге с двусторонним (неразделённым) движением в Нью-Мексико, где Руководство CDL требует размещать предупреждающие треугольники остановившегося коммерческого транспортного средства?","options":["В пределах 10 футов от транспортного средства, а также 100 футов позади и 100 футов впереди транспортного средства","На 10, 100 и 200 футов позади транспортного средства","Только на 50 футов позади и 50 футов впереди","Только на 200 футов позади и 200 футов впереди"],"explanation":"Руководство CDL Нью-Мексико (Sec. 2.5) предписывает, что на двухполосной дороге, по которой движется транспорт в обоих направлениях, или на неразделённой автомагистрали следует разместить одно устройство в пределах 10 футов от передней или задней части и по одному на 100 футов позади и 100 футов впереди транспортного средства."},"77":{"q":"В Нью-Мексико, если коммерческое транспортное средство остановилось там, где холм, поворот или другое препятствие не позволяет увидеть предупреждающие треугольники в пределах 500 футов, водитель должен:","options":["Разместить все три треугольника в пределах 50 футов от заднего бампера","Оставить все треугольники на стандартных 10, 100 и 200 футах","Использовать только аварийную сигнализацию вместо треугольников","Переместить самый дальний треугольник дальше за препятствие, на расстояние до 500 футов от транспортного средства"],"explanation":"Руководство CDL Нью-Мексико (Sec. 2.5) указывает, что если холм, поворот или препятствие закрывают видимость в пределах 500 футов, самый дальний треугольник следует переместить дальше по дороге, на расстояние до 500 футов, чтобы другие водители получили предупреждение. NMSA 1978, Section 66-3-853 аналогично требует размещения на расстоянии от 100 до 500 футов вблизи таких препятствий."},"78":{"q":"Закон Нью-Мексико 66-3-849 требует, чтобы автобусы и крупные грузовики ВОЗИЛИ с собой какой набор аварийного предупреждающего оборудования?","options":["Три красных аварийных светоотражателя (или сигнальные огни/фальшфейеры) плюс два красных матерчатых флага","Один красный фонарь и один флаг","Только два жёлтых проблесковых маячка и огнетушитель","Четыре оранжевых конуса и светоотражающий жилет"],"explanation":"NMSA 1978, Section 66-3-849 требует, чтобы соответствующие транспортные средства (автобусы, грузовики, седельные тягачи и т.д.) возили с собой предупреждающие устройства, такие как три красных аварийных светоотражателя, два красных матерчатых флага и три фальшфейера (или эквивалентные сигнальные огни/фонари). Руководство CDL Нью-Мексико также перечисляет три светоотражающих треугольника, шесть фальшфейеров или три жидкостных сигнальных огня в качестве обязательных предупреждающих устройств для стоящего транспортного средства."},"79":{"q":"Какое ведомство штата выдаёт коммерческие водительские удостоверения (CDL) в Нью-Мексико?","options":["Motor Vehicle Division (MVD)","Департамент транспорта Нью-Мексико (NMDOT)","Бюро коммерческого транспорта Полиции штата","Public Regulation Commission (PRC)"],"explanation":"В Нью-Мексико CDL выдаются Motor Vehicle Division (MVD), входящим в состав Taxation and Revenue Department. NMDOT занимается дорогами и разрешениями на негабаритные/сверхтяжёлые перевозки, а не лицензированием водителей. Источник: MVD New Mexico, страница Commercial Driver's Licenses (CDL) и Chapter 5: Commercial Driver License."},"80":{"q":"При подаче заявления на CDL в Нью-Мексико заявители должны самостоятельно отнести себя к одной из скольких категорий водителей?","options":["Четыре категории","Две категории","Три категории","Шесть категорий"],"explanation":"Заявители на CDL в Нью-Мексико должны самостоятельно отнести себя к одной из четырёх категорий, описывающих тип коммерческой деятельности, в которой они предполагают работать: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) и Excepted Intrastate (EA). Источник: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.71."},"81":{"q":"Водитель с CDL в Нью-Мексико, который работает с пересечением границ штатов и НЕ освобождён от федеральных правил физической квалификации, должен самостоятельно отнести себя к какой категории?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Водитель, работающий в межштатной коммерции, который обязан соответствовать федеральным медицинским стандартам DOT, самостоятельно относит себя к категории Non-Excepted Interstate (NI) и должен иметь действующий Medical Examiner's Certificate, поданный в MVD. Источник: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.71."},"82":{"q":"Кто уполномочен проводить медицинский осмотр для получения Medical Examiner's Certificate для CDL в Нью-Мексико?","options":["Медицинский специалист, внесённый в National Registry of Certified Medical Examiners","Любой лицензированный врач в Нью-Мексико","Медсестра-практик в любой клинике неотложной помощи","Медицинский сотрудник полевого офиса MVD"],"explanation":"Все коммерческие водительские медицинские сертификации в Нью-Мексико должны выполняться медицинским специалистом, внесённым в FMCSA National Registry of Certified Medical Examiners. Наличия только общей медицинской лицензии недостаточно. Источник: MVD New Mexico, страница Commercial Driver's Licenses (CDL); FMCSA National Registry."},"83":{"q":"Как обладатель CDL в Нью-Мексико регистрирует DOT Medical Examiner's Certificate в штате?","options":["Подав копию сертификата в MVD, которое вносит медицинский статус в водительскую запись","Отправив его напрямую почтой в FMCSA в Вашингтоне, округ Колумбия","Храня оригинал карточки только в транспортном средстве; копия в MVD не предоставляется","Подав его в Департамент здравоохранения Нью-Мексико"],"explanation":"Обладатели CDL в Нью-Мексико должны предоставить в MVD (State Driver Licensing Agency) копию своего Medical Examiner's Certificate; затем MVD вносит статус медицинской сертификации в коммерческую водительскую запись (CDLIS). Карточка, которую возят в транспортном средстве, сама по себе не выполняет требование о подаче документа в штат. Источник: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.71(h)."},"84":{"q":"Перед сдачей экзамена на CDL впервые подающий заявление в Нью-Мексико, как правило, должен пройти какую федерально обязательную подготовку?","options":["Entry-Level Driver Training (ELDT) у провайдера из FMCSA Training Provider Registry","40-часовой курс OSHA по безопасности коммерческих транспортных средств","Аудиторный курс безопасного вождения Нью-Мексико","Стажировку не менее 90 дней у лицензированного перевозчика"],"explanation":"Впервые подающие заявление на CDL (а также при определённых повышениях класса/добавлении endorsement) должны пройти Entry-Level Driver Training (ELDT) у провайдера, внесённого в FMCSA Training Provider Registry, прежде чем сдавать экзамен по навыкам или теоретический экзамен. Правило применяется к заявителям с 7 февраля 2022 года и позднее. Источник: MVD New Mexico Chapter 5; FMCSA ELDT rule, 49 CFR Part 380."},"85":{"q":"Сколько времени после первичной выдачи Commercial Learner's Permit (CLP) в Нью-Мексико обладатель должен ждать, прежде чем получит право сдавать экзамен по навыкам на CDL?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 10 дней","Не менее 60 дней"],"explanation":"Обладатель CLP не имеет права сдавать экзамен по навыкам на CDL ранее чем через 14 дней после первичной выдачи CLP. Этот федеральный минимум обеспечивается MVD Нью-Мексико. Источник: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.25(a)(3)."},"86":{"q":"В течение какого срока действует Commercial Learner's Permit (CLP) в Нью-Мексико?","options":["1 год (с одним продлением без повторной сдачи экзаменов)","90 дней","6 месяцев","2 года"],"explanation":"CLP Нью-Мексико выдаётся на 1 год. Согласно федеральному стандарту он может быть один раз продлён в течение этого периода без повторной сдачи общего теоретического экзамена. Источник: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.25(c)."},"87":{"q":"Из скольких частей состоит экзамен по навыкам на CDL в Нью-Мексико, и каковы они?","options":["Три части: предрейсовый осмотр транспортного средства, базовое управление транспортным средством и вождение по дороге","Две части: письменный экзамен и поездка по дороге","Три части: тест на пневматические тормоза, тест на сдачу назад и ночное вождение","Четыре части: осмотр, сдача назад, шоссе и параллельная парковка"],"explanation":"Экзамен по навыкам на CDL состоит из трёх частей, которые должны быть сданы по порядку: предрейсовый осмотр транспортного средства, базовое управление транспортным средством (низкоскоростные манёвры) и экзамен по вождению по дороге. Источник: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.113."},"88":{"q":"Каков минимальный проходной балл на теоретических (письменных) экзаменах на CDL в Нью-Мексико?","options":["80 процентов","70 процентов","75 процентов","90 процентов"],"explanation":"Теоретические экзамены на CDL в Нью-Мексико должны быть сданы с результатом не менее 80 процентов, что соответствует федеральному стандарту. Источник: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.135."},"89":{"q":"Какое условие человек должен уже выполнять, прежде чем подавать заявление на CDL в Нью-Мексико?","options":["Иметь действующее водительское удостоверение Нью-Мексико Class D (обычное) или действующий CDL другого штата","Иметь passenger (P) endorsement, полученный в любом штате","Иметь федеральный допуск к опасным грузам от TSA","Иметь мотоциклетный endorsement в водительском удостоверении Нью-Мексико"],"explanation":"Чтобы подать заявление на CDL в Нью-Мексико, вы должны уже иметь действующее некоммерческое (Class D) водительское удостоверение Нью-Мексико или действующий CDL другого штата. Источник: MVD New Mexico, требования для получения CDL Нью-Мексико."},"90":{"q":"Согласно правилам MVD Нью-Мексико, сколько подтверждений фактического проживания в Нью-Мексико должен представить заявитель на CDL?","options":["Два подтверждения фактического проживания","Одно подтверждение фактического проживания","Три подтверждения фактического проживания","Подтверждение проживания не требуется"],"explanation":"Заявитель на CDL в Нью-Мексико должен представить два подтверждения фактического проживания в штате. Ежемесячные документы, такие как счета за коммунальные услуги или банковские выписки, используемые как подтверждение, должны быть датированы в пределах 60 дней до подачи заявления. Источник: MVD New Mexico, страница Commercial Driver's Licenses (CDL)."},"91":{"q":"Какие варианты цикла продления предлагает Нью-Мексико для CDL?","options":["Удостоверение на 4 года или на 8 лет","Удостоверение на 1 год или на 5 лет","Только удостоверение на 5 лет","Удостоверение на 2 года или на 6 лет"],"explanation":"Нью-Мексико предлагает CDL с циклом продления на 4 года или на 8 лет. Источник: MVD New Mexico FAQ и Chapter 5."},"92":{"q":"Почему обладатель CDL в Нью-Мексико может быть ограничен удостоверением на 4 года (вместо 8 лет)?","options":["Потому что у него есть Hazardous Materials (Hazmat) endorsement","Потому что у него есть passenger (P) endorsement","Потому что он ездит только внутри штата","Потому что он младше 30 лет"],"explanation":"Водители с Hazardous Materials (Hazmat) endorsement не могут получить CDL на 8 лет; периодическая проверка биографических данных TSA, связанная с Hazmat, ограничивает их циклом в 4 года. Источник: MVD New Mexico FAQ; правила TSA/FMCSA для Hazmat endorsement."},"93":{"q":"Как организованы теоретические экзамены на CDL в Нью-Мексико в части пересдач?","options":["Заявители могут сдавать письменные экзамены на CDL до двух раз в неделю","Заявители могут сдавать письменные экзамены только раз в 30 дней","Заявители получают неограниченное число пересдач в тот же день","Заявители могут сдавать письменные экзамены только раз в календарный год"],"explanation":"Нью-Мексико позволяет заявителям на CDL сдавать письменные (теоретические) экзамены на CDL до двух раз в неделю. Источник: MVD New Mexico, страница Commercial Driver's Licenses (CDL)."},"94":{"q":"Каков минимальный возраст для получения CDL Нью-Мексико с ограничением только для вождения внутри штата (intrastate)?","options":["18 лет","16 лет","21 год","19 лет"],"explanation":"Человек может получить CDL Нью-Мексико для вождения внутри штата в 18 лет; заявитель в возрасте 18–20 лет ограничен работой только внутри штата. Для работы в межштатной коммерции требуется возраст 21 год. Источник: MVD New Mexico Chapter 5; FMCSA 49 CFR 391.11."},"95":{"q":"Когда водитель обменивает действующий CDL другого штата на CDL Нью-Мексико того же класса и с теми же endorsements, какая сдача экзаменов обычно требуется?","options":["Письменные экзамены не требуются для эквивалентного класса и endorsements","Необходимо повторно сдать и письменный экзамен, и экзамен по навыкам","Необходимо повторно сдать только дорожный экзамен по навыкам","Необходимо повторить только предрейсовый осмотр"],"explanation":"Нью-Мексико не требует письменных экзаменов для обмена действующего CDL другого штата на CDL Нью-Мексико того же класса и с теми же endorsements. (Hazmat endorsement по-прежнему требует собственного экзамена и проверки биографических данных TSA.) Источник: MVD New Mexico, требования для получения CDL Нью-Мексико."},"96":{"q":"Помимо письменного теоретического экзамена, заявитель на CDL в Нью-Мексико, желающий получить Hazardous Materials (Hazmat) endorsement, должен также пройти что?","options":["Снятие отпечатков пальцев и оценку угрозы безопасности TSA (проверку биографических данных)","Отдельный дорожный экзамен по ночному вождению","10-дневный курс безопасного вождения","Проверку зрения в государственной клинике"],"explanation":"Водитель Нью-Мексико, желающий получить Hazmat endorsement, должен сдать теоретический экзамен по Hazmat и пройти снятие отпечатков пальцев для оценки угрозы безопасности TSA (проверки биографических данных), прежде чем endorsement будет предоставлен. Источник: MVD New Mexico, требования для получения CDL Нью-Мексико; TSA Hazmat Endorsement Threat Assessment Program."},"97":{"q":"Когда заявитель на CDL в Нью-Мексико возвращается в MVD для получения CDL после сдачи экзамена по навыкам, результаты экзамена обычно предоставляются в какой форме?","options":["В запечатанном конверте с баллами за экзамен по навыкам, предъявляемом вместе с CLP и необходимыми документами","В виде электронного письма, отправленного напрямую от экзаменатора в FMCSA","В виде устного отчёта, предоставляемого только руководителю экзаменатора","В виде балла, напечатанного на обороте регистрации транспортного средства, использованного на дорожном экзамене"],"explanation":"После сдачи экзамена по навыкам, проводимого утверждённым экзаменатором CDL, заявитель возвращается в MVD со своим водительским удостоверением, CLP и запечатанным конвертом с баллами за экзамен по навыкам для выдачи CDL. Источник: MVD New Mexico, требования для получения CDL Нью-Мексико."}},"tr":{"0":{"q":"New Mexico karayollarında, bir ticari aracın veya yükünün (aynalar ve belirli güvenlik cihazları hariç) büyük boyut izni olmaksızın yasal olarak izin verilen azami genişliği nedir?","options":["8 feet 6 inch (102 inches)","8 feet (96 inches)","9 feet (108 inches)","10 feet (120 inches)"],"explanation":"New Mexico, bir aracın veya yükün toplam dış genişliğini, aynalar ve onaylı güvenlik aksamı hariç olmak üzere 8 feet 6 inch (102 inches) ile sınırlar. Daha geniş bir yük, büyük boyut izni gerektirir. Kaynak: NMSA 1978, Section 66-7-402 (Araçların genişliği); NM CDL Manual."},"1":{"q":"New Mexico karayollarında bir aracın ve yükünün izin olmaksızın yasal olarak izin verilen azami yüksekliği nedir?","options":["14 feet","13 feet 6 inches","15 feet","13 feet"],"explanation":"New Mexico, azami araç ve yük yüksekliğini 14 feet olarak belirler. 14 feet üzerindeki yükler büyük boyut (aşırı yükseklik) izni gerektirir. Kaynak: NMSA 1978, Section 66-7-404 (Araçların ve yüklerin yüksekliği ve uzunluğu)."},"2":{"q":"New Mexico mevzuatına göre bir ticari aracın herhangi bir tek aksı üzerindeki azami brüt ağırlık nedir?","options":["21,600 pounds","20,000 pounds","22,400 pounds","18,000 pounds"],"explanation":"New Mexico'nun tek aks sınırı 21,600 pounds olup, 20,000 pound'luk federal Interstate tek aks sınırından daha yüksektir. Kaynak: NMSA 1978, Section 66-7-409 (Tek akslar, tekerlekler ve lastikler üzerindeki yük sınırları)."},"3":{"q":"New Mexico yasalarına göre, bir tandem aks grubu (birbirinden 4 feet aralıklı iki aks) üzerinde izin verilen azami ağırlık nedir?","options":["34,320 pounds","34,000 pounds","36,000 pounds","32,000 pounds"],"explanation":"New Mexico'nun aks grubu ağırlık tablosu, bir tandemde (yaklaşık 4 feet aralıklı iki aks) 34,320 pounds'a izin verir; bu, 34,000 pound'luk federal Interstate tandem sınırının biraz üzerindedir. Kaynak: NMSA 1978, Section 66-7-410 (Araçların ve yüklerin brüt ağırlığı)."},"4":{"q":"New Mexico karayollarında bir kamyon-römork kombinasyonunun izin olmaksızın azami toplam uzunluğu nedir?","options":["65 feet","60 feet","70 feet","75 feet"],"explanation":"New Mexico, genel olarak karayollarında bir toplam kombinasyonu (kamyon artı römork) 65 feet ile sınırlar; daha uzun kombinasyonlar büyük boyut izni gerektirir. Kaynak: NMSA 1978, Section 66-7-404 (Araçların ve yüklerin yüksekliği ve uzunluğu)."},"5":{"q":"New Mexico'nun Interstate (federal yardımlı) karayolu sisteminde, aşırı ağırlık izni olmaksızın izin verilen azami brüt araç ağırlığı nedir?","options":["80,000 pounds","86,400 pounds","84,000 pounds","90,000 pounds"],"explanation":"Interstate sisteminde New Mexico, 80,000 pound'luk federal brüt üst sınırı uygular. Eyaletin kendi yasal tablosu, belirli Interstate olmayan eyalet karayollarında biraz daha fazlasına izin verir, ancak izin olmaksızın Interstate azami değeri 80,000 pounds'tur. Kaynak: New Mexico'da uygulandığı şekliyle 23 U.S.C. 127; NMSA 1978, Section 66-7-410."},"6":{"q":"New Mexico'nun yasal brüt ağırlık tablosuna göre, Interstate olmayan bir eyalet karayolunda özel izin olmaksızın (yaklaşık 56 feet veya daha fazla yeterli aks aralığıyla) izin verilen azami brüt ağırlık nedir?","options":["86,400 pounds","80,000 pounds","94,000 pounds","84,000 pounds"],"explanation":"New Mexico'nun brüt ağırlık tablosu, Interstate olmayan eyalet karayollarında ilk ve son akslar arasındaki mesafe yaklaşık 56 feet veya daha fazla olduğunda en fazla 86,400 pounds'a ulaşır. Interstate sistemi, federal 80,000 pounds ile sınırlı kalmaya devam eder. Kaynak: NMSA 1978, Section 66-7-410 (Araçların ve yüklerin brüt ağırlığı)."},"7":{"q":"Belirlenmiş New Mexico karayollarında (Ulusal Ağ) izin olmaksızın çalışan bir yarı römorkun azami uzunluğu nedir?","options":["57 feet 6 inches","53 feet","48 feet","60 feet"],"explanation":"New Mexico, belirlenmiş Ulusal Ağ güzergahlarında 57 feet 6 inch'e kadar bir yarı römorka izin verir. Kaynak: NMSA 1978, Section 66-7-404 (Araçların ve yüklerin yüksekliği ve uzunluğu); NM CDL Manual."},"8":{"q":"New Mexico'da, Interstate sisteminde bir grup ardışık aks üzerindeki azami izin verilen brüt ağırlığı belirlemek için hangi formül kullanılır?","options":["Federal Köprü Formülü (Federal Bridge Formula)","Net Tonaj Kuralı","Aks Aralığı Bölümü","Brüt Kombinasyon Oranı"],"explanation":"Interstate sisteminde New Mexico, herhangi bir aks grubu üzerindeki ağırlığı, aralığa (L) ve aks sayısına (N) göre sınırlayan Federal Köprü Formülü'nü (Federal Bridge Formula), W = 500[(LN/(N-1)) + 12N + 36], uygular. Kaynak: New Mexico'da uygulandığı şekliyle 23 U.S.C. 127 / FBF; NM CDL Manual."},"9":{"q":"New Mexico eyalet karayollarında çalışan ticari araçlar için büyük boyut/aşırı ağırlık izinlerini kim verir?","options":["New Mexico Ulaştırma Departmanı (New Mexico Department of Transportation, NMDOT)","İlçe şerif ofisi","Federal Motorlu Taşıyıcı Güvenlik İdaresi (Federal Motor Carrier Safety Administration)","Yerel şehir bayındırlık departmanı"],"explanation":"New Mexico'da büyük boyut ve aşırı ağırlık izinleri, Giriş Noktaları / izin birimi ve çevrimiçi izin sistemi aracılığıyla yönetilen New Mexico Ulaştırma Departmanı (NMDOT) tarafından verilir. Kaynak: NMDOT İzinleri / Giriş Noktaları; NMSA 1978, Section 66-7-413."},"10":{"q":"Bir taşıyıcının, New Mexico'nun yasal ağırlık sınırlarını aşan tek ve bölünemez bir yükü taşıması gerekiyor. Taşıyıcının yolculuktan önce neyi edinmesi gerekir?","options":["Bir NMDOT aşırı ağırlık (özel) izni","Yeni bir CDL onayı","FMCSA'dan federal bir Interstate muafiyeti","Yalnızca yük sigortası kanıtı"],"explanation":"New Mexico'nun yasal boyut veya ağırlık sınırlarının üzerindeki bir yükü taşımak, genellikle bölünemez yükler için NMDOT'tan özel bir (büyük boyut/aşırı ağırlık) izin gerektirir. Kaynak: NMSA 1978, Section 66-7-413; NMDOT İzinleri."},"11":{"q":"New Mexico'nun tek aks kurallarına göre, herhangi bir tek tekerlek üzerinde izin verilen azami ağırlık nedir?","options":["11,000 pounds","10,000 pounds","12,500 pounds","9,000 pounds"],"explanation":"New Mexico, tek aks, tekerlek ve lastik yük kurallarının bir parçası olarak herhangi bir tek tekerlek üzerindeki yükü 11,000 pounds ile sınırlar. Kaynak: NMSA 1978, Section 66-7-409 (Tek akslar, tekerlekler ve lastikler üzerindeki yük sınırları)."},"12":{"q":"New Mexico'nun lastik yükü kuralı, ağırlığı lastik genişliğinin her inch'i başına ne kadarla sınırlar?","options":["Lastik genişliğinin her inch'i başına 600 pounds","Lastik genişliğinin her inch'i başına 500 pounds","Lastik genişliğinin her inch'i başına 800 pounds","Lastik genişliğinin her inch'i başına 1,000 pounds"],"explanation":"New Mexico, aks, tekerlek ve lastik yük sınırlarının bir parçası olarak lastik yüklemesini lastik genişliğinin her inch'i başına 600 pounds ile sınırlar. Kaynak: NMSA 1978, Section 66-7-409 (Tek akslar, tekerlekler ve lastikler üzerindeki yük sınırları)."},"13":{"q":"New Mexico'da bir büyük boyut/aşırı ağırlık izni en yaygın olarak hangi sürelerle verilir?","options":["Tek bir yolculuk veya yıllık bir dönem","Yalnızca tek bir yolculuk, asla daha uzun değil","Yalnızca azami 30 gün","Kalıcı olarak, son kullanma tarihi olmaksızın"],"explanation":"New Mexico büyük boyut/aşırı ağırlık izinleri, harekete bağlı olarak genellikle ya tek seferlik yolculuk izinleri ya da yıllık izinler olarak verilir. Kaynak: NMDOT İzinleri / Giriş Noktaları; NMSA 1978, Section 66-7-413."},"14":{"q":"New Mexico Interstate yollarında uygulandığı şekliyle Federal Köprü Formülü'nde (Federal Bridge Formula), L ve N değişkenleri neyi temsil eder?","options":["L = bir grubun dış aksları arasındaki feet cinsinden mesafe; N = gruptaki aks sayısı","L = pounds cinsinden yük; N = lastik sayısı","L = römork uzunluğu; N = ton cinsinden net ağırlık","L = yasal sınır; N = sahip olunan izin sayısı"],"explanation":"Federal Köprü Formülü'nde L, iki veya daha fazla ardışık aks grubunun uç noktaları (ilk ve son akslar) arasındaki feet cinsinden mesafedir ve N, o gruptaki aks sayısıdır. Kaynak: New Mexico'da uygulandığı şekliyle 23 U.S.C. 127 / FBF; NM CDL Manual."},"15":{"q":"Bir yarı römork yükünün genişliği 8 feet 8 inch'tir. New Mexico karayollarında yasal olarak taşınması için ne gereklidir?","options":["Bir NMDOT büyük boyut (aşırı genişlik) izni","Hiçbir şey; yasal genişlik içindedir","Yalnızca bir geniş yük bayrağı, izin gerekmez","Class A CDL'ye geçiş"],"explanation":"New Mexico'nun yasal genişlik sınırı 8 feet 6 inch'tir; 8 feet 8 inch'te yük bunu aşar, bu nedenle bir NMDOT aşırı genişlik büyük boyut izni gereklidir. Kaynak: NMSA 1978, Section 66-7-402; NMDOT İzinleri."},"16":{"q":"Genişlik veya uzunluk eşikleri aşıldığında, New Mexico refakat (kılavuz/pilot) araçları gerektirebilir. New Mexico, hareket halindeki bir yük için genellikle hangi genişliğin üzerinde refakat araçları gerektirir?","options":["14 feet'ten daha geniş","10 feet'ten daha geniş","8 feet 6 inch'ten daha geniş","20 feet'ten daha geniş"],"explanation":"New Mexico, genellikle genişliği 14 feet'i aşan yükler için (ve uzunluğu yaklaşık 90 feet'i aşan yükler için) refakat/pilot araçları gerektirir. Kaynak: NMDOT büyük boyut izni hareket gereklilikleri."},"17":{"q":"Bir taşıyıcı bugün New Mexico'da bir büyük boyut/aşırı ağırlık iznine en yaygın olarak nasıl başvurur?","options":["NMDOT'un çevrimiçi izin sistemi aracılığıyla","Vali ofisine kağıt bir form göndererek","Washington, D.C.'deki FMCSA'yı arayarak","Yalnızca bir ilçe adliyesinde şahsen"],"explanation":"New Mexico büyük boyut/aşırı ağırlık izinleri, esas olarak taşıyıcıların yük boyutlarını, ağırlığını, güzergahını ve seyahat tarihlerini girdiği NMDOT'un çevrimiçi izin sistemi aracılığıyla edinilir. Kaynak: NMDOT İzinleri / Giriş Noktaları."},"18":{"q":"New Mexico'nun brüt ağırlık rakamları, federal Interstate standardından farklıdır. 20,000 pound'luk federal Interstate tek aks sınırıyla karşılaştırıldığında, New Mexico'nun yasal tek aks sınırı:","options":["Daha yüksek, 21,600 pounds","Daha düşük, 18,000 pounds","Aynı, 20,000 pounds","Daha yüksek, 25,000 pounds"],"explanation":"New Mexico'nun yasal tek aks sınırı, 20,000 pound'luk federal Interstate tek aks sınırından daha yüksek olan 21,600 pounds'tur. Interstate sisteminin kendisinde hala daha düşük olan federal rakam geçerlidir. Kaynak: NMSA 1978, Section 66-7-409; 23 U.S.C. 127."},"19":{"q":"New Mexico'da, çekilen ünite(ler) 10,000 lbs GVWR'yi aştığında, en az hangi değerde bir Brüt Kombinasyon Ağırlık Derecesine (Gross Combination Weight Rating, GCWR) sahip herhangi bir araç kombinasyonunu kullanmak için Class A CDL gereklidir?","options":["26,001 veya daha fazla pounds","10,001 veya daha fazla pounds","18,001 veya daha fazla pounds","33,001 veya daha fazla pounds"],"explanation":"Bir New Mexico Class A CDL, çekilen ünite(ler)in GVWR'si 10,000 pounds'u aşması koşuluyla, 26,001 veya daha fazla pounds GCWR'ye sahip herhangi bir araç kombinasyonunu sürmeye yetki verir. Kaynak: NM MVD Driver Manual Chapter 5 (Ticari Sürücü Belgesi)."},"20":{"q":"Hangi New Mexico CDL sınıfı, 26,001 veya daha fazla pounds GVWR'ye sahip tek bir aracı veya 10,000 lbs GVWR'yi aşmayan bir üniteyi çeken böyle bir aracı sürmeye yetki verir?","options":["Class B","Class A","Class C","Class D"],"explanation":"Bir New Mexico Class B CDL, 26,001 veya daha fazla pounds GVWR'ye sahip herhangi bir tek aracı veya 10,000 pounds GVWR'yi aşmayan bir üniteyi çeken böyle bir aracı kapsar. 26,001 GCWR'nin üzerinde olup 10,000 lbs'den fazlasını çeken bir kombinasyon, Class A gerektirir. Kaynak: NM MVD Driver Manual Chapter 5."},"21":{"q":"26,001 lbs GVWR'nin altındaki bir araca New Mexico Class C CDL yalnızca hangi amaçla kullanıldığında uygulanır?","options":["16 veya daha fazla yolcu (sürücü dahil) ya da plakart gerektiren tehlikeli maddeler taşıma","5,000 lbs üzerindeki herhangi bir römorku çekme","Ücret karşılığında 9 veya daha fazla yolcu taşıma","Herhangi bir yük için eyalet sınırları arasında çalışma"],"explanation":"Bir New Mexico Class C CDL, 26,001 lbs GVWR'den daha az olan tek bir araca (veya 10,000 lbs'yi aşmayan bir üniteyi çeken bir araca) yalnızca sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlandığında ya da tehlikeli maddeler için plakart gerektiğinde uygulanır. Kaynak: NM MVD Driver Manual Chapter 5."},"22":{"q":"New Mexico tarafından benimsenen federal kurallara göre, bir Ticari Öğrenme İzni (Commercial Learner Permit, CLP) sahibi, CLP ilk verildikten sonra en az kaç gün geçene kadar CDL beceri testine giremez?","options":["14 gün","7 gün","30 gün","10 gün"],"explanation":"CLP sahibi, CLP'nin ilk verilmesinden sonraki ilk 14 gün içinde CDL beceri testine girmeye uygun değildir. New Mexico bu federal 14 günlük bekleme süresini uygular. Kaynak: NM MVD Driver Manual Chapter 5; 49 CFR 383.25."},"23":{"q":"Yalnızca eyalet içi (New Mexico içinde) ticaretle sınırlı bir New Mexico CDL'sinin verilmesi için asgari yaş nedir?","options":["18 yaşında","21 yaşında","16 yaşında","19 yaşında"],"explanation":"Bir başvuru sahibinin, eyalet içi ticaretle sınırlı bir New Mexico CDL'sine sahip olmak için en az 18 yaşında olması gerekir. 18-20 yaşları arasındaki bir sürücü, kendisini yalnızca New Mexico içinde sürmekle sınırlayan bir 'K' kısıtlaması alır. Kaynak: NM MVD Driver Manual Chapter 5."},"24":{"q":"Eyaletler arası (eyalet sınırları arasında) ticaret için bir New Mexico CDL'sinin verilmesi için asgari yaş nedir?","options":["21 yaşında","18 yaşında","23 yaşında","25 yaşında"],"explanation":"Bir sürücünün eyaletler arası ticarette bir ticari motorlu araç kullanması için en az 21 yaşında olması gerekir. 18-20 yaşları arasındaki New Mexico sürücüleri eyalet içi çalışmayla sınırlıdır. Kaynak: NM MVD Driver Manual Chapter 5; 49 CFR 391.11."},"25":{"q":"Bir New Mexico CDL'sinde, 'K' kısıtlaması sürücü hakkında neyi belirtir?","options":["Yalnızca eyalet içi ticaretle sınırlı","Hava frenleri olmayan araçlarla sınırlı","Otomatik şanzımanlı araçlarla sınırlı","Yolcu taşıyamaz"],"explanation":"New Mexico, 18-20 yaşları arasındaki başvuru sahiplerine verilen CDL'lere, sürücüyü yalnızca eyalet içi (New Mexico içinde) ticaretle sınırlayan bir 'K' kısıtlaması koyar. Kaynak: NM MVD Driver Manual Chapter 5."},"26":{"q":"Sıvı veya gaz halindeki maddeleri dökme olarak taşıyan bir tank aracını kullanmak için bir New Mexico CDL'sinde hangi onay gereklidir?","options":["N (Tank Aracı)","T (İkili/Üçlü)","H (Tehlikeli Maddeler)","P (Yolcu)"],"explanation":"N onayı, sıvı veya gaz halindeki maddeleri dökme olarak taşımak için kullanılan bir tank aracının kullanımına yetki verir. N onayı, gerekli bilgi testi geçildikten sonra bir CLP'ye eklenebilir. Kaynak: NM MVD Driver Manual Chapter 5."},"27":{"q":"Tek bir güç ünitesinin arkasında iki veya üç römork çekmek için hangi New Mexico CDL onayı gereklidir?","options":["T (İkili/Üçlü)","N (Tank Aracı)","S (Okul Otobüsü)","X (Kombinasyon)"],"explanation":"T onayı, ikili veya üçlü römork çekmeye yetki verir ve bir bilgi testi geçmeyi gerektirir. Kaynak: NM MVD Driver Manual Chapter 5; 49 CFR 383.93."},"28":{"q":"Bir New Mexico CDL sahibinin, sürücü dahil 16 veya daha fazla kişiyi taşımak için tasarlanmış bir ticari aracı sürmek için hangi onaya ihtiyacı vardır?","options":["P (Yolcu)","S (Okul Otobüsü)","N (Tank Aracı)","T (İkili/Üçlü)"],"explanation":"P (Yolcu) onayı, sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlanmış bir aracı sürmek için gereklidir. Beceri testi, o sınıfı temsil eden bir araçta yapılmalıdır. Kaynak: NM MVD Driver Manual Chapter 5; 49 CFR 383.93."},"29":{"q":"H (Tehlikeli Maddeler) onayı verilmeden önce, bir New Mexico başvuru sahibinin hangi güvenlik taramasını geçmesi gerekir?","options":["Universal Enroll aracılığıyla TSA parmak izi temelli bir geçmiş/tehdit değerlendirmesi","Yalnızca bir FBI en çok arananlar listesi karşılaştırması","Yalnızca eyalet polisi tarafından yapılan bir sabıka kaydı kontrolü","Parmak izi olmaksızın bir New Mexico MVD görüşmesi"],"explanation":"New Mexico MVD, başvuru sahibi Universal Enroll sistemi aracılığıyla TSA parmak izi temelli bir geçmiş kontrolünü (Tehlikeli Maddeler Onayı Tehdit Değerlendirmesi) tamamlayana ve TSA başvuru sahibinin bir güvenlik tehdidi olmadığına karar verene kadar HazMat (H) onayını veremez. Kaynak: NM MVD Tehlikeli Madde Onayı sayfası; 49 CFR 1572."},"30":{"q":"New Mexico'da ilk kez alınan bir HazMat (H) onayı için ELDT, başvuru sahibinin bilgi testinden önce hangi eğitimi tamamlamasını gerektirir?","options":["FMCSA Eğitim Sağlayıcı Kayıt Listesi'nde (Training Provider Registry) yer alan bir sağlayıcı ile tehlikeli maddeler teori eğitimi","Yalnızca direksiyon başında saha eğitimi","40 saatlik yüz yüze bir HazMat yol kursu","Eğitim yok; yalnızca TSA geçmiş kontrolü"],"explanation":"İlk kez H onayı başvuranlar, bilgi testine girmeden önce FMCSA Eğitim Sağlayıcı Kayıt Listesi'nde (Training Provider Registry) listelenen bir sağlayıcıdan HazMat teori eğitimini (H için direksiyon başında bileşen gerekmez) tamamlamalıdır. Kaynak: NM MVD Driver Manual Chapter 5; 49 CFR 380.725."},"31":{"q":"ELDT gereklilikleri, ilk CLP başvurusunu hangi tarihte veya sonrasında yapan ilk kez başvuran New Mexico başvuru sahiplerine uygulanır?","options":["7 Şubat 2022","1 Ocak 2020","30 Eylül 2021","1 Temmuz 2023"],"explanation":"7 Şubat 2022 tarihinde veya sonrasında ilk kez CLP başvurusu yapan tüm başvuru sahipleri, 49 CFR 380.600-380.603'teki federal Giriş Seviyesi Sürücü Eğitimi (Entry-Level Driver Training, ELDT) kurallarına uymak zorundadır. Kaynak: NM MVD Driver Manual Chapter 5."},"32":{"q":"Bir New Mexico ELDT başvuru sahibi, CDL/onay uygunluğuna sayılması için gerekli giriş seviyesi sürücü eğitimini nereden almalıdır?","options":["FMCSA Eğitim Sağlayıcı Kayıt Listesi'nde (Training Provider Registry, TPR) listelenen bir sağlayıcıdan","Başvuru sahibinin seçtiği herhangi bir ticari sürücü okulundan","Doğrudan New Mexico MVD saha ofisinden","Kayıt gerekmeden bir işverenin kurum içi programından"],"explanation":"ELDT, FMCSA Eğitim Sağlayıcı Kayıt Listesi'nde (Training Provider Registry, TPR) tpr.fmcsa.dot.gov adresinde listelenen bir sağlayıcı ile tamamlanmalıdır; sağlayıcı sertifikasyonu FMCSA'ya gönderir. Kaynak: NM MVD Driver Manual Chapter 5; FMCSA TPR."},"33":{"q":"Bir New Mexico 'Non-Excepted Interstate' (NI) öz beyanı, sürücünün eyaletler arası ticarette çalıştığı ve:","options":["Federal DOT tıbbi kart gerekliliklerini karşılaması gerektiği anlamına gelir","Herhangi bir tıbbi gerekliliği karşılamak zorunda olmadığı anlamına gelir","Yalnızca New Mexico eyalet tıbbi gerekliliklerini karşıladığı anlamına gelir","Bir çiftlik aracı kullandığı için muaf olduğu anlamına gelir"],"explanation":"Non-Excepted Interstate (NI) seçimi, sürücünün eyaletler arası ticarette çalıştığını ve federal DOT tıbbi muayene sertifikası gerekliliklerini karşılamasının zorunlu olduğunu beyan eder. Kaynak: NM MVD Driver Manual Chapter 5 (Tıbbi Öz Beyan)."},"34":{"q":"Hangi New Mexico tıbbi öz beyan kategorisi, yalnızca New Mexico içinde çalışan ve New Mexico'nun tıbbi gerekliliklerini karşılaması GEREKMEYEN bir sürücüye uygulanır?","options":["EA (Excepted Intrastate)","NA (Non-Excepted Intrastate)","NI (Non-Excepted Interstate)","EI (Excepted Interstate)"],"explanation":"Excepted Intrastate (EA), sürücünün yalnızca New Mexico içinde çalıştığı ve New Mexico Eyaleti tıbbi gerekliliklerini karşılamak zorunda olmadığı anlamına gelir. NA, NM tıbbi gerekliliklerini karşılamayı gerektirir. Kaynak: NM MVD Driver Manual Chapter 5."},"35":{"q":"Kimlik ve yasal mevcudiyetin yanı sıra, bir New Mexico CDL başvuru sahibinin ikametgahı kanıtlamak için hangi belge setini sunması gerekir?","options":["Bir New Mexico adresini gösteren iki fiziksel ikametgah kanıtı","Bir yıldan eski bir adet fatura","Tek bir eyalet dışı kira sözleşmesi","Herhangi bir eyaletten seçmen kayıt kartı"],"explanation":"New Mexico, kimlik kanıtı, yasal mevcudiyet/ABD vatandaşlığı ve Sosyal Güvenlik numarasının yanı sıra bir New Mexico adresini gösteren iki fiziksel ikametgah kanıtı gerektirir. Kaynak: NM MVD Driver Manual Chapter 5; NM CDL Kabul Edilen Belgeler listesi."},"36":{"q":"Bir New Mexico CDL'si için bir Sosyal Güvenlik Numarasını belgelemek için, bir başvuru sahibi aşağıdakilerden hangisini sağlamalıdır?","options":["Bir Sosyal Güvenlik kartı veya SSN'nin geçerli bir kanıtı","Yalnızca bir pasaport fotoğraf sayfası","İki adet fatura","Tek başına bir doğum belgesi"],"explanation":"New Mexico, CDL başvuru belgelerinin bir parçası olarak (kimlik, yasal mevcudiyet ve iki ikametgah kanıtının yanı sıra) bir Sosyal Güvenlik kartı veya Sosyal Güvenlik Numarasının başka bir geçerli kanıtını gerektirir. Kaynak: NM MVD Driver Manual Chapter 5; NM CDL Kabul Edilen Belgeler."},"37":{"q":"Her New Mexico CDL bilgi (yazılı) testinde asgari geçer puan nedir?","options":["%80","%70","%75","%90"],"explanation":"Bir başvuru sahibinin her New Mexico CDL bilgi sınavını geçmek için en az %80 alması gerekir. Bir başvuru sahibi bir bilgi testine haftada en fazla iki kez girebilir, ancak sistem 7 günlük bir süre içinde iki başarısızlıktan sonra üçüncü bir girişimi engeller. Kaynak: NM MVD Driver Manual Chapter 5."},"38":{"q":"İlk kez başvuran biri, bir New Mexico Ticari Öğrenme İzni'ne (Commercial Learner Permit, CLP) hangi onayı EKLETEMEZ?","options":["H (Tehlikeli Maddeler)","N (Tank Aracı)","P (Yolcu)","S (Okul Otobüsü)"],"explanation":"H (HazMat) onayı bir CLP üzerinde alınamaz; bir TSA tehdit değerlendirmesi gerektirir ve yalnızca tam bir CDL'ye eklenir. N, P ve S onayları (geçerli kısıtlamalarla) bir CLP'de taşınabilir. Kaynak: NM MVD Driver Manual Chapter 5; 49 CFR 383.25."},"39":{"q":"New Mexico'da, bir ticari motorlu araç (CMV) kullanan bir sürücü için azami yasal kandaki alkol konsantrasyonu (BAC) nedir?","options":["0.08%","0.04%","0.02%","0.00%"],"explanation":"New Mexico federal CMV standardını izler: bir CMV'yi 0.04% veya daha fazla BAC ile kullanmak yasa dışıdır (ticari olmayan sürücüler için 0.08% sınırının yarısı). Kaynak: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"40":{"q":"New Mexico'nun zımni rıza kuralına göre, bir CMV kullanan bir CDL sahibine ne olur?","options":["Ayrı bir nefes testi izni taşımaları gerekir","Alkol testine rıza göstermiş sayılırlar","Hiçbir cezaya tabi olmadan testi reddedebilirler","Yalnızca önce resmi olarak tutuklanırlarsa rıza gösterirler"],"explanation":"NM CDL Manual, bir CMV kullanarak 'alkol testine rıza göstermiş sayılacağınızı' belirtir. Ret, büyük bir suç ile aynı diskalifiyeyi taşır. Kaynak: NM CDL Manual section 1.3.2; NMSA 66-5-68 / Zımni Rıza Yasası."},"41":{"q":"New Mexico'da, plakart gerektirmeyen bir CMV'de 0.04% BAC ihlali gibi bir İLK büyük suç için bir sürücü CDL'sini ne kadar süre kaybeder?","options":["60 gün","120 gün","En az 1 yıl","En az 3 yıl"],"explanation":"New Mexico, ilk büyük bir suç için (ör. 0.04% BAC, DUI, test reddi, kaza yerini terk etme) asgari bir yıllık CDL diskalifiyesi uygular. Kaynak: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"42":{"q":"Bir New Mexico CDL sahibi, tehlikeli maddeler için plakart taşıyan bir CMV'yi kullanırken ilk büyük bir suç işlerse, diskalifiye süresi ne kadardır?","options":["En az 1 yıl","En az 2 yıl","En az 3 yıl","Ömür boyu"],"explanation":"New Mexico, büyük suç tehlikeli maddeler için plakart taşıyan bir CMV kullanılırken işlenirse ilk suç diskalifiyesini en az 3 yıla yükseltir. Kaynak: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"43":{"q":"İKİNCİ bir büyük suç (bir CMV'de ikinci bir DUI gibi) için New Mexico CDL diskalifiye süresi nedir?","options":["3 yıl","5 yıl","10 yıl","Ömür boyu"],"explanation":"New Mexico, ikinci bir büyük suç durumunda bir sürücüyü bir CDL'ye sahip olmaktan ömür boyu diskalifiye eder. (Kural gereği 10 yıl sonra yeniden verme mümkün olabilir, ancak diskalifiyenin kendisi ömür boyu bir yasaktır.) Kaynak: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"44":{"q":"New Mexico'da, bir CMV kullanırken kandaki alkol testine rıza göstermeyi reddetmek aşağıdakilerden hangisi olarak değerlendirilir?","options":["Küçük bir evrak ihlali","Ciddi bir trafik ihlali (60 günlük tip)","Büyük bir suç (1 yıllık diskalifiye)","Bir hizmet dışı emri ihlali"],"explanation":"New Mexico, kandaki alkol testine girmeyi reddetmeyi, 0.04% BAC mahkumiyeti ile aynı asgari bir yıllık CDL diskalifiyesini taşıyan büyük bir suç olarak değerlendirir. Kaynak: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"45":{"q":"Bir New Mexico CMV sürücüsü, 0.04%'in ALTINDA tespit edilebilir bir miktar alkol kaydeder. Anında sonuç nedir?","options":["0.04%'in altında sonuç yok","24 saat boyunca hizmet dışı bırakılır","1 yıllık CDL diskalifiyesi","60 günlük CDL diskalifiyesi"],"explanation":"New Mexico, 0.04%'in altındaki herhangi bir tespit edilebilir alkol miktarı için bir CMV sürücüsünü 24 saat boyunca hizmet dışı bırakır. 0.04% veya daha fazla bir okuma ise bunun yerine diskalifiye edici büyük bir suçtur. Kaynak: NM CDL Manual section 1.3.2."},"46":{"q":"Aşağıdakilerden hangisi bir New Mexico CDL sahibi için 'ciddi trafik ihlali' olarak sınıflandırılır?","options":["Limitin 5 mph üzerinde sürmek","Belirlenen limitin 15 mph veya daha fazla üzerinde aşırı hız yapmak","Bir CMV'de bir park ihlali","Süresi dolmuş bir tescil etiketi"],"explanation":"New Mexico, aşırı hızı (belirlenen limitin 15 mph veya daha fazla üzeri) tehlikeli sürüş, uygunsuz şerit değişiklikleri ve çok yakın takip ile birlikte ciddi bir trafik ihlali olarak listeler. Kaynak: NM CDL Manual section 1.3.3."},"47":{"q":"Aşağıdakilerden hangisi CDL sahipleri için New Mexico'nun listelediği ciddi trafik ihlallerinden biri DEĞİLDİR?","options":["Tehlikeli sürüş","Bir aracı çok yakından takip etmek","Uygunsuz veya düzensiz şerit değişiklikleri","Yanmış bir farla CMV kullanmak"],"explanation":"New Mexico'nun ciddi trafik ihlali listesi tehlikeli sürüş, çok yakın takip ve uygunsuz/düzensiz şerit değişikliklerini içerir; yanmış bir far bir ekipman sorunudur, listelenen ciddi bir ihlal değildir. Kaynak: NM CDL Manual section 1.3.3."},"48":{"q":"New Mexico'da, üç yıllık bir süre içinde bir CMV'de İKİ ciddi trafik ihlali işleyen bir sürücü CDL'sini ne kadar süre kaybeder?","options":["En az 30 gün","En az 60 gün","En az 120 gün","En az 1 yıl"],"explanation":"New Mexico, üç yıllık bir süre içinde bir CMV'de işlenen iki ciddi trafik ihlali için bir CDL sahibini en az 60 gün diskalifiye eder. Kaynak: NM CDL Manual section 1.3.3; NMSA 66-5-68."},"49":{"q":"New Mexico'da, üç yıllık bir süre içinde bir CMV'de ÜÇ veya daha fazla ciddi trafik ihlali işleyen bir sürücü CDL'sini ne kadar süre kaybeder?","options":["60 gün","90 gün","En az 120 gün","En az 1 yıl"],"explanation":"New Mexico, üç yıllık bir süre içinde bir CMV'de işlenen üç veya daha fazla ciddi trafik ihlali için bir CDL sahibini en az 120 gün diskalifiye eder. Kaynak: NM CDL Manual section 1.3.3; NMSA 66-5-68."},"50":{"q":"New Mexico'da uygun CDL sınıfı ve/veya gerekli onaylar olmadan bir CMV kullanmak ne olarak değerlendirilir?","options":["Ciddi bir trafik ihlali","Büyük bir suç (1 yıl)","Bir hizmet dışı ihlali","Yalnızca bir uyarı, ihlal değil"],"explanation":"New Mexico, uygun CDL sınıfı ve/veya onaylar olmadan (veya CDL'yi yanında bulundurmadan) bir CMV kullanmayı ciddi bir trafik ihlali olarak listeler. Kaynak: NM CDL Manual section 1.3.3."},"51":{"q":"New Mexico'da bir sürücünün İLK hizmet dışı emri ihlali için asgari CDL diskalifiyesi nedir?","options":["En az 30 gün","En az 60 gün","En az 90 gün","En az 1 yıl"],"explanation":"New Mexico, ilk hizmet dışı emri ihlali için bir CDL sahibini en az 90 gün diskalifiye eder. Kaynak: NM CDL Manual section 1.3.4; NMSA 66-5-68."},"52":{"q":"New Mexico'da, on yıllık bir süre içinde İKİNCİ bir hizmet dışı emri ihlali için CDL diskalifiyesi ne kadardır?","options":["En az 90 gün","En az 1 yıl","En az 3 yıl","En az 5 yıl"],"explanation":"New Mexico, on yıllık bir süre içinde iki hizmet dışı emri ihlali için bir CDL sahibini en az 1 yıl diskalifiye eder. Kaynak: NM CDL Manual section 1.3.4; NMSA 66-5-68."},"53":{"q":"New Mexico'da, on yıllık bir süre içinde ÜÇ veya daha fazla hizmet dışı emri ihlali için asgari CDL diskalifiyesi nedir?","options":["1 yıl","En az 3 yıl","5 yıl","Ömür boyu"],"explanation":"New Mexico, on yıllık bir süre içinde üç veya daha fazla hizmet dışı emri ihlali için bir CDL sahibini en az 3 yıl diskalifiye eder. Kaynak: NM CDL Manual section 1.3.4; NMSA 66-5-68."},"54":{"q":"New Mexico'da bir sürücünün İLK demiryolu-karayolu hemzemin geçit ihlali için asgari CDL diskalifiyesi nedir?","options":["En az 30 gün","En az 60 gün","En az 120 gün","En az 1 yıl"],"explanation":"New Mexico, ilk demiryolu-karayolu hemzemin geçit ihlali için bir CDL sahibini en az 60 gün diskalifiye eder. Kaynak: NM CDL Manual section 1.3.5; NMSA 66-5-68."},"55":{"q":"Üç yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali için New Mexico CDL diskalifiyesi nedir?","options":["120 gün","180 gün","En az 1 yıl","3 yıl"],"explanation":"New Mexico, üç yıllık bir süre içinde üçüncü bir demiryolu-karayolu hemzemin geçit ihlali için bir CDL sahibini en az 1 yıl diskalifiye eder (ilk 60 gün, ikinci 120 gün). Kaynak: NM CDL Manual section 1.3.5; NMSA 66-5-68."},"56":{"q":"New Mexico/federal kurallara göre, bir CMV sürücüsünün CDL'si, sürüş sırasında elde tutulan bir cep telefonu kullanmaktan dolayı ne zaman diskalifiyeye tabi olur?","options":["Tek bir ilk mahkumiyetten sonra","İki veya daha fazla mahkumiyetten sonra","Yalnızca kusurlu bir kazadan sonra","Elde tutarak kullanım asla diskalifiye edici değildir"],"explanation":"Bir New Mexico CDL'si, bir CMV kullanırken elde tutulan cep telefonu kullanımı için iki veya daha fazla mahkumiyetten sonra diskalifiye edilir: 3 yıl içinde ikinci suç için 60 gün ve 3 yıl içinde üç veya daha fazlası için 120 gün. Kaynak: NM CDL Manual section 2.9.4."},"57":{"q":"New Mexico'da bir CMV sürücüsünün, elde tutulan cep telefonu / mesajlaşma yasağını ihlal etmekten dolayı karşılaşabileceği azami idari para cezası nedir?","options":["750 dolara kadar","2,750 dolara kadar","5,000 dolara kadar","11,000 dolara kadar"],"explanation":"New Mexico'da uygulanan federal kısıtlamaya göre, elde tutulan telefon/mesajlaşma yasağını ihlal eden bir sürücü 2,750 dolara kadar idari para cezasına tabidir; buna izin veren veya bunu zorunlu kılan bir işveren 11,000 dolara kadar ceza ile karşı karşıya kalır. Kaynak: NM CDL Manual section 2.9.4."},"58":{"q":"New Mexico'da bir mahkeme, bir CDL olmadan bir ticari motorlu araç kullanmaktan veya birden fazla ehliyete sahip olmaktan dolayı bir kişiye en fazla ne kadar para cezası verebilir?","options":["1,000 dolara kadar","2,750 dolara kadar","5,000 dolara kadar","11,000 dolara kadar"],"explanation":"New Mexico, bir mahkemenin bir CDL olmadan bir CMV kullanmaktan veya birden fazla ehliyete sahip olmaktan dolayı bir sürücüye 5,000 dolara kadar para cezası verebileceğini (veya hapis cezası uygulayabileceğini) öngörür. Kaynak: NM CDL Manual sections 1.3.7 and 1.4."},"59":{"q":"New Mexico yasalarına göre, bir okul otobüsü çocukları bindirmek veya indirmek için özel okul otobüsü sinyalleri çalışır halde yol üzerinde durduğunda, yaklaşan bir sürücü otobüsten ne kadar mesafe önce durmak zorundadır?","options":["Otobüse ulaşmadan en az 10 feet önce","Otobüse ulaşmadan en az 25 feet önce","Otobüse ulaşmadan en az 20 feet önce","Otobüse ulaşmadan en az 15 feet önce"],"explanation":"NMSA 1978, Section 66-7-347(A), sinyalleri çalışır halde duran bir okul otobüsüne yaklaşan veya onu geçen bir sürücünün, aracını otobüse ulaşmadan en az on feet önce durdurmasını ve sinyaller kapanana, otobüs hareket edene veya sürücü devam etmesi için işaret verene kadar ilerlememesini gerektirir."},"60":{"q":"New Mexico'da, çocukları bindiren duran bir okul otobüsünü DURMADAN geçmesine bir sürücüye izin veren kesin koşul hangisidir?","options":["Sürücünün gittiği yönde iki veya daha fazla şerit bulunması","Otobüs ilk görüldüğünde 100 feet'ten daha uzakta olması","Okul otobüsünün, ayrı yol platformlarına sahip bir karayolunun farklı bir yol platformunda bulunması","Sürücünün 25 mph altında seyretmesi"],"explanation":"NMSA 1978, Section 66-7-347(C), bölünmüş karayolu istisnasının tek halini sağlar: ayrı yol platformlarına sahip bir karayolunda seyreden bir sürücü, farklı bir yol platformundaki bir otobüs için durmak zorunda değildir (veya otobüsün bir bindirme bölgesinde olduğu ve yayaların karşıdan karşıya geçmesine izin verilmeyen kontrollü erişimli bir karayolunda). Yalnızca fazladan şerit bulunması veya düşük hız, durma zorunluluğunu ortadan kaldırmaz."},"61":{"q":"Bir New Mexico karayolunda, çocuk taşıyan bir okul otobüsü, ücret karşılığı yolcu taşıyan bir otobüs veya plakartlı tehlikeli madde taşıyan bir araç, bir demiryolu-karayolu hemzemin geçidinden önce en yakın raya hangi mesafede durmak zorundadır?","options":["25 feet'ten az olmamak ve 75 feet'ten fazla olmamak üzere","10 feet'ten az olmamak ve 40 feet'ten fazla olmamak üzere","15 feet'ten az olmamak ve 50 feet'ten fazla olmamak üzere","5 feet'ten az olmamak ve 25 feet'ten fazla olmamak üzere"],"explanation":"NMSA 1978, Section 66-7-343(A), bu araçların geçide girmeden önce en yakın raya 15 feet'ten az ve 50 feet'ten fazla olmamak üzere durmasını gerektirir. New Mexico CDL Manual (Sec. 2.15) da aynı 15 ila 50 feet kuralını belirtir."},"62":{"q":"New Mexico'nun demiryolu geçidi durma yasası (66-7-343), kapsamdaki bir sürücünün geçitte dururken aracını yeterince düşük bir vitese takmasını şu amaçla gerektirir:","options":["Bir tren yaklaşırsa geri vites seçilebilsin","Geçidi temizlemeden önce vites değiştirmeye gerek kalmasın","Karşı tarafta motor freni devreye sokulabilsin","Araç %5 eğimde yeniden hareket edebilsin"],"explanation":"NMSA 1978, Section 66-7-343(B)(3), geçitten çıkmadan önce vites değiştirmeye gerek kalmayacak kadar düşük bir vites seçilmesini gerektirir ve Subsection (C), geçitteyken vites değiştirmeyi yasaklar. New Mexico CDL Manual şunu tekrarlar: 'Demiryolu raylarını geçerken vites değiştirmeyin.'"},"63":{"q":"Aşağıdakilerden hangisi, bir otobüsü veya plakartlı tehlikeli madde aracını bir demiryolu-karayolu hemzemin geçidinde durmaktan muaf tutan New Mexico'nun listelediği istisnalardan BİRİ DEĞİLDİR?","options":["Yanıp sönen kırmızı ışık ve zilin aktif olduğu bir geçit","Bir polis memurunun trafiği ilerlemeye yönlendirdiği bir geçit","Dur-geç trafik ışığıyla kontrol edilen bir geçit","'Muaf geçit' (exempt crossing) tabelasıyla işaretlenmiş bir geçit"],"explanation":"NMSA 1978, Section 66-7-343(D) istisnaları listeler: trafiği yönlendiren bir memur, bir dur-geç trafik ışığı, bir iş bölgesi içindeki endüstriyel manevra geçidi, terk edildiği bu şekilde tabelalanan bir geçit ve bir 'muaf geçit' (exempt crossing) tabelası. Aktif olarak yanıp sönen kırmızı ışık ve zilli bir geçit bir istisna DEĞİLDİR; araç yine de durmak zorundadır."},"64":{"q":"Daha düşük bir sınırın işaretlenmediği bir karayolundaki herhangi bir araç için New Mexico yasasının belirlediği genel azami hız sınırı nedir?","options":["Saatte 65 mil","Saatte 75 mil","Saatte 80 mil","Saatte 70 mil"],"explanation":"NMSA 1978, Section 66-7-301(A)(3), genel yasal azami sınırı saatte yetmiş beş mil olarak belirler. Bu değer, işaretlenmiş daha düşük bir sınır veya belirlenmiş bir çift ceza bölgesi olmadığında geçerlidir."},"65":{"q":"New Mexico, çekici kamyonlara (büyük kamyonlar) otomobillere kıyasla daha düşük bir yasal azami hız sınırı uygular mı?","options":["Evet - kamyonlar yasayla 60 mph ile sınırlıdır","Hayır - aynı 75 mph yasal azami sınırı kamyonlara ve otomobillere uygulanır","Evet - kamyonlar yasayla geceleri 55 mph ile sınırlıdır","Evet - kamyonlar yasayla 65 mph ile sınırlıdır"],"explanation":"New Mexico, ayrı hız sınırı uygulayan bir eyalet değildir. NMSA 1978, Section 66-7-301'deki 75 mph azami sınırı tüm araçlara uygulanır. 65 mph'lik bir çekici kamyon sınırı öneren bir 2025 tasarısı (SB226) komisyonda kaldı ve hiçbir zaman yasalaşmadı, dolayısıyla kamyona özel bir yasal hız üst sınırı yoktur."},"66":{"q":"New Mexico yasasına göre, çocuklar okula gidip gelirken ve okul bölgesi düzgün şekilde işaretlenmişken bir okulun yanından geçerken azami hız sınırı nedir?","options":["Saatte 25 mil","Saatte 20 mil","Saatte 30 mil","Saatte 15 mil"],"explanation":"NMSA 1978, Section 66-7-301(A)(1), çocuklar okula gidip gelirken ve bölge düzgün şekilde işaretlenmişken bir okulun yanından geçerken tüm karayollarında 15 mph'lik bir sınır belirler."},"67":{"q":"İşaretlenmiş bir sınır olmadığında, New Mexico yasası bir iş veya yerleşim bölgesinde sürüş için hangi hızı belirler?","options":["Saatte 20 mil","Saatte 35 mil","Saatte 30 mil","Saatte 25 mil"],"explanation":"NMSA 1978, Section 66-7-301(A)(2), başka bir sınırın işaretlenmediği bir iş veya yerleşim bölgesinde 30 mph'lik bir sınır belirler."},"68":{"q":"1 Temmuz 2023'ten itibaren geçerli olmak üzere, New Mexico'nun şerit kullanım yasası (66-7-376), çok şeritli bir yolda sol şeridin kullanımını genel olarak hangi duruma sınırlar?","options":["Yalnızca gün doğumu ile gün batımı arasında","Yalnızca plakartlı tehlikeli madde taşırken","Yalnızca başka bir aracı geçerken ve sollarken","Yalnızca 65 mph üzerinde seyrederken"],"explanation":"1 Temmuz 2023'te yürürlüğe giren SB102 (Laws 2023) ile çıkarılan NMSA 1978, Section 66-7-376(A)(4), trafik, akış veya yol yapılandırması (birleşen trafik gibi) sol şeridi gerektirmedikçe, geçme ve sollama hali dışında sol şeritte sürmeyi yasaklar."},"69":{"q":"New Mexico'nun 66-7-376'daki sol şerit kısıtlaması aşağıdaki konumlardan hangisinde GEÇERLİ DEĞİLDİR?","options":["Her yönde üç şeritli herhangi bir eyalet karayolunda","Bir belediyenin şehir sınırları içinde, interstate olmayan bir yolda","Şehirler arası dört şeritli bölünmüş bir U.S. karayolunda","Interstate 40'ın kırsal bir kesiminde"],"explanation":"NMSA 1978, Section 66-7-376(A)(4), sol şerit yasağının, yol ulusal interstate ve savunma karayolları sisteminin parçası olmadığı sürece, bir belediyenin şehir sınırları içinde veya bir county yolunda geçerli olmadığını açıkça belirtir."},"70":{"q":"New Mexico'nun şerit kullanım yasasına göre, şerit değiştiren bir sürücü, şerit değiştirme niyetini araç tarafından kat edilen son kaç feet boyunca işaret etmek zorundadır?","options":["100 feet","150 feet","200 feet","50 feet"],"explanation":"NMSA 1978, Section 66-7-376(A)(2), bir şeritten ayrılmadan önce sürücünün, araç tarafından kat edilen son yüz feet'ten az olmamak üzere şerit değiştirme niyetini işaret etmesini gerektirir."},"71":{"q":"New Mexico, iki yönlü sol dönüş şeridini paralel çift sarı çizgilerle (iç tarafı kesik, dış tarafı düz) işaretler. Sol dönüşe hazırlanan veya sol dönüş yapan bir araç, bu şeritte ne kadar mesafeden fazla sürülemez?","options":["300 feet","500 feet","200 feet","100 feet"],"explanation":"NMSA 1978, Section 66-7-376(B), yoldan sola dönen araçların, dönüşe hazırlanırken ve dönüşü yaparken iki yönlü sol dönüş şeridinde iki yüz feet'ten fazla sürülemeyeceğini öngörür."},"72":{"q":"New Mexico'nun Move Over (Yer Aç) yasasına göre, yetkili bir acil durum aracı yanıp sönen ışıklar veya sirenle yaklaştığında, diğer her aracın sürücüsü şunu yapmak zorundadır:","options":["Bir şerit sola geçip hızı korumak","20 mph'ye yavaşlayıp mevcut şeritte kalmak","Konumdan bağımsız olarak mevcut şeritte hemen durmak","Mümkün olduğunca sağ kenara veya bordüre yanaşıp araç geçene kadar durmak"],"explanation":"NMSA 1978, Section 66-7-332(A), yetkili bir acil durum aracının hemen yaklaşması durumunda sürücülerin yol vermesini ve bir memur tarafından aksi yönlendirilmedikçe hemen yola paralel ve sağ kenara veya bordüre mümkün olduğunca yakın, herhangi bir kavşaktan uzakta sürmesini ve araç geçene kadar durmasını gerektirir."},"73":{"q":"New Mexico'nun Move Over (Yer Aç) yasası, yanıp sönen acil durum veya tehlike ışıkları gösteren sabit bir araca uygulanır. Yetkili acil durum araçlarının yanı sıra, özellikle hangi araçlar kapsama dahildir?","options":["Otobüs durağındaki okul otobüsleri","Posta dağıtım araçları","Banketteki tarım ekipmanları","Kurtarma veya onarım (çekici/vinç) araçları"],"explanation":"NMSA 1978, Section 66-7-332(B), sabit araç için 'yer aç ve yavaşla' yükümlülüğünü, yanıp sönen acil durum veya tehlike ışıkları gösteren sabit bir yetkili acil durum aracını veya bir kurtarma ya da onarım aracını kapsayacak şekilde genişletir."},"74":{"q":"New Mexico'nun Move Over (Yer Aç) yasasına göre, bir sürücü sabit bir acil durum veya kurtarma aracına yaklaştığında ancak bitişik şeritten çıkmak makul ölçüde güvenli DEĞİLSE, sürücü şunu yapmak zorundadır:","options":["Seyir şeridinde tamamen durmak","Koşullar altında makul ve ihtiyatlı bir hıza yavaşlamak, dikkatle ilerlemek ve durmaya hazır olmak","Bölgeyi hızlıca temizlemek için olay yerini hızlanarak geçmek","Bölge boyunca işaretlenmiş hız sınırında devam etmek"],"explanation":"NMSA 1978, Section 66-7-332(B)(2), sabit aracın bitişiğinde olmayan bir şeritte sürmek makul ölçüde güvenli değilse, sürücünün hızını koşullar altında makul ve ihtiyatlı bir hıza düşürmesini, dikkatle ilerlemesini ve durmaya hazır olmasını öngörür."},"75":{"q":"Bir New Mexico ticari aracı tek yönlü veya bölünmüş bir karayolunda durmak zorunda kalırsa, CDL Manual üç uyarı cihazının (reflektörlü üçgenler) nereye yerleştirilmesini gerektirir?","options":["Yalnızca aracın tam arkasına 100 feet'te","Yaklaşan trafiğe doğru 10 feet, 50 feet ve 150 feet'te","Yalnızca 100 feet ön ve 100 feet arka","Yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet'te"],"explanation":"New Mexico CDL Manual (Sec. 2.5), federal CMV standardını (49 CFR 392.22) takip eder: tek yönlü veya bölünmüş bir karayolunda, uyarı cihazlarını durduktan sonra 10 dakika içinde yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet'e yerleştirin."},"76":{"q":"New Mexico'da iki şeritli, iki yönlü (bölünmemiş) bir yolda, CDL Manual durmuş bir ticari aracın uyarı üçgenlerinin nereye yerleştirilmesini gerektirir?","options":["Aracın 10 feet içinde ve aracın 100 feet arkasında ve 100 feet önünde","Yalnızca aracın 10, 100 ve 200 feet arkasında","Yalnızca 50 feet arkada ve 50 feet önde","Yalnızca 200 feet arkada ve 200 feet önde"],"explanation":"New Mexico CDL Manual (Sec. 2.5), her iki yönde trafik taşıyan iki şeritli bir yolda veya bölünmemiş bir karayolunda, bir cihazı aracın ön veya arkasının 10 feet içine, birini 100 feet arkasına ve birini 100 feet önüne yerleştirmeyi öğütler."},"77":{"q":"New Mexico'da, bir ticari araç, bir tepe, viraj veya başka bir engelin uyarı üçgenlerinin 500 feet içinde görülmesini engellediği bir yerde durmuşsa, sürücü şunu yapmalıdır:","options":["Üç üçgenin tümünü arka tamponun 50 feet içine yerleştirmek","Tüm üçgenleri standart 10, 100 ve 200 feet'te bırakmak","Üçgenler yerine yalnızca dörtlü flaşörleri kullanmak","En arkadaki üçgeni engelin ötesine, araçtan 500 feet'e kadar geriye taşımak"],"explanation":"New Mexico CDL Manual (Sec. 2.5), bir tepe, viraj veya engelin görüş hattını 500 feet içinde engellemesi durumunda, diğer sürücülerin uyarı alması için en arkadaki üçgenin yol boyunca 500 feet'e kadar geriye taşınmasını yönlendirir. NMSA 1978, Section 66-3-853 de bu tür engellerin yakınında 100 ila 500 feet dışarıya yerleştirme gerektirir."},"78":{"q":"New Mexico yasası 66-3-849, otobüslerin ve büyük kamyonların hangi acil durum uyarı ekipmanı setini TAŞIMASINI gerektirir?","options":["Üç kırmızı acil durum reflektörü (veya işaret fişeği/fusee) artı iki kırmızı bez bayrak","Tek bir kırmızı fener ve bir bayrak","Yalnızca iki amber flaşör ve bir yangın söndürücü","Dört turuncu koni ve bir reflektörlü yelek"],"explanation":"NMSA 1978, Section 66-3-849, kapsamdaki araçların (otobüsler, kamyonlar, çekici kamyonlar vb.) üç kırmızı acil durum reflektörü, iki kırmızı bez bayrak ve üç fusee (veya eşdeğeri işaret fişeği/fener) gibi uyarı cihazları taşımasını gerektirir. New Mexico CDL Manual da gerekli park halindeki araç uyarı cihazları olarak üç reflektörlü üçgen, altı fusee veya üç sıvı yanan işaret fişeğini sıralar."},"79":{"q":"New Mexico'da Ticari Sürücü Belgelerini (CDL) hangi eyalet kurumu düzenler?","options":["Motor Vehicle Division (MVD)","New Mexico Department of Transportation (NMDOT)","Eyalet Polisi'nin Ticari Araç Bürosu","Public Regulation Commission (PRC)"],"explanation":"New Mexico'da CDL'ler, Taxation and Revenue Department'ın bir parçası olan Motor Vehicle Division (MVD) tarafından düzenlenir. NMDOT, sürücü belgelendirmesi değil, yolları ve aşırı boyut/aşırı ağırlık izinlerini ele alır. Kaynak: MVD New Mexico, Commercial Driver's Licenses (CDL) sayfası ve Chapter 5: Commercial Driver License."},"80":{"q":"Bir New Mexico CDL'sine başvururken, başvuranlar kaç sürücü kategorisinden birine kendi beyanlarıyla girmek zorundadır?","options":["Dört kategori","İki kategori","Üç kategori","Altı kategori"],"explanation":"New Mexico CDL başvuranları, faaliyet göstermeyi bekledikleri ticaret türünü tanımlayan dört kategoriden birine kendi beyanlarıyla girmek zorundadır: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) ve Excepted Intrastate (EA). Kaynak: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.71."},"81":{"q":"Eyalet sınırları ötesinde faaliyet gösteren ve federal fiziksel-yeterlilik kurallarından muaf OLMAYAN bir New Mexico CDL sürücüsü, hangi kategoride kendi beyanını yapmak zorundadır?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Eyaletler arası ticarette faaliyet gösteren ve federal DOT tıbbi standartlarını karşılaması gereken bir sürücü, Non-Excepted Interstate (NI) olarak kendi beyanını yapar ve MVD'de kayıtlı güncel bir Medical Examiner's Certificate bulundurmak zorundadır. Kaynak: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.71."},"82":{"q":"Bir New Mexico CDL Medical Examiner's Certificate için fiziksel muayeneyi yapmaya kim yetkilidir?","options":["National Registry of Certified Medical Examiners'da listelenmiş bir tıp uzmanı","New Mexico'da lisanslı herhangi bir hekim","Herhangi bir acil bakım kliniğindeki bir hemşire pratisyen","MVD saha ofisi tıbbi görevlisi"],"explanation":"New Mexico'daki tüm Ticari Sürücü Tıbbi Belgelendirmeleri, FMCSA National Registry of Certified Medical Examiners'da listelenmiş bir tıp uzmanı tarafından tamamlanmak zorundadır. Tek başına genel bir tıp lisansı yeterli değildir. Kaynak: MVD New Mexico, Commercial Driver's Licenses (CDL) sayfası; FMCSA National Registry."},"83":{"q":"Bir New Mexico CDL sahibi, DOT Medical Examiner's Certificate'ini eyalette nasıl kayda geçirir?","options":["Belgenin bir kopyasını MVD'ye sunarak; MVD tıbbi durumu sürüş kaydına işler","Doğrudan Washington, D.C.'deki FMCSA'ya posta ile göndererek","Yalnızca orijinal kartı araçta tutarak; MVD'ye kopya verilmez","New Mexico Department of Health'e dosyalayarak"],"explanation":"New Mexico CDL sahipleri, MVD'ye (Eyalet Sürücü Belgelendirme Kurumu) Medical Examiner's Certificate'lerinin bir kopyasını sağlamak zorundadır; MVD ardından tıbbi belgelendirme durumunu ticari sürüş kaydına (CDLIS) işler. Yalnızca araçta taşınan kart, eyalet dosyalama gerekliliğini karşılamaz. Kaynak: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.71(h)."},"84":{"q":"CDL için test girmeden önce, ilk kez başvuran bir New Mexico başvuranı genel olarak hangi federal olarak zorunlu eğitimi tamamlamak zorundadır?","options":["FMCSA Training Provider Registry'deki bir sağlayıcıdan Entry-Level Driver Training (ELDT)","40 saatlik bir OSHA ticari araç güvenliği kursu","Bir New Mexico defansif sürüş sınıf kursu","Lisanslı bir taşıyıcıyla en az 90 günlük bir çıraklık"],"explanation":"İlk kez CDL başvuranları (ve belirli sınıf yükseltmeleri/onayları), beceri veya bilgi testine girmeden önce FMCSA Training Provider Registry'de listelenmiş bir sağlayıcı aracılığıyla Entry-Level Driver Training (ELDT) tamamlamak zorundadır. Kural, 7 Şubat 2022 tarihinde veya sonrasında başvuranlara uygulanır. Kaynak: MVD New Mexico Chapter 5; FMCSA ELDT kuralı, 49 CFR Part 380."},"85":{"q":"Bir New Mexico Commercial Learner's Permit (CLP) ilk düzenlenmesinden sonra, sahibinin CDL beceri testine girmeye uygun olabilmesi için ne kadar beklemesi gerekir?","options":["En az 14 gün","En az 30 gün","En az 10 gün","En az 60 gün"],"explanation":"Bir CLP sahibi, CLP'nin ilk düzenlenmesinden en az 14 gün sonrasına kadar CDL beceri testine girmeye uygun değildir. Bu federal asgari süre New Mexico MVD tarafından uygulanır. Kaynak: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.25(a)(3)."},"86":{"q":"Bir New Mexico Commercial Learner's Permit (CLP) ne kadar süreyle geçerlidir?","options":["1 yıl (yeniden test olmadan bir kez yenilemeye izin verilir)","90 gün","6 ay","2 yıl"],"explanation":"New Mexico CLP, 1 yıl için düzenlenir. Federal standart kapsamında, bu süre içinde genel bilgi testini yeniden almadan bir kez yenilenebilir. Kaynak: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.25(c)."},"87":{"q":"New Mexico CDL beceri testi kaç bölümden oluşur ve bunlar nelerdir?","options":["Üç bölüm: sefer öncesi araç muayenesi, temel araç kontrolü ve yolda sürüş","İki bölüm: bir yazılı sınav ve yolda bir sürüş","Üç bölüm: hava freni testi, geri manevra testi ve gece sürüşü","Dört bölüm: muayene, geri manevra, otoyol ve paralel park"],"explanation":"CDL beceri testi, sırayla geçilmesi gereken üç bölümden oluşur: sefer öncesi araç muayenesi, temel araç kontrolü (düşük hızlı manevralar) ve yolda sürüş testi. Kaynak: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.113."},"88":{"q":"New Mexico CDL bilgi (yazılı) testlerinde asgari geçme puanı nedir?","options":["Yüzde 80","Yüzde 70","Yüzde 75","Yüzde 90"],"explanation":"New Mexico CDL bilgi testleri, federal standartla uyumlu olarak en az yüzde 80 puanla geçilmek zorundadır. Kaynak: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.135."},"89":{"q":"Bir kişi, bir New Mexico CDL'sine başvurmadan önce hangi ön koşula zaten sahip olmak zorundadır?","options":["Geçerli bir New Mexico Class D (normal) sürücü belgesi veya geçerli bir eyalet dışı CDL","Herhangi bir eyalette alınmış bir yolcu (P) onayı","TSA'dan federal bir hazmat izni","Bir New Mexico belgesinde motosiklet onayı"],"explanation":"Bir New Mexico CDL'sine başvurmak için, zaten geçerli bir ticari olmayan (Class D) New Mexico sürücü belgesine veya geçerli bir eyalet dışı CDL'ye sahip olmak zorundasınız. Kaynak: MVD New Mexico, bir New Mexico CDL almak için gereklilikler."},"90":{"q":"New Mexico MVD kurallarına göre, bir CDL başvuranı New Mexico'da kaç adet fiziksel ikamet kanıtı sunmak zorundadır?","options":["İki fiziksel ikamet kanıtı","Bir fiziksel ikamet kanıtı","Üç fiziksel ikamet kanıtı","İkamet kanıtı gerekmez"],"explanation":"Bir New Mexico CDL başvuranı, eyalette iki fiziksel ikamet kanıtı sunmak zorundadır. Kanıt olarak kullanılan fatura veya banka ekstreleri gibi aylık belgelerin başvuru tarihinden itibaren 60 gün içinde tarihlenmiş olması gerekir. Kaynak: MVD New Mexico, Commercial Driver's Licenses (CDL) sayfası."},"91":{"q":"New Mexico bir CDL için hangi yenileme döngüsü seçeneklerini sunar?","options":["4 yıllık veya 8 yıllık bir belge","1 yıllık veya 5 yıllık bir belge","Yalnızca 5 yıllık bir belge","2 yıllık veya 6 yıllık bir belge"],"explanation":"New Mexico, CDL'leri 4 yıllık veya 8 yıllık bir yenileme döngüsüyle sunar. Kaynak: MVD New Mexico FAQ ve Chapter 5."},"92":{"q":"Bir New Mexico CDL sahibi neden 8 yıllık yerine 4 yıllık belgeyle sınırlı olabilir?","options":["Hazardous Materials (Hazmat) onayına sahip oldukları için","Bir yolcu (P) onayına sahip oldukları için","Yalnızca eyalet içi sürüş yaptıkları için","30 yaşın altında oldukları için"],"explanation":"Hazardous Materials (Hazmat) onayına sahip sürücüler 8 yıllık CDL'yi alamaz; Hazmat'a bağlı periyodik TSA güvenlik soruşturması onları 4 yıllık döngüyle sınırlar. Kaynak: MVD New Mexico FAQ; TSA/FMCSA Hazmat onay kuralları."},"93":{"q":"New Mexico CDL bilgi testleri, yeniden alımlar açısından nasıl planlanır?","options":["Başvuranlar CDL yazılı testlerini haftada en fazla iki kez alabilir","Başvuranlar yazılı testleri yalnızca her 30 günde bir alabilir","Başvuranlar sınırsız aynı gün yeniden alım hakkına sahiptir","Başvuranlar yazılı testleri yalnızca takvim yılında bir kez alabilir"],"explanation":"New Mexico, CDL başvuranlarının CDL yazılı (bilgi) testlerini haftada en fazla iki kez almasına izin verir. Kaynak: MVD New Mexico, Commercial Driver's Licenses (CDL) sayfası."},"94":{"q":"Yalnızca eyalet içi (in-state) sürüşle sınırlı bir New Mexico CDL almak için asgari yaş nedir?","options":["18 yaşında","16 yaşında","21 yaşında","19 yaşında"],"explanation":"Bir kişi 18 yaşında eyalet içi sürüş için bir New Mexico CDL alabilir; 18-20 yaş arası bir başvuran eyalet içi faaliyetle sınırlıdır. Eyaletler arası ticarette faaliyet göstermek 21 yaş gerektirir. Kaynak: MVD New Mexico Chapter 5; FMCSA 49 CFR 391.11."},"95":{"q":"Bir sürücü, geçerli bir eyalet dışı CDL'yi aynı sınıf ve onaylara sahip bir New Mexico CDL ile değiştirdiğinde, genel olarak hangi test gerekir?","options":["Eşdeğer sınıf ve onaylar için yazılı test gerekmez","Hem yazılı hem de beceri testleri yeniden alınmalıdır","Yalnızca yolda beceri testi yeniden alınmalıdır","Yalnızca sefer öncesi muayene tekrarlanmalıdır"],"explanation":"New Mexico, geçerli bir eyalet dışı CDL'yi aynı sınıf ve onaylara sahip bir New Mexico CDL ile değiştirmek için yazılı test gerektirmez. (Hazmat onayı yine de kendi testini ve TSA güvenlik soruşturmasını gerektirir.) Kaynak: MVD New Mexico, bir New Mexico CDL almak için gereklilikler."},"96":{"q":"Bir yazılı bilgi testine ek olarak, Hazardous Materials (Hazmat) onayı isteyen bir New Mexico CDL başvuranı başka ne tamamlamak zorundadır?","options":["Parmak izi alımı ve bir TSA güvenlik tehdidi değerlendirmesi (güvenlik soruşturması)","Ayrı bir yolda gece sürüş testi","10 günlük bir defansif sürüş kursu","Eyalet işletmeli bir klinikte göz muayenesi"],"explanation":"Hazmat onayı isteyen bir New Mexico sürücüsü, onay verilmeden önce Hazmat bilgi testini geçmek ve bir TSA güvenlik tehdidi değerlendirmesi (güvenlik soruşturması) için parmak izi vermek zorundadır. Kaynak: MVD New Mexico, bir New Mexico CDL almak için gereklilikler; TSA Hazmat Endorsement Threat Assessment Program."},"97":{"q":"Bir New Mexico CDL başvuranı, beceri testini geçtikten sonra CDL'yi almak için MVD'ye geri döndüğünde, test sonuçları tipik olarak hangi biçimde sağlanır?","options":["Beceri testi puanlarını içeren, CLP ve gerekli belgelerle birlikte sunulan kapalı bir zarf","Sınav görevlisinden doğrudan FMCSA'ya gönderilen bir e-posta","Yalnızca sınav görevlisinin amirine verilen sözlü bir rapor","Yol testi aracının tescil belgesinin arkasına basılan bir puan"],"explanation":"Onaylı bir CDL sınav görevlisi tarafından uygulanan beceri testini geçtikten sonra, başvuran CDL'nin düzenlenmesi için sürücü belgesi, CLP ve beceri testi puanlarını içeren kapalı bir zarfla MVD'ye geri döner. Kaynak: MVD New Mexico, bir New Mexico CDL almak için gereklilikler."}},"es":{"0":{"q":"En las carreteras de Nuevo México, ¿cuál es el ancho máximo legal de un vehículo comercial o su carga (sin contar los espejos ni ciertos dispositivos de seguridad) sin un permiso de sobredimensión?","options":["8 pies 6 pulgadas (102 inches)","8 pies (96 inches)","9 pies (108 inches)","10 pies (120 inches)"],"explanation":"Nuevo México limita el ancho exterior total de un vehículo o su carga a 8 pies 6 pulgadas (102 inches), sin contar los espejos ni los dispositivos de seguridad aprobados. Una carga más ancha requiere un permiso de sobredimensión. Fuente: NMSA 1978, Section 66-7-402 (Width of vehicles); NM CDL Manual."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo y su carga en las carreteras de Nuevo México sin un permiso?","options":["14 pies","13 pies 6 pulgadas","15 pies","13 pies"],"explanation":"Nuevo México establece la altura máxima del vehículo y su carga en 14 pies. Las cargas que superen los 14 pies requieren un permiso de sobredimensión (por exceso de altura). Fuente: NMSA 1978, Section 66-7-404 (Height and length of vehicles and loads)."},"2":{"q":"¿Cuál es el peso bruto máximo sobre cualquier eje sencillo de un vehículo comercial según el estatuto de Nuevo México?","options":["21,600 pounds","20,000 pounds","22,400 pounds","18,000 pounds"],"explanation":"El límite de eje sencillo de Nuevo México es de 21,600 pounds, que es mayor que el límite federal interestatal de eje sencillo de 20,000 pounds. Fuente: NMSA 1978, Section 66-7-409 (Load limits on single axles, wheels and tires)."},"3":{"q":"Según la ley de Nuevo México, ¿cuál es el peso máximo permitido sobre un conjunto de ejes en tándem (dos ejes separados 4 pies entre sí)?","options":["34,320 pounds","34,000 pounds","36,000 pounds","32,000 pounds"],"explanation":"La tabla de pesos por grupo de ejes de Nuevo México permite 34,320 pounds sobre un tándem (dos ejes separados unos 4 pies entre sí), ligeramente por encima del límite federal interestatal de tándem de 34,000 pounds. Fuente: NMSA 1978, Section 66-7-410 (Gross weight of vehicles and loads)."},"4":{"q":"¿Cuál es la longitud total máxima de una combinación de camión y remolque en las carreteras de Nuevo México sin un permiso?","options":["65 pies","60 pies","70 pies","75 pies"],"explanation":"Nuevo México limita la combinación total (camión más remolque) a 65 pies en las carreteras en general; las combinaciones más largas necesitan un permiso de sobredimensión. Fuente: NMSA 1978, Section 66-7-404 (Height and length of vehicles and loads)."},"5":{"q":"En el sistema de carreteras interestatales (de ayuda federal) de Nuevo México, ¿cuál es el peso bruto vehicular máximo permitido sin un permiso de sobrepeso?","options":["80,000 pounds","86,400 pounds","84,000 pounds","90,000 pounds"],"explanation":"En el sistema interestatal, Nuevo México aplica el tope federal de 80,000 pounds de peso bruto. La propia tabla estatutaria del estado permite algo más en ciertas carreteras estatales no interestatales, pero 80,000 pounds es el máximo interestatal sin un permiso. Fuente: 23 U.S.C. 127 según se aplica en Nuevo México; NMSA 1978, Section 66-7-410."},"6":{"q":"Según la tabla estatutaria de peso bruto de Nuevo México, ¿cuál es el peso bruto máximo permitido (con suficiente separación entre ejes de unos 56 pies o más) en una carretera estatal no interestatal sin un permiso especial?","options":["86,400 pounds","80,000 pounds","94,000 pounds","84,000 pounds"],"explanation":"La tabla de peso bruto de Nuevo México llega como máximo a 86,400 pounds cuando la distancia entre el primer y el último eje es de aproximadamente 56 pies o más en carreteras estatales no interestatales. El sistema interestatal permanece limitado al tope federal de 80,000 pounds. Fuente: NMSA 1978, Section 66-7-410 (Gross weight of vehicles and loads)."},"7":{"q":"¿Cuál es la longitud máxima de un semirremolque que opera en las carreteras designadas de Nuevo México (la National Network) sin un permiso?","options":["57 pies 6 pulgadas","53 pies","48 pies","60 pies"],"explanation":"Nuevo México permite un semirremolque de hasta 57 pies 6 pulgadas en las rutas designadas de la National Network. Fuente: NMSA 1978, Section 66-7-404 (Height and length of vehicles and loads); NM CDL Manual."},"8":{"q":"En Nuevo México, ¿qué fórmula se utiliza en el sistema interestatal para determinar el peso bruto máximo permitido sobre un grupo de ejes consecutivos?","options":["The Federal Bridge Formula","La regla de tonelaje neto","El cociente de separación de ejes","La razón de combinación bruta"],"explanation":"En el sistema interestatal, Nuevo México aplica la Federal Bridge Formula, W = 500[(LN/(N-1)) + 12N + 36], que limita el peso sobre cualquier grupo de ejes en función de la separación (L) y el número (N) de ejes. Fuente: 23 U.S.C. 127 / FBF según se aplica en Nuevo México; NM CDL Manual."},"9":{"q":"¿Quién emite los permisos de sobredimensión/sobrepeso para los vehículos comerciales que operan en las carreteras estatales de Nuevo México?","options":["El New Mexico Department of Transportation (NMDOT)","La oficina del alguacil del condado","La Federal Motor Carrier Safety Administration","El departamento de obras públicas de la ciudad local"],"explanation":"Los permisos de sobredimensión y sobrepeso en Nuevo México son emitidos por el New Mexico Department of Transportation (NMDOT), administrados a través de su unidad de Ports of Entry / permisos y su sistema de permisos en línea. Fuente: NMDOT Permits / Ports of Entry; NMSA 1978, Section 66-7-413."},"10":{"q":"Un transportista necesita mover una sola carga indivisible que excede los límites legales de peso de Nuevo México. ¿Qué debe obtener el transportista antes del viaje?","options":["Un permiso de sobrepeso (especial) del NMDOT","Un nuevo endoso de CDL","Una exención interestatal federal de la FMCSA","Solo un comprobante de seguro de carga"],"explanation":"Mover una carga que supere los límites legales de dimensión o peso de Nuevo México requiere un permiso especial (de sobredimensión/sobrepeso) del NMDOT, generalmente para cargas no divisibles. Fuente: NMSA 1978, Section 66-7-413; NMDOT Permits."},"11":{"q":"Según las reglas de eje sencillo de Nuevo México, ¿cuál es el peso máximo permitido sobre cualquier rueda individual?","options":["11,000 pounds","10,000 pounds","12,500 pounds","9,000 pounds"],"explanation":"Nuevo México limita la carga sobre cualquier rueda individual a 11,000 pounds, como parte de sus reglas de carga de eje sencillo, rueda y neumático. Fuente: NMSA 1978, Section 66-7-409 (Load limits on single axles, wheels and tires)."},"12":{"q":"La regla de carga por neumático de Nuevo México limita el peso a cuánto por pulgada de ancho del neumático?","options":["600 pounds por pulgada de ancho del neumático","500 pounds por pulgada de ancho del neumático","800 pounds por pulgada de ancho del neumático","1,000 pounds por pulgada de ancho del neumático"],"explanation":"Nuevo México limita la carga del neumático a 600 pounds por pulgada de ancho del neumático como parte de sus límites de carga por eje, rueda y neumático. Fuente: NMSA 1978, Section 66-7-409 (Load limits on single axles, wheels and tires)."},"13":{"q":"Un permiso de sobredimensión/sobrepeso en Nuevo México se emite más comúnmente, ¿por cuáles duraciones?","options":["Por un solo viaje o por un período anual","Solo por un solo viaje, nunca más largo","Por un máximo de 30 días únicamente","De forma permanente, sin vencimiento"],"explanation":"Los permisos de sobredimensión/sobrepeso de Nuevo México se emiten normalmente ya sea como permisos de un solo viaje o como permisos anuales, según el traslado. Fuente: NMDOT Permits / Ports of Entry; NMSA 1978, Section 66-7-413."},"14":{"q":"Según la Federal Bridge Formula tal como se aplica en las interestatales de Nuevo México, ¿qué representan las variables L y N?","options":["L = distancia en pies entre los ejes exteriores de un grupo; N = número de ejes del grupo","L = carga en libras; N = número de neumáticos","L = longitud del remolque; N = peso neto en toneladas","L = límite legal; N = número de permisos en posesión"],"explanation":"En la Federal Bridge Formula, L es la distancia en pies entre los extremos (el primer y el último eje) de cualquier grupo de dos o más ejes consecutivos, y N es el número de ejes de ese grupo. Fuente: 23 U.S.C. 127 / FBF según se aplica en Nuevo México; NM CDL Manual."},"15":{"q":"La carga de un semirremolque mide 8 pies 8 pulgadas de ancho. ¿Qué se requiere para moverla legalmente en las carreteras de Nuevo México?","options":["Un permiso de sobredimensión (por exceso de ancho) del NMDOT","Nada; está dentro del ancho legal","Solo una bandera de carga ancha, sin permiso","Un cambio a un CDL Clase A"],"explanation":"El límite legal de ancho de Nuevo México es de 8 pies 6 pulgadas; con 8 pies 8 pulgadas la carga lo excede, por lo que se requiere un permiso de sobredimensión por exceso de ancho del NMDOT. Fuente: NMSA 1978, Section 66-7-402; NMDOT Permits."},"16":{"q":"Cuando se superan los umbrales de ancho o longitud, Nuevo México puede exigir vehículos de escolta (piloto). ¿Por encima de qué ancho exige Nuevo México generalmente escoltas para una carga en movimiento?","options":["Más de 14 pies de ancho","Más de 10 pies de ancho","Más de 8 pies 6 pulgadas de ancho","Más de 20 pies de ancho"],"explanation":"Nuevo México generalmente exige vehículos de escolta/piloto para cargas que superen los 14 pies de ancho (y para cargas que superen unos 90 pies de longitud). Fuente: requisitos de traslado de permisos de sobredimensión del NMDOT."},"17":{"q":"¿Cómo solicita más comúnmente un transportista un permiso de sobredimensión/sobrepeso en Nuevo México hoy en día?","options":["A través del sistema de permisos en línea del NMDOT","Enviando por correo un formulario en papel a la oficina del Gobernador","Llamando a la FMCSA en Washington, D.C.","Solo en persona en un juzgado del condado"],"explanation":"Los permisos de sobredimensión/sobrepeso de Nuevo México se obtienen principalmente a través del sistema de permisos en línea del NMDOT, donde los transportistas ingresan las dimensiones de la carga, el peso, la ruta y las fechas de viaje. Fuente: NMDOT Permits / Ports of Entry."},"18":{"q":"Las cifras de peso bruto de Nuevo México difieren del estándar federal interestatal. En comparación con el límite federal interestatal de eje sencillo de 20,000 pounds, el límite estatutario de eje sencillo de Nuevo México es:","options":["Mayor, en 21,600 pounds","Menor, en 18,000 pounds","Idéntico, en 20,000 pounds","Mayor, en 25,000 pounds"],"explanation":"El límite estatutario de eje sencillo de Nuevo México es de 21,600 pounds, mayor que el límite federal interestatal de eje sencillo de 20,000 pounds. La cifra federal más baja sigue rigiendo en el propio sistema interestatal. Fuente: NMSA 1978, Section 66-7-409; 23 U.S.C. 127."},"19":{"q":"En Nuevo México, se requiere un CDL Clase A para operar cualquier combinación de vehículos con una Clasificación de Peso Bruto Combinado (GCWR) de al menos qué valor, cuando la(s) unidad(es) remolcada(s) superan los 10,000 lbs GVWR?","options":["26,001 o más libras","10,001 o más libras","18,001 o más libras","33,001 o más libras"],"explanation":"Un CDL Clase A de Nuevo México autoriza conducir cualquier combinación de vehículos con un GCWR de 26,001 o más libras, siempre que el GVWR de la(s) unidad(es) remolcada(s) supere los 10,000 libras. Fuente: NM MVD Driver Manual Chapter 5 (Commercial Driver License)."},"20":{"q":"¿Qué clase de CDL de Nuevo México autoriza conducir un solo vehículo con un GVWR de 26,001 o más libras, o tal vehículo remolcando una unidad que no supere los 10,000 lbs GVWR?","options":["Clase B","Clase A","Clase C","Clase D"],"explanation":"Un CDL Clase B de Nuevo México cubre cualquier vehículo individual con un GVWR de 26,001 o más libras, o tal vehículo remolcando una unidad que no exceda los 10,000 libras GVWR. Una combinación de más de 26,001 GCWR que remolque más de 10,000 lbs requiere Clase A. Fuente: NM MVD Driver Manual Chapter 5."},"21":{"q":"Un CDL Clase C de Nuevo México aplica a un vehículo de menos de 26,001 lbs GVWR únicamente cuando se utiliza para cuál propósito?","options":["Transportar 16 o más pasajeros (incluido el conductor) o materiales peligrosos con placas (placarded)","Remolcar cualquier remolque de más de 5,000 lbs","Transportar 9 o más pasajeros a cambio de pago","Operar a través de las fronteras estatales con cualquier carga"],"explanation":"Un CDL Clase C de Nuevo México aplica a un vehículo individual de menos de 26,001 lbs GVWR (o que remolque una unidad de no más de 10,000 lbs) únicamente cuando está diseñado para transportar 16 o más pasajeros incluido el conductor, o cuando lleva placas (placarded) por materiales peligrosos. Fuente: NM MVD Driver Manual Chapter 5."},"22":{"q":"Según las reglas federales adoptadas por Nuevo México, el titular de un Permiso de Aprendiz Comercial (CLP) NO puede presentar el examen práctico (skills test) del CDL hasta al menos cuántos días después de que el CLP se emite inicialmente?","options":["14 days","7 days","30 days","10 days"],"explanation":"El titular del CLP no es elegible para presentar el examen práctico del CDL durante los primeros 14 days después de la emisión inicial del CLP. Nuevo México aplica esta espera federal de 14 días. Fuente: NM MVD Driver Manual Chapter 5; 49 CFR 383.25."},"23":{"q":"¿Cuál es la edad mínima para que se emita un CDL de Nuevo México restringido únicamente al comercio intraestatal (dentro de Nuevo México)?","options":["18 años","21 años","16 años","19 años"],"explanation":"Un solicitante debe tener al menos 18 años para tener un CDL de Nuevo México limitado al comercio intraestatal. Un conductor que tiene de 18 a 20 años recibe una restricción 'K' que lo limita a conducir únicamente dentro de Nuevo México. Fuente: NM MVD Driver Manual Chapter 5."},"24":{"q":"¿Cuál es la edad mínima para que se emita un CDL de Nuevo México para el comercio interestatal (a través de las fronteras estatales)?","options":["21 años","18 años","23 años","25 años"],"explanation":"Un conductor debe tener al menos 21 años para operar un vehículo motorizado comercial en el comercio interestatal. Los conductores de Nuevo México de entre 18 y 20 años están limitados a la operación intraestatal. Fuente: NM MVD Driver Manual Chapter 5; 49 CFR 391.11."},"25":{"q":"En un CDL de Nuevo México, ¿qué indica la restricción 'K' acerca del conductor?","options":["Limitado únicamente al comercio intraestatal","Restringido a vehículos sin frenos de aire","Restringido a vehículos con transmisión automática","No puede transportar pasajeros"],"explanation":"Nuevo México coloca una restricción 'K' en los CDL emitidos a solicitantes de entre 18 y 20 años, limitando al conductor únicamente al comercio intraestatal (dentro de Nuevo México). Fuente: NM MVD Driver Manual Chapter 5."},"26":{"q":"¿Qué endoso se requiere en un CDL de Nuevo México para operar un vehículo cisterna que transporta materiales líquidos o gaseosos a granel?","options":["N (Tank Vehicle)","T (Doubles/Triples)","H (Hazardous Materials)","P (Passenger)"],"explanation":"El endoso N autoriza la operación de un vehículo cisterna utilizado para transportar materiales líquidos o gaseosos a granel. El endoso N puede agregarse a un CLP tras aprobar el examen de conocimientos requerido. Fuente: NM MVD Driver Manual Chapter 5."},"27":{"q":"¿Qué endoso del CDL de Nuevo México se requiere para jalar dos o tres remolques detrás de una sola unidad motriz?","options":["T (Doubles/Triples)","N (Tank Vehicle)","S (School Bus)","X (Combination)"],"explanation":"El endoso T autoriza jalar remolques dobles o triples y requiere aprobar un examen de conocimientos. Fuente: NM MVD Driver Manual Chapter 5; 49 CFR 383.93."},"28":{"q":"¿Qué endoso necesita el titular de un CDL de Nuevo México para conducir un vehículo comercial diseñado para transportar 16 o más personas, incluido el conductor?","options":["P (Passenger)","S (School Bus)","N (Tank Vehicle)","T (Doubles/Triples)"],"explanation":"El endoso P (Passenger) se requiere para conducir un vehículo diseñado para transportar 16 o más pasajeros incluido el conductor. El examen práctico debe realizarse en un vehículo representativo de esa clase. Fuente: NM MVD Driver Manual Chapter 5; 49 CFR 383.93."},"29":{"q":"Antes de que se emita el endoso H (Hazardous Materials), un solicitante de Nuevo México debe pasar cuál evaluación de seguridad?","options":["Una evaluación de antecedentes/amenazas basada en huellas dactilares de la TSA a través de Universal Enroll","Únicamente una comparación con la lista de los más buscados del FBI","Una verificación de antecedentes penales realizada solo por la policía estatal","Una entrevista con el New Mexico MVD sin huellas dactilares"],"explanation":"El New Mexico MVD no puede emitir el endoso de HazMat (H) hasta que el solicitante complete una verificación de antecedentes basada en huellas dactilares de la TSA (Hazardous Materials Endorsement Threat Assessment) a través del sistema Universal Enroll y la TSA determine que el solicitante no representa una amenaza para la seguridad. Fuente: NM MVD Hazardous Material Endorsement page; 49 CFR 1572."},"30":{"q":"Para un endoso de HazMat (H) por primera vez en Nuevo México, el ELDT requiere que el solicitante complete cuál capacitación antes del examen de conocimientos?","options":["Capacitación teórica de materiales peligrosos con un proveedor del FMCSA Training Provider Registry","Únicamente capacitación práctica en pista","Un curso vial presencial de HazMat de 40 horas","Ninguna capacitación; solo la verificación de antecedentes de la TSA"],"explanation":"Los solicitantes de un endoso H por primera vez deben completar la capacitación teórica de HazMat (no se requiere ningún componente práctico al volante para el H) con un proveedor incluido en el FMCSA Training Provider Registry antes de presentar el examen de conocimientos. Fuente: NM MVD Driver Manual Chapter 5; 49 CFR 380.725."},"31":{"q":"Los requisitos del ELDT aplican a los solicitantes de Nuevo México por primera vez que solicitaron un CLP inicial en o después de cuál fecha?","options":["February 7, 2022","January 1, 2020","September 30, 2021","July 1, 2023"],"explanation":"Todos los solicitantes de un CLP por primera vez en o después del February 7, 2022 deben cumplir con las reglas federales de Entry-Level Driver Training (ELDT) en 49 CFR 380.600-380.603. Fuente: NM MVD Driver Manual Chapter 5."},"32":{"q":"¿Dónde debe obtener un solicitante de ELDT de Nuevo México la capacitación de conductor de nivel inicial requerida para que cuente hacia la elegibilidad del CDL/endoso?","options":["De un proveedor incluido en el FMCSA Training Provider Registry (TPR)","De cualquier escuela de manejo comercial que el solicitante elija","Directamente de la oficina de campo del New Mexico MVD","De un programa interno de un empleador, sin necesidad de registro"],"explanation":"El ELDT debe completarse con un proveedor incluido en el FMCSA Training Provider Registry (TPR) en tpr.fmcsa.dot.gov; el proveedor presenta la certificación a la FMCSA. Fuente: NM MVD Driver Manual Chapter 5; FMCSA TPR."},"33":{"q":"Una autocertificación de Nuevo México de 'Non-Excepted Interstate' (NI) significa que el conductor opera en el comercio interestatal y:","options":["Debe cumplir con los requisitos federales de la tarjeta médica del DOT","No tiene que cumplir con ningún requisito médico","Solo cumple con los requisitos médicos del estado de Nuevo México","Está exento porque conduce un vehículo agrícola"],"explanation":"Seleccionar Non-Excepted Interstate (NI) certifica que el conductor opera en el comercio interestatal y está obligado a cumplir con los requisitos federales del certificado del examinador médico del DOT. Fuente: NM MVD Driver Manual Chapter 5 (Medical Self-Certification)."},"34":{"q":"¿Qué categoría de autocertificación médica de Nuevo México aplica a un conductor que opera únicamente dentro de Nuevo México y NO está obligado a cumplir con los requisitos médicos de Nuevo México?","options":["EA (Excepted Intrastate)","NA (Non-Excepted Intrastate)","NI (Non-Excepted Interstate)","EI (Excepted Interstate)"],"explanation":"Excepted Intrastate (EA) significa que el conductor opera únicamente dentro de Nuevo México y no tiene que cumplir con los requisitos médicos del estado de Nuevo México. NA requeriría cumplir con los requisitos médicos de NM. Fuente: NM MVD Driver Manual Chapter 5."},"35":{"q":"Además de la identidad y la presencia legal, ¿qué conjunto de documentos debe presentar un solicitante de CDL de Nuevo México para comprobar la residencia?","options":["Dos comprobantes de residencia física que muestren una dirección de Nuevo México","Una factura de servicios públicos de más de un año de antigüedad","Un solo contrato de arrendamiento de otro estado","Una tarjeta de registro de votante de cualquier estado"],"explanation":"Nuevo México requiere dos comprobantes de residencia física que muestren una dirección de Nuevo México, junto con un comprobante de identidad, presencia legal/ciudadanía estadounidense y un número de Seguro Social. Fuente: NM MVD Driver Manual Chapter 5; NM CDL Acceptable Documents list."},"36":{"q":"Para documentar un Número de Seguro Social para un CDL de Nuevo México, un solicitante debe presentar cuál de los siguientes?","options":["Una tarjeta de Seguro Social o un comprobante válido del SSN","Únicamente la página de la foto del pasaporte","Dos facturas de servicios públicos","Únicamente un acta de nacimiento"],"explanation":"Nuevo México requiere una tarjeta de Seguro Social u otro comprobante válido del Número de Seguro Social como parte de los documentos de solicitud del CDL (junto con la identidad, la presencia legal y dos comprobantes de residencia). Fuente: NM MVD Driver Manual Chapter 5; NM CDL Acceptable Documents."},"37":{"q":"¿Cuál es la calificación mínima para aprobar cada examen de conocimientos (escrito) del CDL de Nuevo México?","options":["80%","70%","75%","90%"],"explanation":"Un solicitante debe obtener al menos 80% para aprobar cada examen de conocimientos del CDL de Nuevo México. Un solicitante puede presentar un examen de conocimientos hasta dos veces por semana, pero el sistema bloquea un tercer intento tras dos reprobaciones dentro de un período de 7 días. Fuente: NM MVD Driver Manual Chapter 5."},"38":{"q":"¿Qué endoso NO puede agregarse a un Permiso de Aprendiz Comercial (CLP) de Nuevo México para un solicitante por primera vez?","options":["H (Hazardous Materials)","N (Tank Vehicle)","P (Passenger)","S (School Bus)"],"explanation":"El endoso H (HazMat) no puede obtenerse en un CLP; requiere una evaluación de amenazas de la TSA y solo se agrega a un CDL completo. Los endosos N, P y S pueden llevarse en un CLP (con las restricciones aplicables). Fuente: NM MVD Driver Manual Chapter 5; 49 CFR 383.25."},"39":{"q":"En Nuevo México, ¿cuál es la concentración máxima legal de alcohol en la sangre (BAC) para un conductor que opera un vehículo motorizado comercial (CMV)?","options":["0.08%","0.04%","0.02%","0.00%"],"explanation":"Nuevo México sigue el estándar federal para CMV: es ilegal operar un CMV con un BAC de 0.04% o más (la mitad del límite de 0.08% para conductores no comerciales). Fuente: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"40":{"q":"Bajo la regla de consentimiento implícito de Nuevo México, ¿qué le sucede al titular de un CDL que opera un CMV?","options":["Debe portar un permiso de prueba de aliento por separado","Se considera que ha dado su consentimiento para las pruebas de alcohol","Puede rechazar las pruebas sin ninguna penalización","Da su consentimiento solo si primero es arrestado formalmente"],"explanation":"El NM CDL Manual establece que, al operar un CMV, 'se considerará que ha dado su consentimiento para las pruebas de alcohol'. La negativa conlleva la misma descalificación que un delito mayor. Fuente: NM CDL Manual section 1.3.2; NMSA 66-5-68 / Implied Consent Act."},"41":{"q":"En Nuevo México, ¿por cuánto tiempo perderá un conductor su CDL por un PRIMER delito mayor, como una infracción de BAC de 0.04%, en un CMV sin placas (non-placarded)?","options":["60 days","120 days","Al menos 1 año","Al menos 3 años"],"explanation":"Nuevo México impone una descalificación mínima del CDL de un año por un primer delito mayor (p. ej., BAC de 0.04%, DUI, negativa a la prueba, abandonar la escena de un accidente). Fuente: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"42":{"q":"Si el titular de un CDL de Nuevo México comete un primer delito mayor mientras opera un CMV que lleva placas (placarded) por materiales peligrosos, ¿cuánto dura la descalificación?","options":["Al menos 1 año","Al menos 2 años","Al menos 3 años","De por vida"],"explanation":"Nuevo México eleva la descalificación por primer delito a al menos 3 años si el delito mayor ocurre mientras se opera un CMV con placas (placarded) por materiales peligrosos. Fuente: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"43":{"q":"¿Cuál es el período de descalificación del CDL de Nuevo México por un SEGUNDO delito mayor (como un segundo DUI en un CMV)?","options":["3 años","5 años","10 años","De por vida"],"explanation":"Nuevo México descalifica a un conductor de tener un CDL de por vida al cometer un segundo delito mayor. (Una reinstalación después de 10 años puede ser posible por reglamento, pero la descalificación en sí es una prohibición de por vida). Fuente: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"44":{"q":"En Nuevo México, negarse a someterse a la prueba de alcohol en la sangre mientras se opera un CMV se trata como cuál de los siguientes?","options":["Una infracción menor de papeleo","Una infracción de tránsito grave (tipo de 60 días)","Un delito mayor (descalificación de 1 año)","Una infracción de orden de fuera de servicio (out-of-service)"],"explanation":"Nuevo México trata la negativa a someterse a la prueba de alcohol en la sangre como un delito mayor, que conlleva la misma descalificación mínima del CDL de un año que una condena por BAC de 0.04%. Fuente: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"45":{"q":"Un conductor de CMV de Nuevo México registra una cantidad detectable de alcohol que está POR DEBAJO de 0.04%. ¿Cuál es la consecuencia inmediata?","options":["Ninguna consecuencia por debajo de 0.04%","Puesto fuera de servicio (out-of-service) por 24 horas","Descalificación del CDL por 1 año","Descalificación del CDL por 60 días"],"explanation":"Nuevo México pone a un conductor de CMV fuera de servicio (out-of-service) por 24 horas por cualquier cantidad detectable de alcohol por debajo de 0.04%. Una lectura de 0.04% o más es, en cambio, un delito mayor descalificante. Fuente: NM CDL Manual section 1.3.2."},"46":{"q":"¿Cuál de los siguientes se clasifica como una 'infracción de tránsito grave' para el titular de un CDL de Nuevo México?","options":["Conducir 5 mph por encima del límite","Exceso de velocidad de 15 mph o más por encima del límite señalado","Una infracción de estacionamiento en un CMV","Una calcomanía de registro vencida"],"explanation":"Nuevo México incluye el exceso de velocidad (15 mph o más por encima del límite señalado) como una infracción de tránsito grave, junto con la conducción imprudente, los cambios de carril indebidos y seguir demasiado de cerca. Fuente: NM CDL Manual section 1.3.3."},"47":{"q":"¿Cuál de los siguientes NO es una de las infracciones de tránsito graves enumeradas por Nuevo México para los titulares de CDL?","options":["Conducción imprudente","Seguir a un vehículo demasiado de cerca","Cambios de carril indebidos o erráticos","Conducir un CMV con un faro fundido"],"explanation":"La lista de infracciones de tránsito graves de Nuevo México incluye la conducción imprudente, seguir demasiado de cerca y los cambios de carril indebidos/erráticos; un faro fundido es un problema de equipo, no una infracción grave enumerada. Fuente: NM CDL Manual section 1.3.3."},"48":{"q":"En Nuevo México, ¿por cuánto tiempo perderá un conductor su CDL por cometer DOS infracciones de tránsito graves en un CMV dentro de un período de tres años?","options":["Al menos 30 days","Al menos 60 days","Al menos 120 days","Al menos 1 año"],"explanation":"Nuevo México descalifica al titular de un CDL por al menos 60 days por dos infracciones de tránsito graves cometidas en un CMV dentro de un período de tres años. Fuente: NM CDL Manual section 1.3.3; NMSA 66-5-68."},"49":{"q":"En Nuevo México, ¿por cuánto tiempo perderá un conductor su CDL por cometer TRES o más infracciones de tránsito graves en un CMV dentro de un período de tres años?","options":["60 days","90 days","Al menos 120 days","Al menos 1 año"],"explanation":"Nuevo México descalifica al titular de un CDL por al menos 120 days por tres o más infracciones de tránsito graves cometidas en un CMV dentro de un período de tres años. Fuente: NM CDL Manual section 1.3.3; NMSA 66-5-68."},"50":{"q":"Conducir un CMV en Nuevo México sin la clase adecuada de CDL y/o los endosos requeridos se considera qué?","options":["Una infracción de tránsito grave","Un delito mayor (1 año)","Una infracción de fuera de servicio (out-of-service)","Solo una advertencia, no una infracción"],"explanation":"Nuevo México incluye conducir un CMV sin la clase adecuada de CDL y/o endosos (o sin tener un CDL en posesión) como una infracción de tránsito grave. Fuente: NM CDL Manual section 1.3.3."},"51":{"q":"¿Cuál es la descalificación mínima del CDL en Nuevo México por la PRIMERA infracción de un conductor a una orden de fuera de servicio (out-of-service)?","options":["Al menos 30 days","Al menos 60 days","Al menos 90 days","Al menos 1 año"],"explanation":"Nuevo México descalifica al titular de un CDL por al menos 90 days por una primera infracción de orden de fuera de servicio. Fuente: NM CDL Manual section 1.3.4; NMSA 66-5-68."},"52":{"q":"En Nuevo México, ¿cuánto dura la descalificación del CDL por una SEGUNDA infracción de orden de fuera de servicio (out-of-service) dentro de un período de diez años?","options":["Al menos 90 days","Al menos 1 año","Al menos 3 años","Al menos 5 años"],"explanation":"Nuevo México descalifica al titular de un CDL por al menos 1 año por dos infracciones de orden de fuera de servicio dentro de un período de diez años. Fuente: NM CDL Manual section 1.3.4; NMSA 66-5-68."},"53":{"q":"En Nuevo México, ¿cuál es la descalificación mínima del CDL por TRES o más infracciones de orden de fuera de servicio (out-of-service) dentro de un período de diez años?","options":["1 año","Al menos 3 años","5 años","De por vida"],"explanation":"Nuevo México descalifica al titular de un CDL por al menos 3 años por tres o más infracciones de orden de fuera de servicio dentro de un período de diez años. Fuente: NM CDL Manual section 1.3.4; NMSA 66-5-68."},"54":{"q":"En Nuevo México, ¿cuál es la descalificación mínima del CDL por la PRIMERA infracción de un conductor en un cruce a nivel de ferrocarril y carretera?","options":["Al menos 30 days","Al menos 60 days","Al menos 120 days","Al menos 1 año"],"explanation":"Nuevo México descalifica al titular de un CDL por al menos 60 days por una primera infracción en un cruce a nivel de ferrocarril y carretera. Fuente: NM CDL Manual section 1.3.5; NMSA 66-5-68."},"55":{"q":"¿Cuál es la descalificación del CDL de Nuevo México por una TERCERA infracción en un cruce a nivel de ferrocarril y carretera dentro de un período de tres años?","options":["120 days","180 days","Al menos 1 año","3 años"],"explanation":"Nuevo México descalifica al titular de un CDL por al menos 1 año por una tercera infracción en un cruce a nivel de ferrocarril y carretera dentro de un período de tres años (60 days la primera, 120 days la segunda). Fuente: NM CDL Manual section 1.3.5; NMSA 66-5-68."},"56":{"q":"Bajo las reglas de Nuevo México/federales, ¿cuándo queda el CDL de un conductor de CMV sujeto a descalificación por usar un teléfono móvil de mano mientras conduce?","options":["Después de una sola primera condena","Después de dos o más condenas","Solo después de un choque con culpa","El uso de mano nunca es descalificante"],"explanation":"Un CDL de Nuevo México se descalifica después de dos o más condenas por el uso de un teléfono móvil de mano mientras se opera un CMV: 60 days por un segundo delito dentro de 3 años y 120 days por tres o más dentro de 3 años. Fuente: NM CDL Manual section 2.9.4."},"57":{"q":"¿Cuál es la sanción civil máxima que puede enfrentar un conductor de CMV en Nuevo México por violar la prohibición de uso de teléfono móvil de mano / mensajes de texto?","options":["Hasta $750","Hasta $2,750","Hasta $5,000","Hasta $11,000"],"explanation":"Bajo la restricción federal aplicada en Nuevo México, un conductor que viola la prohibición de teléfono de mano/mensajes de texto está sujeto a una sanción civil de hasta $2,750; un empleador que lo permita o lo exija enfrenta hasta $11,000. Fuente: NM CDL Manual section 2.9.4."},"58":{"q":"En Nuevo México, un tribunal puede multar a una persona hasta qué cantidad por conducir un vehículo motorizado comercial sin un CDL o por tener más de una licencia?","options":["Hasta $1,000","Hasta $2,750","Hasta $5,000","Hasta $11,000"],"explanation":"Nuevo México dispone que un tribunal puede multar a un conductor hasta $5,000 (o imponer cárcel) por conducir un CMV sin un CDL o por tener más de una licencia. Fuente: NM CDL Manual sections 1.3.7 and 1.4."},"59":{"q":"Según la ley de Nuevo México, cuando un autobús escolar está detenido en la vía con sus señales especiales de autobús escolar funcionando para subir o bajar niños, ¿a qué distancia antes del autobús debe detenerse un conductor que se aproxima?","options":["Al menos 10 feet antes de llegar al autobús","Al menos 25 feet antes de llegar al autobús","Al menos 20 feet antes de llegar al autobús","Al menos 15 feet antes de llegar al autobús"],"explanation":"NMSA 1978, Section 66-7-347(A) exige que un conductor que se aproxime o que vaya a rebasar un autobús escolar detenido con las señales en funcionamiento detenga el vehículo al menos diez feet antes de llegar al autobús y no avance hasta que las señales se apaguen, el autobús se mueva o el conductor del autobús le indique que puede avanzar."},"60":{"q":"En Nuevo México, ¿cuál es la condición exacta que permite a un conductor continuar más allá de un autobús escolar detenido que está subiendo niños SIN detenerse?","options":["Hay dos o más carriles en la dirección del conductor","El autobús está a más de 100 feet de distancia cuando se ve por primera vez","El autobús escolar está en una calzada distinta de una carretera con calzadas separadas","El conductor circula a menos de 25 mph"],"explanation":"NMSA 1978, Section 66-7-347(C) establece la única excepción para carreteras divididas: un conductor en una carretera con calzadas separadas no necesita detenerse por un autobús que se encuentra en una calzada distinta (o en una carretera de acceso controlado donde el autobús está en una zona de carga y no se permite el cruce de peatones). El simple hecho de tener carriles adicionales o circular a baja velocidad no exime de detenerse."},"61":{"q":"En una carretera de Nuevo México, un autobús escolar que transporta niños, un autobús que transporta pasajeros a cambio de pago, o un vehículo con materiales peligrosos rotulado debe detenerse antes de un cruce a nivel entre ferrocarril y carretera, ¿a qué distancia del riel más cercano?","options":["No menos de 25 feet y no más de 75 feet","No menos de 10 feet y no más de 40 feet","No menos de 15 feet y no más de 50 feet","No menos de 5 feet y no más de 25 feet"],"explanation":"NMSA 1978, Section 66-7-343(A) exige que estos vehículos se detengan no menos de 15 feet y no más de 50 feet del riel más cercano antes de entrar al cruce. El New Mexico CDL Manual (Sec. 2.15) establece la misma regla de 15 a 50 feet."},"62":{"q":"La ley de Nuevo México sobre la parada en cruces ferroviarios (66-7-343) exige que un conductor obligado, mientras está detenido en el cruce, ponga el vehículo en una marcha lo suficientemente baja para que:","options":["Se pueda seleccionar la reversa si se aproxima un tren","No sea necesario cambiar de marcha antes de despejar el cruce","Se pueda activar el freno de motor al otro lado","El vehículo pueda volver a arrancar en una pendiente del 5%"],"explanation":"NMSA 1978, Section 66-7-343(B)(3) exige seleccionar una marcha lo suficientemente baja para que no sea necesario cambiar de marcha antes de salir del cruce, y la Subsection (C) prohíbe cambiar de marcha mientras se está en el cruce. El New Mexico CDL Manual lo repite: 'No cambie de marcha mientras cruza las vías del ferrocarril.'"},"63":{"q":"¿Cuál de estas NO es una de las excepciones enumeradas en Nuevo México que eximen a un autobús o a un vehículo con materiales peligrosos rotulado de detenerse en un cruce a nivel entre ferrocarril y carretera?","options":["Un cruce donde una luz roja intermitente y una campana están activas","Un cruce donde un oficial de policía dirige el tránsito para que avance","Un cruce controlado por un semáforo de pare y siga","Un cruce marcado con un letrero de 'cruce exento'"],"explanation":"NMSA 1978, Section 66-7-343(D) enumera las excepciones: un oficial dirigiendo el tránsito, un semáforo de pare y siga, un cruce de maniobras industriales dentro de un distrito comercial, un cruce abandonado señalizado como tal, y un letrero de 'cruce exento'. Un cruce con luz roja intermitente y campana activas NO es una excepción; el vehículo igual debe detenerse."},"64":{"q":"¿Cuál es el límite máximo general de velocidad establecido por el estatuto de Nuevo México para cualquier vehículo en una carretera donde no haya un límite menor señalizado?","options":["65 miles per hour","75 miles per hour","80 miles per hour","70 miles per hour"],"explanation":"NMSA 1978, Section 66-7-301(A)(3) fija el máximo general por estatuto en setenta y cinco miles per hour. Esta cifra se aplica en ausencia de un límite menor señalizado o de una zona designada de multa doble."},"65":{"q":"¿Impone Nuevo México un límite máximo de velocidad por estatuto más bajo a los tractocamiones (camiones grandes) que a los autos?","options":["Sí: los camiones están limitados a 60 mph por estatuto","No: el mismo máximo de 75 mph por estatuto aplica a camiones y autos","Sí: los camiones están limitados a 55 mph de noche por estatuto","Sí: los camiones están limitados a 65 mph por estatuto"],"explanation":"Nuevo México no es un estado con límite de velocidad diferenciado. El máximo de 75 mph en NMSA 1978, Section 66-7-301 aplica a todos los vehículos. Un proyecto de ley de 2025 (SB226) que proponía un límite de 65 mph para tractocamiones murió en comité y nunca se convirtió en ley, por lo que no existe ningún tope de velocidad por estatuto específico para camiones."},"66":{"q":"Según el estatuto de Nuevo México, ¿cuál es el límite máximo de velocidad al pasar por una escuela mientras los niños van o salen de la escuela y la zona escolar está debidamente señalizada?","options":["25 miles per hour","20 miles per hour","30 miles per hour","15 miles per hour"],"explanation":"NMSA 1978, Section 66-7-301(A)(1) fija un límite de 15 mph en todas las carreteras al pasar por una escuela mientras los niños van o salen de la escuela y la zona está debidamente señalizada."},"67":{"q":"En ausencia de un límite señalizado, ¿qué velocidad fija el estatuto de Nuevo México para conducir en un distrito comercial o residencial?","options":["20 miles per hour","35 miles per hour","30 miles per hour","25 miles per hour"],"explanation":"NMSA 1978, Section 66-7-301(A)(2) fija un límite de 30 mph en un distrito comercial o residencial donde no haya otro límite señalizado."},"68":{"q":"A partir del 1 de julio de 2023, la ley de circulación por carriles de Nuevo México (66-7-376) generalmente restringe el uso del carril izquierdo en una vía de varios carriles, ¿a qué situación?","options":["Solo entre el amanecer y el atardecer","Solo al transportar materiales peligrosos rotulados","Solo al alcanzar y rebasar a otro vehículo","Solo al circular a más de 65 mph"],"explanation":"NMSA 1978, Section 66-7-376(A)(4), promulgada por el SB102 (Laws 2023) con vigencia a partir del 1 de julio de 2023, prohíbe circular por el carril izquierdo de una vía excepto al alcanzar y rebasar, a menos que el tránsito, el flujo o la configuración de la vía (como la incorporación de tránsito) requieran el carril izquierdo."},"69":{"q":"La restricción del carril izquierdo de Nuevo México en 66-7-376 NO aplica en cuál de estos lugares?","options":["En cualquier carretera estatal con tres carriles en cada sentido","Dentro de los límites de una municipalidad, en una vía que no sea interestatal","En una carretera federal dividida de cuatro carriles entre ciudades","En un tramo rural de la Interstate 40"],"explanation":"NMSA 1978, Section 66-7-376(A)(4) establece expresamente que la prohibición del carril izquierdo no aplica dentro de los límites de una municipalidad ni en un camino de condado, siempre que la vía no forme parte del sistema nacional de carreteras interestatales y de defensa."},"70":{"q":"Según la ley de uso de carriles de Nuevo México, un conductor que cambia de carril debe señalar la intención de cambiar de carril durante al menos cuántos feet recorridos finales?","options":["100 feet","150 feet","200 feet","50 feet"],"explanation":"NMSA 1978, Section 66-7-376(A)(2) exige que, antes de salir de un carril, el conductor señale la intención de cambiar de carril durante no menos de los últimos cien feet recorridos por el vehículo."},"71":{"q":"Nuevo México marca un carril central de giro a la izquierda de doble sentido con líneas amarillas dobles paralelas (interior discontinua, exterior continua). Un vehículo que se prepara para girar o que está girando a la izquierda no puede circular por ese carril durante más de qué distancia?","options":["300 feet","500 feet","200 feet","100 feet"],"explanation":"NMSA 1978, Section 66-7-376(B) establece que los vehículos que giran a la izquierda desde la vía no deberán circular por el carril central de giro a la izquierda de doble sentido durante más de doscientos feet mientras se preparan para el giro y lo realizan."},"72":{"q":"Según la ley Move Over de Nuevo México, cuando un vehículo de emergencia autorizado se aproxima con luces intermitentes o sirena, el conductor de todo otro vehículo debe:","options":["Cambiarse un carril a la izquierda y mantener la velocidad","Reducir a 20 mph y permanecer en el carril actual","Detenerse de inmediato en el carril actual sin importar la posición","Acercarse lo más posible al borde derecho o al cordón y detenerse hasta que pase"],"explanation":"NMSA 1978, Section 66-7-332(A) exige que los conductores, ante la aproximación inmediata de un vehículo de emergencia autorizado, cedan el paso y conduzcan de inmediato paralelos y lo más cerca posible del borde derecho o cordón, despejados de cualquier intersección, y se detengan hasta que haya pasado, salvo que un oficial indique lo contrario."},"73":{"q":"La ley Move Over de Nuevo México aplica a un vehículo detenido que muestra luces intermitentes de emergencia o de advertencia. Además de los vehículos de emergencia autorizados, ¿qué vehículos están específicamente cubiertos?","options":["Autobuses escolares en una parada de autobús","Vehículos de reparto postal","Maquinaria agrícola en el acotamiento","Vehículos de recuperación o reparación (grúa/auxilio)"],"explanation":"NMSA 1978, Section 66-7-332(B) extiende el deber de 'cambiar de carril y reducir la velocidad' ante un vehículo detenido a un vehículo de emergencia autorizado detenido o a un vehículo de recuperación o reparación que muestra luces intermitentes de emergencia o de advertencia."},"74":{"q":"Según la ley Move Over de Nuevo México, cuando un conductor se aproxima a un vehículo de emergencia o de recuperación detenido pero NO es razonablemente seguro salir del carril adyacente, el conductor debe:","options":["Detenerse por completo en el carril de circulación","Reducir a una velocidad razonable y prudente según las circunstancias, avanzar con precaución y estar preparado para detenerse","Acelerar para pasar la escena y despejarla rápidamente","Continuar al límite de velocidad señalizado a través de la zona"],"explanation":"NMSA 1978, Section 66-7-332(B)(2) establece que si no es razonablemente seguro circular por un carril no adyacente al vehículo detenido, el conductor deberá reducir la velocidad a una velocidad razonable y prudente según las circunstancias, avanzar con precaución y estar preparado para detenerse."},"75":{"q":"Si un vehículo comercial de Nuevo México debe detenerse en una vía de un solo sentido o dividida, ¿dónde exige el CDL Manual que se coloquen los tres dispositivos de advertencia (triángulos reflectantes)?","options":["Solo directamente detrás del vehículo a 100 feet","A 10 feet, 50 feet y 150 feet hacia el tránsito que se aproxima","Solo a 100 feet adelante y 100 feet atrás","A 10 feet, 100 feet y 200 feet hacia el tránsito que se aproxima"],"explanation":"El New Mexico CDL Manual (Sec. 2.5) sigue el estándar federal para CMV (49 CFR 392.22): en una vía de un solo sentido o dividida, coloque los dispositivos de advertencia a 10 feet, 100 feet y 200 feet hacia el tránsito que se aproxima, dentro de los 10 minutos siguientes a detenerse."},"76":{"q":"En una vía de dos carriles y doble sentido (no dividida) en Nuevo México, ¿dónde exige el CDL Manual que se coloquen los triángulos de advertencia de un vehículo comercial detenido?","options":["A menos de 10 feet del vehículo, y a 100 feet atrás y 100 feet adelante del vehículo","Solo a 10, 100 y 200 feet detrás del vehículo","Solo a 50 feet atrás y 50 feet adelante","Solo a 200 feet atrás y 200 feet adelante"],"explanation":"El New Mexico CDL Manual (Sec. 2.5) indica que en una vía de dos carriles que lleva tránsito en ambos sentidos o una carretera no dividida, coloque un dispositivo a menos de 10 feet del frente o de la parte trasera, y uno a 100 feet atrás y uno a 100 feet adelante del vehículo."},"77":{"q":"En Nuevo México, si un vehículo comercial está detenido donde una colina, una curva u otra obstrucción impide que los triángulos de advertencia se vean dentro de 500 feet, el conductor debe:","options":["Colocar los tres triángulos a menos de 50 feet del parachoques trasero","Dejar todos los triángulos en los 10, 100 y 200 feet estándar","Usar solo las luces intermitentes de cuatro direcciones en lugar de triángulos","Mover el triángulo más alejado hacia atrás más allá de la obstrucción, hasta 500 feet del vehículo"],"explanation":"El New Mexico CDL Manual (Sec. 2.5) indica que si una colina, una curva o una obstrucción bloquea la línea de visión dentro de 500 feet, el triángulo más alejado debe moverse hacia atrás por la vía, hasta 500 feet, para que otros conductores reciban la advertencia. NMSA 1978, Section 66-3-853 exige de forma similar la colocación de 100 a 500 feet cerca de tales obstrucciones."},"78":{"q":"El estatuto 66-3-849 de Nuevo México exige que los autobuses y camiones grandes LLEVEN cuál conjunto de equipo de advertencia de emergencia?","options":["Tres reflectores rojos de emergencia (o bengalas/fusees) más dos banderas rojas de tela","Una sola linterna roja y una bandera","Solo dos luces estroboscópicas ámbar y un extintor","Cuatro conos naranjas y un chaleco reflectante"],"explanation":"NMSA 1978, Section 66-3-849 exige que los vehículos cubiertos (autobuses, camiones, tractocamiones, etc.) lleven dispositivos de advertencia tales como tres reflectores rojos de emergencia, dos banderas rojas de tela y tres fusees (o las bengalas/linternas equivalentes). El New Mexico CDL Manual igualmente enumera tres triángulos reflectantes, seis fusees, o tres bengalas de combustible líquido como los dispositivos de advertencia obligatorios para vehículos estacionados."},"79":{"q":"¿Qué agencia estatal emite las Licencias de Conducir Comerciales (CDL) en Nuevo México?","options":["La Motor Vehicle Division (MVD)","El New Mexico Department of Transportation (NMDOT)","El Buró de Vehículos Comerciales de la Policía Estatal","La Public Regulation Commission (PRC)"],"explanation":"En Nuevo México, las CDL son emitidas por la Motor Vehicle Division (MVD), que forma parte del Taxation and Revenue Department. El NMDOT se encarga de las carreteras y de los permisos para vehículos de sobredimensión/sobrepeso, no de la licencia de conductores. Fuente: MVD New Mexico, página de Commercial Driver's Licenses (CDL) y Chapter 5: Commercial Driver License."},"80":{"q":"Al solicitar una CDL de Nuevo México, ¿en cuántas categorías de conductor deben autocertificarse los solicitantes, eligiendo una?","options":["Cuatro categorías","Dos categorías","Tres categorías","Seis categorías"],"explanation":"Los solicitantes de CDL de Nuevo México deben autocertificarse en una de cuatro categorías que describen el tipo de comercio en el que esperan operar: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) y Excepted Intrastate (EA). Fuente: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.71."},"81":{"q":"Un conductor con CDL de Nuevo México que opera cruzando líneas estatales y que NO está exento de las reglas federales de calificación física, ¿en qué categoría debe autocertificarse?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Un conductor que opera en comercio interestatal y que está obligado a cumplir los estándares médicos federales del DOT se autocertifica como Non-Excepted Interstate (NI) y debe mantener un Medical Examiner's Certificate vigente en archivo con la MVD. Fuente: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.71."},"82":{"q":"¿Quién está autorizado para realizar el examen físico para un Medical Examiner's Certificate de CDL de Nuevo México?","options":["Un profesional médico que figure en el National Registry of Certified Medical Examiners","Cualquier médico con licencia en Nuevo México","Un enfermero practicante en cualquier clínica de atención urgente","El oficial médico de la oficina local de la MVD"],"explanation":"Todas las Certificaciones Médicas de Conductores Comerciales en Nuevo México deben ser realizadas por un profesional médico que figure en el FMCSA National Registry of Certified Medical Examiners. Una licencia médica general por sí sola no es suficiente. Fuente: MVD New Mexico, página de Commercial Driver's Licenses (CDL); FMCSA National Registry."},"83":{"q":"¿Cómo logra un titular de CDL de Nuevo México que el DOT Medical Examiner's Certificate quede registrado ante el estado?","options":["Presentando una copia del certificado a la MVD, que registra el estado médico en el historial de conducción","Enviándolo por correo directamente a la FMCSA en Washington, D.C.","Conservando la tarjeta original únicamente en el vehículo; no se entrega copia a la MVD","Presentándolo ante el New Mexico Department of Health"],"explanation":"Los titulares de CDL de Nuevo México deben proporcionar a la MVD (la State Driver Licensing Agency) una copia de su Medical Examiner's Certificate; la MVD entonces registra el estado de la certificación médica en el historial de conducción comercial (CDLIS). La tarjeta que se lleva en el vehículo por sí sola no cumple el requisito de registro estatal. Fuente: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.71(h)."},"84":{"q":"Antes de presentar el examen para una CDL, un solicitante primerizo de Nuevo México generalmente debe completar cuál capacitación exigida a nivel federal?","options":["Entry-Level Driver Training (ELDT) de un proveedor que figure en el FMCSA Training Provider Registry","Un curso OSHA de seguridad de vehículos comerciales de 40 horas","Un curso presencial de manejo defensivo de Nuevo México","Un aprendizaje de al menos 90 días con un transportista con licencia"],"explanation":"Los solicitantes primerizos de CDL (y ciertas ampliaciones/endosos) deben completar Entry-Level Driver Training (ELDT) a través de un proveedor que figure en el FMCSA Training Provider Registry antes de presentar el examen de habilidades o de conocimientos. La regla aplica a los solicitantes a partir del 7 de febrero de 2022. Fuente: MVD New Mexico Chapter 5; FMCSA ELDT rule, 49 CFR Part 380."},"85":{"q":"¿Cuánto tiempo después de la emisión inicial de un Commercial Learner's Permit (CLP) de Nuevo México debe esperar el titular antes de poder presentar el examen de habilidades de la CDL?","options":["Al menos 14 days","Al menos 30 days","Al menos 10 days","Al menos 60 days"],"explanation":"Un titular de CLP no puede presentar el examen de habilidades de la CDL hasta al menos 14 days después de la emisión inicial del CLP. Este mínimo federal es aplicado por la New Mexico MVD. Fuente: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.25(a)(3)."},"86":{"q":"¿Por cuánto tiempo es válido un Commercial Learner's Permit (CLP) de Nuevo México?","options":["1 year (con una renovación permitida sin volver a examinarse)","90 days","6 months","2 years"],"explanation":"El CLP de Nuevo México se emite por 1 year. Según el estándar federal, puede renovarse una vez dentro de ese período sin volver a presentar el examen de conocimientos generales. Fuente: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.25(c)."},"87":{"q":"El examen de habilidades de la CDL de Nuevo México, ¿de cuántas partes consta y cuáles son?","options":["Tres partes: inspección previaje del vehículo, control básico del vehículo y conducción en carretera","Dos partes: un examen escrito y una conducción en carretera","Tres partes: examen de frenos de aire, examen de retroceso y conducción nocturna","Cuatro partes: inspección, retroceso, carretera y estacionamiento en paralelo"],"explanation":"El examen de habilidades de la CDL tiene tres partes que deben aprobarse en orden: la inspección previaje del vehículo, el control básico del vehículo (maniobras a baja velocidad) y el examen de conducción en carretera. Fuente: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.113."},"88":{"q":"¿Cuál es la calificación mínima para aprobar los exámenes de conocimientos (escritos) de la CDL de Nuevo México?","options":["80 percent","70 percent","75 percent","90 percent"],"explanation":"Los exámenes de conocimientos de la CDL de Nuevo México deben aprobarse con una calificación de al menos 80 percent, en concordancia con el estándar federal. Fuente: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.135."},"89":{"q":"¿Qué requisito previo debe tener ya una persona antes de solicitar una CDL de Nuevo México?","options":["Una licencia de conducir válida de Nuevo México Class D (regular) o una CDL válida de otro estado","Un endoso de pasajeros (P) obtenido en cualquier estado","Una autorización federal de hazmat de la TSA","Un endoso de motocicleta en una licencia de Nuevo México"],"explanation":"Para solicitar una CDL de Nuevo México ya debe tener una licencia de conducir no comercial (Class D) válida de Nuevo México o una CDL válida de otro estado. Fuente: MVD New Mexico, requisitos para obtener una CDL de Nuevo México."},"90":{"q":"Según las reglas de la New Mexico MVD, ¿cuántas pruebas de residencia física en Nuevo México debe presentar un solicitante de CDL?","options":["Dos pruebas de residencia física","Una prueba de residencia física","Tres pruebas de residencia física","No se requiere prueba de residencia"],"explanation":"Un solicitante de CDL de Nuevo México debe presentar dos pruebas de residencia física en el estado. Los documentos mensuales, como recibos de servicios públicos o estados de cuenta bancarios usados como prueba, deben tener fecha dentro de los 60 days previos a la solicitud. Fuente: MVD New Mexico, página de Commercial Driver's Licenses (CDL)."},"91":{"q":"¿Qué opciones de ciclo de renovación ofrece Nuevo México para una CDL?","options":["Una credencial de 4 years o de 8 years","Una credencial de 1 year o de 5 years","Solo una credencial de 5 years","Una credencial de 2 years o de 6 years"],"explanation":"Nuevo México ofrece CDL en un ciclo de renovación de 4 years o de 8 years. Fuente: MVD New Mexico FAQ y Chapter 5."},"92":{"q":"¿Por qué podría un titular de CDL de Nuevo México estar limitado a la credencial de 4 years (en lugar de la de 8 years)?","options":["Porque tiene un endoso de Materiales Peligrosos (Hazmat)","Porque tiene un endoso de pasajeros (P)","Porque conduce solo dentro del estado (intraestatal)","Porque es menor de 30 años"],"explanation":"Los conductores que tienen el endoso de Materiales Peligrosos (Hazmat) no pueden obtener la CDL de 8 years; la verificación periódica de antecedentes de la TSA ligada al Hazmat los limita al ciclo de 4 years. Fuente: MVD New Mexico FAQ; reglas de endoso Hazmat de TSA/FMCSA."},"93":{"q":"¿Cómo se programan los exámenes de conocimientos de la CDL de Nuevo México en cuanto a las repeticiones?","options":["Los solicitantes pueden presentar los exámenes escritos de la CDL hasta dos veces por semana","Los solicitantes pueden presentar los exámenes escritos solo una vez cada 30 days","Los solicitantes obtienen repeticiones ilimitadas el mismo día","Los solicitantes pueden presentar los exámenes escritos solo una vez por año calendario"],"explanation":"Nuevo México permite a los solicitantes de CDL presentar los exámenes escritos (de conocimientos) de la CDL hasta dos veces por semana. Fuente: MVD New Mexico, página de Commercial Driver's Licenses (CDL)."},"94":{"q":"¿Cuál es la edad mínima para obtener una CDL de Nuevo México restringida solo a la conducción intraestatal (dentro del estado)?","options":["18 años","16 años","21 años","19 años"],"explanation":"Una persona puede obtener una CDL de Nuevo México para conducción intraestatal a los 18 años; un solicitante de 18 a 20 años está restringido a la operación dentro del estado. Operar en comercio interestatal requiere tener 21 años. Fuente: MVD New Mexico Chapter 5; FMCSA 49 CFR 391.11."},"95":{"q":"Cuando un conductor canjea una CDL válida de otro estado por una CDL de Nuevo México de la misma clase y endosos, ¿qué examen se requiere generalmente?","options":["No se requieren exámenes escritos para la clase y endosos equivalentes","Deben volver a presentarse tanto el examen escrito como el de habilidades","Solo debe volver a presentarse el examen de habilidades en carretera","Solo debe repetirse la inspección previaje"],"explanation":"Nuevo México no exige exámenes escritos para canjear una CDL válida de otro estado por una CDL de Nuevo México de la misma clase y endosos. (El endoso de Hazmat aún requiere su propio examen y la verificación de antecedentes de la TSA.) Fuente: MVD New Mexico, requisitos para obtener una CDL de Nuevo México."},"96":{"q":"Además de un examen escrito de conocimientos, un solicitante de CDL de Nuevo México que busca un endoso de Materiales Peligrosos (Hazmat) también debe completar qué?","options":["Toma de huellas dactilares y una evaluación de amenaza de seguridad de la TSA (verificación de antecedentes)","Un examen separado de conducción nocturna en carretera","Un curso de manejo defensivo de 10 days","Un examen de la vista en una clínica administrada por el estado"],"explanation":"Un conductor de Nuevo México que busca el endoso de Hazmat debe aprobar el examen de conocimientos de Hazmat y tomarse las huellas dactilares para una evaluación de amenaza de seguridad de la TSA (verificación de antecedentes) antes de que se otorgue el endoso. Fuente: MVD New Mexico, requisitos para obtener una CDL de Nuevo México; TSA Hazmat Endorsement Threat Assessment Program."},"97":{"q":"Cuando un solicitante de CDL de Nuevo México regresa a la MVD para recibir la CDL tras aprobar el examen de habilidades, ¿en qué forma se entregan normalmente los resultados del examen?","options":["Un sobre sellado que contiene las calificaciones del examen de habilidades, presentado junto con el CLP y los documentos requeridos","Un correo electrónico enviado directamente del examinador a la FMCSA","Un informe verbal dado solo al supervisor del examinador","Una calificación impresa en el reverso del registro del vehículo del examen de manejo"],"explanation":"Tras aprobar el examen de habilidades administrado por un examinador de CDL aprobado, el solicitante regresa a la MVD con su licencia de conducir, el CLP y un sobre sellado que contiene las calificaciones del examen de habilidades para que se le emita la CDL. Fuente: MVD New Mexico, requisitos para obtener una CDL de Nuevo México."}},"hi":{"0":{"q":"न्यू मैक्सिको के राजमार्गों पर, ओवरसाइज़ परमिट के बिना किसी वाणिज्यिक वाहन या उसके भार की अधिकतम कानूनी चौड़ाई (दर्पणों और कुछ सुरक्षा उपकरणों को छोड़कर) कितनी है?","options":["8 फुट 6 इंच (102 inches)","8 फुट (96 inches)","9 फुट (108 inches)","10 फुट (120 inches)"],"explanation":"न्यू मैक्सिको किसी वाहन या भार की कुल बाहरी चौड़ाई को 8 फुट 6 इंच (102 inches) तक सीमित करता है, जिसमें दर्पण और स्वीकृत सुरक्षा उपकरण शामिल नहीं हैं। इससे अधिक चौड़े भार के लिए ओवरसाइज़ परमिट आवश्यक है। स्रोत: NMSA 1978, Section 66-7-402 (Width of vehicles); NM CDL Manual."},"1":{"q":"न्यू मैक्सिको के राजमार्गों पर परमिट के बिना किसी वाहन और उसके भार की अधिकतम कानूनी ऊँचाई कितनी है?","options":["14 फुट","13 फुट 6 इंच","15 फुट","13 फुट"],"explanation":"न्यू मैक्सिको अधिकतम वाहन-और-भार की ऊँचाई 14 फुट निर्धारित करता है। 14 फुट से अधिक ऊँचे भार के लिए ओवरसाइज़ (ओवर-हाइट) परमिट आवश्यक है। स्रोत: NMSA 1978, Section 66-7-404 (Height and length of vehicles and loads)."},"2":{"q":"न्यू मैक्सिको के कानून के तहत किसी वाणिज्यिक वाहन के किसी एक सिंगल एक्सल पर अधिकतम सकल वजन कितना हो सकता है?","options":["21,600 pounds","20,000 pounds","22,400 pounds","18,000 pounds"],"explanation":"न्यू मैक्सिको की सिंगल-एक्सल सीमा 21,600 pounds है, जो 20,000-pound की संघीय इंटरस्टेट सिंगल-एक्सल सीमा से अधिक है। स्रोत: NMSA 1978, Section 66-7-409 (Load limits on single axles, wheels and tires)."},"3":{"q":"न्यू मैक्सिको के कानून के तहत, किसी टैंडेम एक्सल सेट (4 फुट की दूरी पर रखे गए दो एक्सल) पर अधिकतम कितना वजन अनुमत है?","options":["34,320 pounds","34,000 pounds","36,000 pounds","32,000 pounds"],"explanation":"न्यू मैक्सिको की एक्सल-समूह वजन तालिका टैंडेम (लगभग 4 फुट की दूरी पर रखे गए दो एक्सल) पर 34,320 pounds की अनुमति देती है, जो 34,000-pound की संघीय इंटरस्टेट टैंडेम सीमा से थोड़ा अधिक है। स्रोत: NMSA 1978, Section 66-7-410 (Gross weight of vehicles and loads)."},"4":{"q":"न्यू मैक्सिको के राजमार्गों पर परमिट के बिना ट्रक-ट्रेलर संयोजन की अधिकतम समग्र लंबाई कितनी है?","options":["65 फुट","60 फुट","70 फुट","75 फुट"],"explanation":"न्यू मैक्सिको सामान्यतः राजमार्गों पर किसी समग्र संयोजन (ट्रक और ट्रेलर) को 65 फुट तक सीमित करता है; इससे लंबे संयोजनों के लिए ओवरसाइज़ परमिट आवश्यक है। स्रोत: NMSA 1978, Section 66-7-404 (Height and length of vehicles and loads)."},"5":{"q":"न्यू मैक्सिको की इंटरस्टेट (संघीय-सहायता) राजमार्ग प्रणाली पर, ओवरवेट परमिट के बिना अधिकतम कितना सकल वाहन वजन अनुमत है?","options":["80,000 pounds","86,400 pounds","84,000 pounds","90,000 pounds"],"explanation":"इंटरस्टेट प्रणाली पर, न्यू मैक्सिको 80,000 pounds सकल की संघीय सीमा लागू करता है। राज्य की अपनी वैधानिक तालिका कुछ गैर-इंटरस्टेट राज्य राजमार्गों पर इससे कुछ अधिक की अनुमति देती है, लेकिन परमिट के बिना इंटरस्टेट अधिकतम 80,000 pounds है। स्रोत: 23 U.S.C. 127 जैसा न्यू मैक्सिको में लागू है; NMSA 1978, Section 66-7-410."},"6":{"q":"न्यू मैक्सिको की वैधानिक सकल-वजन तालिका के तहत, किसी गैर-इंटरस्टेट राज्य राजमार्ग पर विशेष परमिट के बिना (लगभग 56 फुट या उससे अधिक की पर्याप्त एक्सल दूरी के साथ) अधिकतम कितना सकल वजन अनुमत है?","options":["86,400 pounds","80,000 pounds","94,000 pounds","84,000 pounds"],"explanation":"न्यू मैक्सिको की सकल-वजन तालिका गैर-इंटरस्टेट राज्य राजमार्गों पर तब अधिकतम 86,400 pounds तक पहुँचती है जब पहले और अंतिम एक्सल के बीच की दूरी लगभग 56 फुट या उससे अधिक हो। इंटरस्टेट प्रणाली संघीय 80,000 pounds पर ही सीमित रहती है। स्रोत: NMSA 1978, Section 66-7-410 (Gross weight of vehicles and loads)."},"7":{"q":"नामित न्यू मैक्सिको राजमार्गों (नेशनल नेटवर्क) पर परमिट के बिना संचालित होने वाले सेमीट्रेलर की अधिकतम लंबाई कितनी है?","options":["57 फुट 6 इंच","53 फुट","48 फुट","60 फुट"],"explanation":"न्यू मैक्सिको नामित नेशनल नेटवर्क मार्गों पर सेमीट्रेलर को 57 फुट 6 इंच तक की अनुमति देता है। स्रोत: NMSA 1978, Section 66-7-404 (Height and length of vehicles and loads); NM CDL Manual."},"8":{"q":"न्यू मैक्सिको में, इंटरस्टेट प्रणाली पर लगातार एक्सल के किसी समूह पर अधिकतम अनुमेय सकल वजन निर्धारित करने के लिए किस सूत्र का उपयोग किया जाता है?","options":["The Federal Bridge Formula","The Net-Tonnage Rule","The Axle-Spacing Quotient","The Gross-Combination Ratio"],"explanation":"इंटरस्टेट प्रणाली पर, न्यू मैक्सिको Federal Bridge Formula लागू करता है, W = 500[(LN/(N-1)) + 12N + 36], जो किसी भी एक्सल समूह पर वजन को दूरी (L) और एक्सल की संख्या (N) के आधार पर सीमित करता है। स्रोत: 23 U.S.C. 127 / FBF जैसा न्यू मैक्सिको में लागू है; NM CDL Manual."},"9":{"q":"न्यू मैक्सिको राज्य राजमार्गों पर संचालित वाणिज्यिक वाहनों के लिए ओवरसाइज़/ओवरवेट परमिट कौन जारी करता है?","options":["The New Mexico Department of Transportation (NMDOT)","काउंटी शेरिफ का कार्यालय","The Federal Motor Carrier Safety Administration","स्थानीय शहर लोक निर्माण विभाग"],"explanation":"न्यू मैक्सिको में ओवरसाइज़ और ओवरवेट परमिट The New Mexico Department of Transportation (NMDOT) द्वारा जारी किए जाते हैं, जिनका प्रशासन इसके Ports of Entry / परमिट इकाई और ऑनलाइन परमिट प्रणाली के माध्यम से होता है। स्रोत: NMDOT Permits / Ports of Entry; NMSA 1978, Section 66-7-413."},"10":{"q":"एक वाहक को एक ऐसा अविभाज्य भार ले जाना है जो न्यू मैक्सिको की कानूनी वजन सीमा से अधिक है। यात्रा से पहले वाहक को क्या प्राप्त करना होगा?","options":["एक NMDOT ओवरवेट (विशेष) परमिट","एक नया CDL एंडोर्समेंट","FMCSA से एक संघीय इंटरस्टेट छूट","केवल कार्गो बीमा का प्रमाण"],"explanation":"न्यू मैक्सिको की कानूनी आकार या वजन सीमा से अधिक भार ले जाने के लिए NMDOT से एक विशेष (ओवरसाइज़/ओवरवेट) परमिट आवश्यक है, जो आमतौर पर अविभाज्य भार के लिए होता है। स्रोत: NMSA 1978, Section 66-7-413; NMDOT Permits."},"11":{"q":"न्यू मैक्सिको के सिंगल-एक्सल नियमों के तहत, किसी एक पहिये पर अधिकतम कितना वजन अनुमत है?","options":["11,000 pounds","10,000 pounds","12,500 pounds","9,000 pounds"],"explanation":"न्यू मैक्सिको किसी एक पहिये पर भार को 11,000 pounds तक सीमित करता है, जो इसके सिंगल-एक्सल, पहिया और टायर भार नियमों का हिस्सा है। स्रोत: NMSA 1978, Section 66-7-409 (Load limits on single axles, wheels and tires)."},"12":{"q":"न्यू मैक्सिको का टायर-भार नियम वजन को प्रति इंच टायर चौड़ाई कितना तक सीमित करता है?","options":["600 pounds प्रति इंच टायर चौड़ाई","500 pounds प्रति इंच टायर चौड़ाई","800 pounds प्रति इंच टायर चौड़ाई","1,000 pounds प्रति इंच टायर चौड़ाई"],"explanation":"न्यू मैक्सिको अपने एक्सल, पहिया और टायर भार सीमाओं के हिस्से के रूप में टायर लोडिंग को 600 pounds प्रति इंच टायर चौड़ाई तक सीमित करता है। स्रोत: NMSA 1978, Section 66-7-409 (Load limits on single axles, wheels and tires)."},"13":{"q":"न्यू मैक्सिको में ओवरसाइज़/ओवरवेट परमिट आमतौर पर किन अवधियों के लिए जारी किया जाता है?","options":["एक एकल यात्रा या एक वार्षिक अवधि","केवल एक एकल यात्रा, कभी इससे अधिक नहीं","केवल अधिकतम 30 दिन","स्थायी रूप से, बिना किसी समाप्ति के"],"explanation":"न्यू मैक्सिको के ओवरसाइज़/ओवरवेट परमिट आमतौर पर या तो एकल-यात्रा परमिट के रूप में या वार्षिक परमिट के रूप में जारी किए जाते हैं, जो आवागमन पर निर्भर करता है। स्रोत: NMDOT Permits / Ports of Entry; NMSA 1978, Section 66-7-413."},"14":{"q":"न्यू मैक्सिको के इंटरस्टेट पर लागू Federal Bridge Formula के तहत, चर L और N क्या दर्शाते हैं?","options":["L = किसी समूह के बाहरी एक्सल के बीच फुट में दूरी; N = समूह में एक्सल की संख्या","L = pounds में भार; N = टायरों की संख्या","L = ट्रेलर की लंबाई; N = टन में शुद्ध वजन","L = कानूनी सीमा; N = धारित परमिटों की संख्या"],"explanation":"Federal Bridge Formula में, L दो या अधिक लगातार एक्सल के किसी समूह के दोनों छोरों (पहले और अंतिम एक्सल) के बीच फुट में दूरी है, और N उस समूह में एक्सल की संख्या है। स्रोत: 23 U.S.C. 127 / FBF जैसा न्यू मैक्सिको में लागू है; NM CDL Manual."},"15":{"q":"एक सेमीट्रेलर भार की चौड़ाई 8 फुट 8 इंच मापी गई है। न्यू मैक्सिको के राजमार्गों पर इसे कानूनी रूप से ले जाने के लिए क्या आवश्यक है?","options":["एक NMDOT ओवरसाइज़ (ओवर-विड्थ) परमिट","कुछ नहीं; यह कानूनी चौड़ाई के भीतर है","केवल एक वाइड-लोड झंडा, कोई परमिट नहीं","एक Class A CDL में परिवर्तन"],"explanation":"न्यू मैक्सिको की कानूनी चौड़ाई सीमा 8 फुट 6 इंच है; 8 फुट 8 इंच पर भार इससे अधिक हो जाता है, इसलिए एक NMDOT ओवर-विड्थ ओवरसाइज़ परमिट आवश्यक है। स्रोत: NMSA 1978, Section 66-7-402; NMDOT Permits."},"16":{"q":"जब चौड़ाई या लंबाई की सीमा पार हो जाती है, तो न्यू मैक्सिको एस्कॉर्ट (पायलट) वाहनों की मांग कर सकता है। किस चौड़ाई से अधिक होने पर न्यू मैक्सिको आमतौर पर किसी चलते भार के लिए एस्कॉर्ट की मांग करता है?","options":["14 फुट से अधिक चौड़ाई","10 फुट से अधिक चौड़ाई","8 फुट 6 इंच से अधिक चौड़ाई","20 फुट से अधिक चौड़ाई"],"explanation":"न्यू मैक्सिको आमतौर पर 14 फुट से अधिक चौड़ाई वाले भार के लिए (और लगभग 90 फुट से अधिक लंबाई वाले भार के लिए) एस्कॉर्ट/पायलट वाहनों की मांग करता है। स्रोत: NMDOT ओवरसाइज़ परमिट आवागमन आवश्यकताएँ।"},"17":{"q":"आज न्यू मैक्सिको में एक वाहक आमतौर पर ओवरसाइज़/ओवरवेट परमिट के लिए सबसे अधिक किस प्रकार आवेदन करता है?","options":["NMDOT की ऑनलाइन परमिट प्रणाली के माध्यम से","गवर्नर के कार्यालय को एक कागजी फॉर्म डाक से भेजकर","वॉशिंगटन, D.C. में FMCSA को कॉल करके","केवल काउंटी कोर्टहाउस में व्यक्तिगत रूप से"],"explanation":"न्यू मैक्सिको के ओवरसाइज़/ओवरवेट परमिट मुख्य रूप से NMDOT की ऑनलाइन परमिट प्रणाली के माध्यम से प्राप्त किए जाते हैं, जहाँ वाहक भार आयाम, वजन, मार्ग और यात्रा तिथियाँ दर्ज करते हैं। स्रोत: NMDOT Permits / Ports of Entry."},"18":{"q":"न्यू मैक्सिको के सकल-वजन आँकड़े संघीय इंटरस्टेट मानक से भिन्न हैं। 20,000-pound की संघीय इंटरस्टेट सिंगल-एक्सल सीमा की तुलना में, न्यू मैक्सिको की वैधानिक सिंगल-एक्सल सीमा है:","options":["अधिक, 21,600 pounds पर","कम, 18,000 pounds पर","समान, 20,000 pounds पर","अधिक, 25,000 pounds पर"],"explanation":"न्यू मैक्सिको की वैधानिक सिंगल-एक्सल सीमा 21,600 pounds है, जो 20,000-pound की संघीय इंटरस्टेट सिंगल-एक्सल सीमा से अधिक है। इंटरस्टेट प्रणाली पर ही निम्न संघीय आँकड़ा अभी भी लागू होता है। स्रोत: NMSA 1978, Section 66-7-409; 23 U.S.C. 127."},"19":{"q":"न्यू मैक्सिको में, जब खींची जाने वाली इकाई(याँ) 10,000 lbs GVWR से अधिक हों, तो कम से कम किस मूल्य की Gross Combination Weight Rating (GCWR) वाले वाहनों के किसी भी संयोजन को संचालित करने के लिए Class A CDL आवश्यक है?","options":["26,001 या अधिक pounds","10,001 या अधिक pounds","18,001 या अधिक pounds","33,001 या अधिक pounds"],"explanation":"एक न्यू मैक्सिको Class A CDL 26,001 या अधिक pounds की GCWR वाले वाहनों के किसी भी संयोजन को चलाने का अधिकार देता है, बशर्ते खींची जा रही इकाई(यों) की GVWR 10,000 pounds से अधिक हो। स्रोत: NM MVD Driver Manual Chapter 5 (Commercial Driver License)."},"20":{"q":"कौन सा न्यू मैक्सिको CDL वर्ग 26,001 या अधिक pounds की GVWR वाले किसी एकल वाहन को, या ऐसे वाहन द्वारा 10,000 lbs GVWR से अधिक न होने वाली इकाई को खींचने को संचालित करने का अधिकार देता है?","options":["Class B","Class A","Class C","Class D"],"explanation":"एक न्यू मैक्सिको Class B CDL 26,001 या अधिक pounds की GVWR वाले किसी भी एकल वाहन को, या ऐसे वाहन द्वारा 10,000 pounds GVWR से अधिक न होने वाली इकाई को खींचने को कवर करता है। 26,001 GCWR से अधिक का संयोजन जो 10,000 lbs से अधिक खींचता है, उसके लिए Class A आवश्यक है। स्रोत: NM MVD Driver Manual Chapter 5."},"21":{"q":"एक न्यू मैक्सिको Class C CDL 26,001 lbs GVWR से कम के वाहन पर केवल तब लागू होता है जब इसका उपयोग किस उद्देश्य के लिए किया जाता है?","options":["16 या अधिक यात्रियों (चालक सहित) या प्लेकार्डेड खतरनाक सामग्री ले जाना","5,000 lbs से अधिक का कोई भी ट्रेलर खींचना","किराये पर 9 या अधिक यात्रियों को ले जाना","किसी भी कार्गो के लिए राज्य की सीमाओं के पार संचालन"],"explanation":"एक न्यू मैक्सिको Class C CDL 26,001 lbs GVWR से कम के किसी एकल वाहन (या 10,000 lbs से अधिक न होने वाली इकाई को खींचने) पर केवल तब लागू होता है जब इसे चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया हो, या जब इसे खतरनाक सामग्री के लिए प्लेकार्ड किया गया हो। स्रोत: NM MVD Driver Manual Chapter 5."},"22":{"q":"न्यू मैक्सिको द्वारा अपनाए गए संघीय नियमों के तहत, एक Commercial Learner Permit (CLP) धारक CLP के शुरुआती जारी होने के कम से कम कितने दिन बाद तक CDL कौशल परीक्षा नहीं दे सकता?","options":["14 days","7 days","30 days","10 days"],"explanation":"CLP धारक CLP के शुरुआती जारी होने के पहले 14 days में CDL कौशल परीक्षा देने के लिए पात्र नहीं है। न्यू मैक्सिको इस संघीय 14-day होल्ड को लागू करता है। स्रोत: NM MVD Driver Manual Chapter 5; 49 CFR 383.25."},"23":{"q":"केवल इंट्रास्टेट (न्यू मैक्सिको के भीतर) वाणिज्य तक सीमित न्यू मैक्सिको CDL जारी करने के लिए न्यूनतम आयु क्या है?","options":["18 वर्ष","21 वर्ष","16 वर्ष","19 वर्ष"],"explanation":"इंट्रास्टेट वाणिज्य तक सीमित न्यू मैक्सिको CDL रखने के लिए आवेदक की आयु कम से कम 18 होनी चाहिए। 18-20 वर्ष का चालक एक 'K' प्रतिबंध प्राप्त करता है जो उसे केवल न्यू मैक्सिको के भीतर ड्राइव करने तक सीमित करता है। स्रोत: NM MVD Driver Manual Chapter 5."},"24":{"q":"इंटरस्टेट (राज्य की सीमाओं के पार) वाणिज्य के लिए न्यू मैक्सिको CDL जारी करने के लिए न्यूनतम आयु क्या है?","options":["21 वर्ष","18 वर्ष","23 वर्ष","25 वर्ष"],"explanation":"इंटरस्टेट वाणिज्य में किसी वाणिज्यिक मोटर वाहन को संचालित करने के लिए चालक की आयु कम से कम 21 होनी चाहिए। 18-20 वर्ष के न्यू मैक्सिको चालक इंट्रास्टेट संचालन तक सीमित हैं। स्रोत: NM MVD Driver Manual Chapter 5; 49 CFR 391.11."},"25":{"q":"न्यू मैक्सिको CDL पर, 'K' प्रतिबंध चालक के बारे में क्या इंगित करता है?","options":["केवल इंट्रास्टेट वाणिज्य तक सीमित","एयर ब्रेक के बिना वाहनों तक सीमित","स्वचालित-ट्रांसमिशन वाहनों तक सीमित","यात्रियों को नहीं ले जा सकता"],"explanation":"न्यू मैक्सिको 18-20 वर्ष के आवेदकों को जारी CDL पर एक 'K' प्रतिबंध लगाता है, जो चालक को केवल इंट्रास्टेट (न्यू मैक्सिको के भीतर) वाणिज्य तक सीमित करता है। स्रोत: NM MVD Driver Manual Chapter 5."},"26":{"q":"थोक में तरल या गैसीय सामग्री ले जाने वाले टैंक वाहन को संचालित करने के लिए न्यू मैक्सिको CDL पर कौन सा एंडोर्समेंट आवश्यक है?","options":["N (Tank Vehicle)","T (Doubles/Triples)","H (Hazardous Materials)","P (Passenger)"],"explanation":"N एंडोर्समेंट थोक में तरल या गैसीय सामग्री के परिवहन के लिए उपयोग किए जाने वाले टैंक वाहन के संचालन का अधिकार देता है। आवश्यक ज्ञान परीक्षा पास करने के बाद N एंडोर्समेंट को CLP पर जोड़ा जा सकता है। स्रोत: NM MVD Driver Manual Chapter 5."},"27":{"q":"किसी एकल पावर यूनिट के पीछे दो या तीन ट्रेलर खींचने के लिए कौन सा न्यू मैक्सिको CDL एंडोर्समेंट आवश्यक है?","options":["T (Doubles/Triples)","N (Tank Vehicle)","S (School Bus)","X (Combination)"],"explanation":"T एंडोर्समेंट डबल या ट्रिपल ट्रेलर खींचने का अधिकार देता है और इसके लिए एक ज्ञान परीक्षा पास करना आवश्यक है। स्रोत: NM MVD Driver Manual Chapter 5; 49 CFR 383.93."},"28":{"q":"चालक सहित 16 या अधिक लोगों को ले जाने के लिए डिज़ाइन किए गए वाणिज्यिक वाहन को चलाने के लिए न्यू मैक्सिको CDL धारक को किस एंडोर्समेंट की आवश्यकता है?","options":["P (Passenger)","S (School Bus)","N (Tank Vehicle)","T (Doubles/Triples)"],"explanation":"चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाहन को चलाने के लिए P (Passenger) एंडोर्समेंट आवश्यक है। कौशल परीक्षा उस वर्ग के प्रतिनिधि वाहन में देनी होगी। स्रोत: NM MVD Driver Manual Chapter 5; 49 CFR 383.93."},"29":{"q":"H (Hazardous Materials) एंडोर्समेंट जारी होने से पहले, एक न्यू मैक्सिको आवेदक को किस सुरक्षा जाँच को पास करना होगा?","options":["Universal Enroll के माध्यम से एक TSA फिंगरप्रिंट-आधारित पृष्ठभूमि/खतरा आकलन","केवल एक FBI मोस्ट-वांटेड सूची तुलना","केवल राज्य-पुलिस आपराधिक रिकॉर्ड जाँच","बिना फिंगरप्रिंट के एक New Mexico MVD साक्षात्कार"],"explanation":"न्यू मैक्सिको MVD HazMat (H) एंडोर्समेंट तब तक जारी नहीं कर सकता जब तक आवेदक Universal Enroll प्रणाली के माध्यम से एक TSA फिंगरप्रिंट-आधारित पृष्ठभूमि जाँच (Hazardous Materials Endorsement Threat Assessment) पूरी न कर ले और TSA यह निर्धारित न कर ले कि आवेदक सुरक्षा खतरा नहीं है। स्रोत: NM MVD Hazardous Material Endorsement page; 49 CFR 1572."},"30":{"q":"न्यू मैक्सिको में पहली बार HazMat (H) एंडोर्समेंट के लिए, ELDT आवेदक को ज्ञान परीक्षा से पहले कौन सा प्रशिक्षण पूरा करना आवश्यक है?","options":["FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता के साथ खतरनाक सामग्री सिद्धांत प्रशिक्षण","केवल बिहाइंड-द-व्हील रेंज प्रशिक्षण","एक 40-घंटे का व्यक्तिगत HazMat रोड कोर्स","कोई प्रशिक्षण नहीं; केवल TSA पृष्ठभूमि जाँच"],"explanation":"पहली बार H एंडोर्समेंट के आवेदकों को ज्ञान परीक्षा देने से पहले FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता से HazMat सिद्धांत प्रशिक्षण (H के लिए कोई बिहाइंड-द-व्हील घटक आवश्यक नहीं है) पूरा करना होगा। स्रोत: NM MVD Driver Manual Chapter 5; 49 CFR 380.725."},"31":{"q":"ELDT आवश्यकताएँ उन पहली बार के न्यू मैक्सिको आवेदकों पर लागू होती हैं जिन्होंने किस तिथि को या उसके बाद प्रारंभिक CLP के लिए आवेदन किया?","options":["February 7, 2022","January 1, 2020","September 30, 2021","July 1, 2023"],"explanation":"February 7, 2022 को या उसके बाद पहली बार CLP के लिए आवेदन करने वाले सभी आवेदकों को 49 CFR 380.600-380.603 में संघीय Entry-Level Driver Training (ELDT) नियमों का पालन करना होगा। स्रोत: NM MVD Driver Manual Chapter 5."},"32":{"q":"CDL/एंडोर्समेंट पात्रता की ओर गिने जाने के लिए एक न्यू मैक्सिको ELDT आवेदक को आवश्यक एंट्री-लेवल ड्राइवर प्रशिक्षण कहाँ से प्राप्त करना होगा?","options":["FMCSA Training Provider Registry (TPR) पर सूचीबद्ध किसी प्रदाता से","आवेदक की पसंद के किसी भी वाणिज्यिक ड्राइविंग स्कूल से","सीधे New Mexico MVD फील्ड कार्यालय से","किसी नियोक्ता के इन-हाउस कार्यक्रम से, बिना किसी रजिस्ट्री की आवश्यकता के"],"explanation":"ELDT को FMCSA Training Provider Registry (TPR) पर सूचीबद्ध किसी प्रदाता के साथ tpr.fmcsa.dot.gov पर पूरा करना होगा; प्रदाता प्रमाणन FMCSA को प्रस्तुत करता है। स्रोत: NM MVD Driver Manual Chapter 5; FMCSA TPR."},"33":{"q":"'Non-Excepted Interstate' (NI) की एक न्यू मैक्सिको स्व-प्रमाणन का अर्थ है कि चालक इंटरस्टेट वाणिज्य में संचालन करता है और:","options":["उसे संघीय DOT मेडिकल कार्ड आवश्यकताओं को पूरा करना होगा","उसे किसी भी मेडिकल आवश्यकता को पूरा करने की आवश्यकता नहीं है","केवल न्यू मैक्सिको राज्य की मेडिकल आवश्यकताओं को पूरा करता है","छूट प्राप्त है क्योंकि वह एक फार्म वाहन चलाता है"],"explanation":"Non-Excepted Interstate (NI) का चयन यह प्रमाणित करता है कि चालक इंटरस्टेट वाणिज्य में संचालन करता है और उसे संघीय DOT मेडिकल परीक्षक के प्रमाणपत्र की आवश्यकताओं को पूरा करना आवश्यक है। स्रोत: NM MVD Driver Manual Chapter 5 (Medical Self-Certification)."},"34":{"q":"कौन सी न्यू मैक्सिको मेडिकल स्व-प्रमाणन श्रेणी ऐसे चालक पर लागू होती है जो केवल न्यू मैक्सिको के भीतर संचालन करता है और जिसे न्यू मैक्सिको की मेडिकल आवश्यकताओं को पूरा करने की आवश्यकता नहीं है?","options":["EA (Excepted Intrastate)","NA (Non-Excepted Intrastate)","NI (Non-Excepted Interstate)","EI (Excepted Interstate)"],"explanation":"Excepted Intrastate (EA) का अर्थ है कि चालक केवल न्यू मैक्सिको के भीतर संचालन करता है और उसे State of New Mexico की मेडिकल आवश्यकताओं को पूरा करने की आवश्यकता नहीं है। NA के लिए NM मेडिकल आवश्यकताओं को पूरा करना आवश्यक होगा। स्रोत: NM MVD Driver Manual Chapter 5."},"35":{"q":"पहचान और वैध उपस्थिति के अलावा, एक न्यू मैक्सिको CDL आवेदक को निवास प्रमाणित करने के लिए कौन सा दस्तावेज़ सेट प्रस्तुत करना होगा?","options":["न्यू मैक्सिको का पता दर्शाने वाले भौतिक निवास के दो प्रमाण","एक वर्ष से पुराना एक उपयोगिता बिल","एक एकल राज्य-बाहर पट्टा समझौता","किसी भी राज्य का एक मतदाता पंजीकरण कार्ड"],"explanation":"न्यू मैक्सिको को न्यू मैक्सिको का पता दर्शाने वाले भौतिक निवास के दो प्रमाणों की आवश्यकता होती है, साथ ही पहचान, वैध उपस्थिति/U.S. नागरिकता, और एक Social Security नंबर का प्रमाण। स्रोत: NM MVD Driver Manual Chapter 5; NM CDL Acceptable Documents list."},"36":{"q":"एक न्यू मैक्सिको CDL के लिए Social Security Number का दस्तावेज़ीकरण करने हेतु, आवेदक को निम्नलिखित में से क्या प्रदान करना चाहिए?","options":["एक Social Security कार्ड या SSN का वैध प्रमाण","केवल एक पासपोर्ट फोटो पृष्ठ","दो उपयोगिता बिल","अकेले एक जन्म प्रमाणपत्र"],"explanation":"न्यू मैक्सिको को CDL आवेदन दस्तावेज़ों के हिस्से के रूप में (पहचान, वैध उपस्थिति, और दो निवास प्रमाणों के साथ) एक Social Security कार्ड या Social Security Number के अन्य वैध प्रमाण की आवश्यकता होती है। स्रोत: NM MVD Driver Manual Chapter 5; NM CDL Acceptable Documents."},"37":{"q":"प्रत्येक न्यू मैक्सिको CDL ज्ञान (लिखित) परीक्षा में न्यूनतम उत्तीर्ण अंक क्या है?","options":["80%","70%","75%","90%"],"explanation":"प्रत्येक न्यू मैक्सिको CDL ज्ञान परीक्षा पास करने के लिए आवेदक को कम से कम 80% अंक प्राप्त करने होंगे। एक आवेदक सप्ताह में दो बार तक ज्ञान परीक्षा दे सकता है, लेकिन 7-day की अवधि के भीतर दो विफलताओं के बाद प्रणाली तीसरे प्रयास को रोक देती है। स्रोत: NM MVD Driver Manual Chapter 5."},"38":{"q":"पहली बार के आवेदक को कौन सा एंडोर्समेंट न्यू मैक्सिको Commercial Learner Permit (CLP) पर नहीं जोड़ा जा सकता?","options":["H (Hazardous Materials)","N (Tank Vehicle)","P (Passenger)","S (School Bus)"],"explanation":"H (HazMat) एंडोर्समेंट CLP पर प्राप्त नहीं किया जा सकता; इसके लिए एक TSA खतरा आकलन आवश्यक है और इसे केवल पूर्ण CDL पर जोड़ा जाता है। N, P, और S एंडोर्समेंट CLP पर रखे जा सकते हैं (लागू प्रतिबंधों के साथ)। स्रोत: NM MVD Driver Manual Chapter 5; 49 CFR 383.25."},"39":{"q":"न्यू मैक्सिको में, किसी वाणिज्यिक मोटर वाहन (CMV) को संचालित करने वाले चालक के लिए अधिकतम कानूनी रक्त अल्कोहल सांद्रता (BAC) क्या है?","options":["0.08%","0.04%","0.02%","0.00%"],"explanation":"न्यू मैक्सिको संघीय CMV मानक का पालन करता है: 0.04% या उससे अधिक BAC के साथ CMV संचालित करना गैरकानूनी है (गैर-वाणिज्यिक चालकों के लिए 0.08% सीमा का आधा)। स्रोत: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"40":{"q":"न्यू मैक्सिको के निहित सहमति नियम के तहत, CMV संचालित करने वाले CDL धारक के साथ क्या होता है?","options":["उन्हें एक अलग ब्रेथ-टेस्ट परमिट साथ रखना होगा","उन्हें अल्कोहल परीक्षण की सहमति दिए हुए माना जाता है","वे बिना किसी दंड के परीक्षण से इनकार कर सकते हैं","वे केवल तभी सहमति देते हैं जब पहले औपचारिक रूप से गिरफ्तार किया जाए"],"explanation":"NM CDL Manual कहता है कि CMV संचालित करने से, आप 'अल्कोहल परीक्षण की अपनी सहमति दिए हुए माने जाएँगे।' इनकार करने पर किसी प्रमुख अपराध के समान ही अयोग्यता होती है। स्रोत: NM CDL Manual section 1.3.2; NMSA 66-5-68 / Implied Consent Act."},"41":{"q":"न्यू मैक्सिको में, किसी गैर-प्लेकार्डेड CMV में पहले प्रमुख अपराध, जैसे 0.04% BAC उल्लंघन, के लिए चालक कितने समय तक अपना CDL खोएगा?","options":["60 days","120 days","कम से कम 1 वर्ष","कम से कम 3 वर्ष"],"explanation":"न्यू मैक्सिको पहले प्रमुख अपराध (जैसे, 0.04% BAC, DUI, परीक्षण से इनकार, दुर्घटना स्थल छोड़ना) के लिए न्यूनतम एक-वर्ष की CDL अयोग्यता लगाता है। स्रोत: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"42":{"q":"यदि कोई न्यू मैक्सिको CDL धारक खतरनाक सामग्री के लिए प्लेकार्डेड CMV संचालित करते समय पहला प्रमुख अपराध करता है, तो अयोग्यता कितनी लंबी होती है?","options":["कम से कम 1 वर्ष","कम से कम 2 वर्ष","कम से कम 3 वर्ष","आजीवन"],"explanation":"न्यू मैक्सिको पहले-अपराध की अयोग्यता को कम से कम 3 वर्ष तक बढ़ा देता है यदि प्रमुख अपराध खतरनाक सामग्री के लिए प्लेकार्डेड CMV संचालित करते समय होता है। स्रोत: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"43":{"q":"किसी दूसरे प्रमुख अपराध (जैसे CMV में दूसरा DUI) के लिए न्यू मैक्सिको CDL अयोग्यता अवधि क्या है?","options":["3 वर्ष","5 वर्ष","10 वर्ष","आजीवन"],"explanation":"न्यू मैक्सिको दूसरे प्रमुख अपराध पर चालक को आजीवन CDL रखने से अयोग्य घोषित कर देता है। (नियम द्वारा 10 वर्ष बाद पुनर्बहाली संभव हो सकती है, लेकिन अयोग्यता स्वयं एक आजीवन प्रतिबंध है।) स्रोत: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"44":{"q":"न्यू मैक्सिको में, CMV संचालित करते समय रक्त अल्कोहल परीक्षण कराने से इनकार करना निम्नलिखित में से किस रूप में माना जाता है?","options":["एक मामूली कागजी उल्लंघन","एक गंभीर यातायात उल्लंघन (60-day प्रकार)","एक प्रमुख अपराध (1-वर्ष की अयोग्यता)","एक आउट-ऑफ-सर्विस आदेश उल्लंघन"],"explanation":"न्यू मैक्सिको रक्त अल्कोहल परीक्षण कराने से इनकार को एक प्रमुख अपराध मानता है, जो 0.04% BAC दोषसिद्धि के समान ही न्यूनतम एक-वर्ष की CDL अयोग्यता रखता है। स्रोत: NM CDL Manual section 1.3.2; NMSA 66-5-68."},"45":{"q":"एक न्यू मैक्सिको CMV चालक 0.04% से कम पता लगने योग्य अल्कोहल मात्रा दर्ज करता है। तत्काल परिणाम क्या है?","options":["0.04% से कम पर कोई परिणाम नहीं","24 घंटे के लिए आउट-ऑफ-सर्विस किया गया","1-वर्ष की CDL अयोग्यता","60-day की CDL अयोग्यता"],"explanation":"न्यू मैक्सिको 0.04% से कम किसी भी पता लगने योग्य अल्कोहल मात्रा के लिए एक CMV चालक को 24 घंटे के लिए आउट-ऑफ-सर्विस रखता है। 0.04% या उससे अधिक की रीडिंग इसके बजाय एक अयोग्य ठहराने वाला प्रमुख अपराध है। स्रोत: NM CDL Manual section 1.3.2."},"46":{"q":"निम्नलिखित में से किसे न्यू मैक्सिको CDL धारक के लिए एक 'गंभीर यातायात उल्लंघन' के रूप में वर्गीकृत किया गया है?","options":["सीमा से 5 mph अधिक ड्राइविंग","निर्धारित सीमा से 15 mph या उससे अधिक पर अत्यधिक गति","CMV में एक पार्किंग उल्लंघन","एक समाप्त पंजीकरण स्टिकर"],"explanation":"न्यू मैक्सिको अत्यधिक गति (निर्धारित सीमा से 15 mph या उससे अधिक) को लापरवाह ड्राइविंग, अनुचित लेन परिवर्तन, और बहुत करीब से पीछा करने के साथ एक गंभीर यातायात उल्लंघन के रूप में सूचीबद्ध करता है। स्रोत: NM CDL Manual section 1.3.3."},"47":{"q":"निम्नलिखित में से कौन सा CDL धारकों के लिए न्यू मैक्सिको के सूचीबद्ध गंभीर यातायात उल्लंघनों में से एक नहीं है?","options":["लापरवाह ड्राइविंग","किसी वाहन का बहुत करीब से पीछा करना","अनुचित या अनियमित लेन परिवर्तन","जली हुई हेडलाइट के साथ CMV चलाना"],"explanation":"न्यू मैक्सिको की गंभीर-यातायात-उल्लंघन सूची में लापरवाह ड्राइविंग, बहुत करीब से पीछा करना, और अनुचित/अनियमित लेन परिवर्तन शामिल हैं; जली हुई हेडलाइट एक उपकरण समस्या है, सूचीबद्ध गंभीर उल्लंघन नहीं। स्रोत: NM CDL Manual section 1.3.3."},"48":{"q":"न्यू मैक्सिको में, तीन-वर्ष की अवधि के भीतर किसी CMV में दो गंभीर यातायात उल्लंघन करने के लिए चालक कितने समय तक अपना CDL खोएगा?","options":["कम से कम 30 days","कम से कम 60 days","कम से कम 120 days","कम से कम 1 वर्ष"],"explanation":"न्यू मैक्सिको तीन-वर्ष की अवधि के भीतर किसी CMV में किए गए दो गंभीर यातायात उल्लंघनों के लिए CDL धारक को कम से कम 60 days के लिए अयोग्य घोषित करता है। स्रोत: NM CDL Manual section 1.3.3; NMSA 66-5-68."},"49":{"q":"न्यू मैक्सिको में, तीन-वर्ष की अवधि के भीतर किसी CMV में तीन या अधिक गंभीर यातायात उल्लंघन करने के लिए चालक कितने समय तक अपना CDL खोएगा?","options":["60 days","90 days","कम से कम 120 days","कम से कम 1 वर्ष"],"explanation":"न्यू मैक्सिको तीन-वर्ष की अवधि के भीतर किसी CMV में किए गए तीन या अधिक गंभीर यातायात उल्लंघनों के लिए CDL धारक को कम से कम 120 days के लिए अयोग्य घोषित करता है। स्रोत: NM CDL Manual section 1.3.3; NMSA 66-5-68."},"50":{"q":"न्यू मैक्सिको में उचित वर्ग के CDL और/या आवश्यक एंडोर्समेंट के बिना CMV चलाना क्या माना जाता है?","options":["एक गंभीर यातायात उल्लंघन","एक प्रमुख अपराध (1 वर्ष)","एक आउट-ऑफ-सर्विस उल्लंघन","केवल एक चेतावनी, उल्लंघन नहीं"],"explanation":"न्यू मैक्सिको उचित वर्ग के CDL और/या एंडोर्समेंट के बिना (या CDL अपने पास न रखते हुए) CMV चलाने को एक गंभीर यातायात उल्लंघन के रूप में सूचीबद्ध करता है। स्रोत: NM CDL Manual section 1.3.3."},"51":{"q":"किसी चालक के पहले आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए न्यू मैक्सिको में न्यूनतम CDL अयोग्यता क्या है?","options":["कम से कम 30 days","कम से कम 60 days","कम से कम 90 days","कम से कम 1 वर्ष"],"explanation":"न्यू मैक्सिको पहले आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए CDL धारक को कम से कम 90 days के लिए अयोग्य घोषित करता है। स्रोत: NM CDL Manual section 1.3.4; NMSA 66-5-68."},"52":{"q":"न्यू मैक्सिको में, दस-वर्ष की अवधि के भीतर दूसरे आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए CDL अयोग्यता कितनी लंबी होती है?","options":["कम से कम 90 days","कम से कम 1 वर्ष","कम से कम 3 वर्ष","कम से कम 5 वर्ष"],"explanation":"न्यू मैक्सिको दस-वर्ष की अवधि के भीतर दो आउट-ऑफ-सर्विस आदेश उल्लंघनों के लिए CDL धारक को कम से कम 1 वर्ष के लिए अयोग्य घोषित करता है। स्रोत: NM CDL Manual section 1.3.4; NMSA 66-5-68."},"53":{"q":"न्यू मैक्सिको में, दस-वर्ष की अवधि के भीतर तीन या अधिक आउट-ऑफ-सर्विस आदेश उल्लंघनों के लिए न्यूनतम CDL अयोग्यता क्या है?","options":["1 वर्ष","कम से कम 3 वर्ष","5 वर्ष","आजीवन"],"explanation":"न्यू मैक्सिको दस-वर्ष की अवधि के भीतर तीन या अधिक आउट-ऑफ-सर्विस आदेश उल्लंघनों के लिए CDL धारक को कम से कम 3 वर्ष के लिए अयोग्य घोषित करता है। स्रोत: NM CDL Manual section 1.3.4; NMSA 66-5-68."},"54":{"q":"न्यू मैक्सिको में, किसी चालक के पहले रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के लिए न्यूनतम CDL अयोग्यता क्या है?","options":["कम से कम 30 days","कम से कम 60 days","कम से कम 120 days","कम से कम 1 वर्ष"],"explanation":"न्यू मैक्सिको पहले रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के लिए CDL धारक को कम से कम 60 days के लिए अयोग्य घोषित करता है। स्रोत: NM CDL Manual section 1.3.5; NMSA 66-5-68."},"55":{"q":"तीन-वर्ष की अवधि के भीतर तीसरे रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के लिए न्यू मैक्सिको CDL अयोग्यता क्या है?","options":["120 days","180 days","कम से कम 1 वर्ष","3 वर्ष"],"explanation":"न्यू मैक्सिको तीन-वर्ष की अवधि के भीतर तीसरे रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के लिए CDL धारक को कम से कम 1 वर्ष के लिए अयोग्य घोषित करता है (पहले के लिए 60 days, दूसरे के लिए 120 days)। स्रोत: NM CDL Manual section 1.3.5; NMSA 66-5-68."},"56":{"q":"न्यू मैक्सिको/संघीय नियमों के तहत, किसी CMV चालक का CDL ड्राइव करते समय हैंड-हेल्ड मोबाइल फोन का उपयोग करने के लिए कब अयोग्यता के अधीन हो जाता है?","options":["एक एकल पहली दोषसिद्धि के बाद","दो या अधिक दोषसिद्धियों के बाद","केवल एक दोषपूर्ण दुर्घटना के बाद","हैंड-हेल्ड उपयोग कभी अयोग्य नहीं ठहराता"],"explanation":"किसी CMV को संचालित करते समय हैंड-हेल्ड मोबाइल फोन उपयोग के लिए दो या अधिक दोषसिद्धियों के बाद एक न्यू मैक्सिको CDL अयोग्य घोषित किया जाता है: 3 वर्ष के भीतर दूसरे अपराध के लिए 60 days और 3 वर्ष के भीतर तीन या अधिक के लिए 120 days। स्रोत: NM CDL Manual section 2.9.4."},"57":{"q":"हैंड-हेल्ड मोबाइल फोन / टेक्स्टिंग निषेध का उल्लंघन करने पर न्यू मैक्सिको में एक CMV चालक को अधिकतम कितना नागरिक दंड का सामना करना पड़ सकता है?","options":["$750 तक","$2,750 तक","$5,000 तक","$11,000 तक"],"explanation":"न्यू मैक्सिको में लागू संघीय प्रतिबंध के तहत, हैंड-हेल्ड फोन/टेक्स्टिंग निषेध का उल्लंघन करने वाला चालक $2,750 तक के नागरिक दंड के अधीन है; जो नियोक्ता इसकी अनुमति देता है या इसकी मांग करता है, उसे $11,000 तक का सामना करना पड़ता है। स्रोत: NM CDL Manual section 2.9.4."},"58":{"q":"न्यू मैक्सिको में, बिना CDL के वाणिज्यिक मोटर वाहन चलाने या एक से अधिक लाइसेंस रखने के लिए अदालत किसी व्यक्ति पर अधिकतम कितनी राशि तक जुर्माना लगा सकती है?","options":["$1,000 तक","$2,750 तक","$5,000 तक","$11,000 तक"],"explanation":"न्यू मैक्सिको प्रावधान करता है कि अदालत बिना CDL के CMV चलाने या एक से अधिक लाइसेंस रखने के लिए चालक पर $5,000 तक जुर्माना लगा सकती है (या जेल भेज सकती है)। स्रोत: NM CDL Manual sections 1.3.7 and 1.4."},"59":{"q":"न्यू मैक्सिको कानून के तहत, जब कोई स्कूल बस बच्चों को चढ़ाने या उतारने के लिए अपने विशेष स्कूल-बस सिग्नल चालू करके सड़क पर रुकी हो, तो आने वाले चालक को बस से कितनी दूरी पहले रुकना चाहिए?","options":["बस तक पहुँचने से कम से कम 10 फीट पहले","बस तक पहुँचने से कम से कम 25 फीट पहले","बस तक पहुँचने से कम से कम 20 फीट पहले","बस तक पहुँचने से कम से कम 15 फीट पहले"],"explanation":"NMSA 1978, Section 66-7-347(A) के अनुसार, सिग्नल चालू किए हुए रुकी हुई स्कूल बस के पास आने वाले या उसे ओवरटेक करने वाले चालक को वाहन को बस तक पहुँचने से कम से कम दस फीट पहले रोकना होगा और तब तक आगे नहीं बढ़ना होगा जब तक सिग्नल बंद न हो जाएँ, बस आगे न बढ़ जाए, या चालक आगे बढ़ने का संकेत न दे।"},"60":{"q":"न्यू मैक्सिको में, कौन-सी सटीक स्थिति किसी चालक को बच्चों को चढ़ा रही रुकी हुई स्कूल बस के पास से बिना रुके आगे बढ़ने की अनुमति देती है?","options":["चालक की दिशा में दो या अधिक लेन हों","जब पहली बार दिखे तब बस 100 फीट से अधिक दूर हो","स्कूल बस अलग-अलग सड़कों वाले राजमार्ग की किसी भिन्न सड़क पर हो","चालक 25 mph से कम गति से चल रहा हो"],"explanation":"NMSA 1978, Section 66-7-347(C) केवल विभाजित-राजमार्ग का अपवाद प्रदान करता है: अलग-अलग सड़कों वाले राजमार्ग पर चालक को किसी भिन्न सड़क पर मौजूद बस के लिए रुकने की आवश्यकता नहीं है (या नियंत्रित-पहुँच वाले राजमार्ग पर जहाँ बस लोडिंग ज़ोन में हो और पैदल यात्रियों को पार करने की अनुमति न हो)। केवल अतिरिक्त लेन या कम गति रुकने से छूट नहीं देती।"},"61":{"q":"न्यू मैक्सिको राजमार्ग पर, बच्चों को ले जा रही स्कूल बस, किराए पर यात्रियों को ले जा रही बस, या प्लेकार्ड लगे खतरनाक-सामग्री वाहन को रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग से पहले निकटतम रेल से किस दूरी पर रुकना चाहिए?","options":["25 फीट से कम नहीं और 75 फीट से अधिक नहीं","10 फीट से कम नहीं और 40 फीट से अधिक नहीं","15 फीट से कम नहीं और 50 फीट से अधिक नहीं","5 फीट से कम नहीं और 25 फीट से अधिक नहीं"],"explanation":"NMSA 1978, Section 66-7-343(A) के अनुसार इन वाहनों को क्रॉसिंग में प्रवेश करने से पहले निकटतम रेल से 15 फीट से कम नहीं और 50 फीट से अधिक नहीं की दूरी पर रुकना होगा। न्यू मैक्सिको CDL मैनुअल (Sec. 2.15) भी यही 15-से-50-फीट का नियम बताता है।"},"62":{"q":"न्यू मैक्सिको का रेलमार्ग-क्रॉसिंग स्टॉप कानून (66-7-343) कवर किए गए चालक से अपेक्षा करता है कि क्रॉसिंग पर रुकते समय वह वाहन को इतने कम गियर में रखे कि:","options":["यदि ट्रेन आ रही हो तो रिवर्स चुना जा सके","क्रॉसिंग पार करने से पहले गियर बदलने की आवश्यकता न पड़े","दूसरी ओर इंजन ब्रेक लगाया जा सके","वाहन 5% ढलान पर फिर से चालू हो सके"],"explanation":"NMSA 1978, Section 66-7-343(B)(3) के अनुसार इतना कम गियर चुनना आवश्यक है कि क्रॉसिंग से बाहर निकलने से पहले गियर बदलने की आवश्यकता न पड़े, और Subsection (C) क्रॉसिंग में रहते हुए गियर बदलने पर रोक लगाती है। न्यू मैक्सिको CDL मैनुअल दोहराता है: 'रेलमार्ग की पटरियाँ पार करते समय गियर न बदलें।'"},"63":{"q":"इनमें से कौन-सा न्यू मैक्सिको के सूचीबद्ध अपवादों में से नहीं है जो किसी बस या प्लेकार्ड लगे हैज़मैट वाहन को रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग पर रुकने से छूट देते हैं?","options":["ऐसा क्रॉसिंग जहाँ चमकती लाल बत्ती और घंटी सक्रिय हो","ऐसा क्रॉसिंग जहाँ कोई पुलिस अधिकारी यातायात को आगे बढ़ने का निर्देश दे","स्टॉप-एंड-गो ट्रैफ़िक लाइट से नियंत्रित क्रॉसिंग","'exempt crossing' चिह्न से चिह्नित क्रॉसिंग"],"explanation":"NMSA 1978, Section 66-7-343(D) अपवादों की सूची देती है: यातायात निर्देशित करने वाला अधिकारी, स्टॉप-एंड-गो ट्रैफ़िक लाइट, व्यवसाय जिले के भीतर औद्योगिक-स्विचिंग क्रॉसिंग, उस रूप में चिह्नित परित्यक्त क्रॉसिंग, और 'exempt crossing' चिह्न। सक्रिय चमकती-लाल-बत्ती-और-घंटी वाला क्रॉसिंग अपवाद नहीं है; वाहन को फिर भी रुकना होगा।"},"64":{"q":"न्यू मैक्सिको कानून द्वारा ऐसे राजमार्ग पर किसी भी वाहन के लिए तय की गई सामान्य अधिकतम गति सीमा क्या है जहाँ कोई कम सीमा पोस्ट नहीं की गई हो?","options":["65 मील प्रति घंटा","75 मील प्रति घंटा","80 मील प्रति घंटा","70 मील प्रति घंटा"],"explanation":"NMSA 1978, Section 66-7-301(A)(3) सामान्य वैधानिक अधिकतम सीमा पचहत्तर मील प्रति घंटा तय करता है। यह आँकड़ा तब लागू होता है जब कोई कम पोस्ट की गई सीमा या निर्धारित डबल-फाइन ज़ोन न हो।"},"65":{"q":"क्या न्यू मैक्सिको ट्रक ट्रैक्टरों (बड़े ट्रकों) पर कारों की तुलना में कम वैधानिक अधिकतम गति सीमा लगाता है?","options":["हाँ - कानून द्वारा ट्रक 60 mph तक सीमित हैं","नहीं - ट्रकों और कारों पर वही 75 mph वैधानिक अधिकतम सीमा लागू होती है","हाँ - कानून द्वारा रात में ट्रक 55 mph तक सीमित हैं","हाँ - कानून द्वारा ट्रक 65 mph तक सीमित हैं"],"explanation":"न्यू मैक्सिको स्प्लिट-स्पीड-लिमिट वाला राज्य नहीं है। NMSA 1978, Section 66-7-301 की 75 mph अधिकतम सीमा सभी वाहनों पर लागू होती है। 65 mph की ट्रक-ट्रैक्टर सीमा प्रस्तावित करने वाला 2025 का एक विधेयक (SB226) समिति में समाप्त हो गया और कभी कानून नहीं बना, इसलिए कोई ट्रक-विशिष्ट वैधानिक गति सीमा मौजूद नहीं है।"},"66":{"q":"न्यू मैक्सिको कानून के अनुसार, जब बच्चे स्कूल जा रहे हों या स्कूल से लौट रहे हों और स्कूल ज़ोन ठीक से पोस्ट किया गया हो, तब किसी स्कूल के पास से गुजरते समय अधिकतम गति सीमा क्या है?","options":["25 मील प्रति घंटा","20 मील प्रति घंटा","30 मील प्रति घंटा","15 मील प्रति घंटा"],"explanation":"NMSA 1978, Section 66-7-301(A)(1) सभी राजमार्गों पर 15 mph की सीमा तय करता है जब बच्चे स्कूल जा रहे हों या स्कूल से लौट रहे हों और ज़ोन ठीक से पोस्ट किया गया हो, तब किसी स्कूल के पास से गुजरते समय।"},"67":{"q":"पोस्ट की गई किसी सीमा के अभाव में, न्यू मैक्सिको कानून व्यवसाय या आवासीय जिले में गाड़ी चलाने के लिए कौन-सी गति तय करता है?","options":["20 मील प्रति घंटा","35 मील प्रति घंटा","30 मील प्रति घंटा","25 मील प्रति घंटा"],"explanation":"NMSA 1978, Section 66-7-301(A)(2) व्यवसाय या आवासीय जिले में, जहाँ कोई अन्य सीमा पोस्ट नहीं की गई हो, 30 mph की सीमा तय करता है।"},"68":{"q":"1 जुलाई 2023 से प्रभावी, न्यू मैक्सिको का लेन-यात्रा कानून (66-7-376) आम तौर पर बहु-लेन वाली सड़क पर बाईं लेन के उपयोग को किस स्थिति तक सीमित करता है?","options":["केवल सूर्योदय और सूर्यास्त के बीच","केवल प्लेकार्ड लगे हैज़मैट ले जाते समय","केवल किसी अन्य वाहन को ओवरटेक करके पास करते समय","केवल 65 mph से अधिक गति से चलते समय"],"explanation":"NMSA 1978, Section 66-7-376(A)(4), जो SB102 (Laws 2023) द्वारा 1 जुलाई 2023 से प्रभावी हुआ, बाईं लेन में गाड़ी चलाने पर रोक लगाता है सिवाय ओवरटेक करके पास करते समय के, जब तक कि यातायात, प्रवाह, या सड़क की संरचना (जैसे विलय होता यातायात) के लिए बाईं लेन आवश्यक न हो।"},"69":{"q":"66-7-376 में न्यू मैक्सिको का बाईं-लेन प्रतिबंध इनमें से किस स्थान पर लागू नहीं होता?","options":["हर दिशा में तीन लेन वाले किसी भी राज्य राजमार्ग पर","किसी नगरपालिका की शहर सीमा के भीतर, ऐसी सड़क पर जो इंटरस्टेट नहीं है","शहरों के बीच चार-लेन वाले विभाजित U.S. राजमार्ग पर","Interstate 40 के ग्रामीण हिस्से पर"],"explanation":"NMSA 1978, Section 66-7-376(A)(4) स्पष्ट रूप से बताता है कि बाईं-लेन का प्रतिबंध किसी नगरपालिका की शहर सीमा के भीतर या किसी काउंटी सड़क पर लागू नहीं होता, जब तक कि वह सड़क इंटरस्टेट और रक्षा राजमार्गों की राष्ट्रीय प्रणाली का हिस्सा न हो।"},"70":{"q":"न्यू मैक्सिको के लेन-उपयोग कानून के तहत, लेन बदलने वाले चालक को लेन बदलने के इरादे का संकेत यात्रा किए गए अंतिम कितने फीट तक देना चाहिए?","options":["100 फीट","150 फीट","200 फीट","50 फीट"],"explanation":"NMSA 1978, Section 66-7-376(A)(2) के अनुसार किसी लेन से हटने से पहले, चालक को वाहन द्वारा यात्रा किए गए अंतिम एक सौ फीट से कम नहीं की दूरी तक लेन बदलने के इरादे का संकेत देना होगा।"},"71":{"q":"न्यू मैक्सिको दो-तरफा बायाँ-मोड़ लेन को समानांतर दोहरी पीली रेखाओं (भीतरी डैश वाली, बाहरी ठोस) से चिह्नित करता है। बाएँ मोड़ की तैयारी कर रहे या बायाँ मोड़ ले रहे वाहन को उस लेन में कितनी दूरी से अधिक नहीं चलाया जा सकता?","options":["300 फीट","500 फीट","200 फीट","100 फीट"],"explanation":"NMSA 1978, Section 66-7-376(B) प्रावधान करता है कि सड़क से बायाँ मोड़ लेने वाले वाहनों को मोड़ की तैयारी और मोड़ लेते समय दो-तरफा बायाँ-मोड़ लेन में दो सौ फीट से अधिक नहीं चलाया जाएगा।"},"72":{"q":"न्यू मैक्सिको के Move Over कानून के तहत, जब कोई अधिकृत आपातकालीन वाहन चमकती बत्तियों या सायरन के साथ आ रहा हो, तो हर दूसरे वाहन के चालक को:","options":["एक लेन बाईं ओर हटें और गति बनाए रखें","20 mph तक धीमा हों और वर्तमान लेन में बने रहें","स्थिति की परवाह किए बिना वर्तमान लेन में तुरंत रुकें","जितना संभव हो दाहिने किनारे या कर्ब के पास खींचें और उसके गुजरने तक रुकें"],"explanation":"NMSA 1978, Section 66-7-332(A) के अनुसार किसी अधिकृत आपातकालीन वाहन के तत्काल आने पर चालकों को रास्ता देना होगा और तुरंत दाहिने किनारे या कर्ब के समानांतर एवं जितना संभव हो उसके पास, किसी भी चौराहे से दूर, गाड़ी ले जानी होगी और उसके गुजरने तक रुकना होगा, जब तक कि किसी अधिकारी द्वारा अन्यथा निर्देशित न किया जाए।"},"73":{"q":"न्यू मैक्सिको का Move Over कानून चमकती आपातकालीन या हैज़र्ड बत्तियाँ दिखा रहे स्थिर वाहन पर लागू होता है। अधिकृत आपातकालीन वाहनों के अलावा, कौन-से वाहन विशेष रूप से शामिल हैं?","options":["बस स्टॉप पर खड़ी स्कूल बसें","डाक वितरण वाहन","किनारे पर खड़े खेती के उपकरण","रिकवरी या मरम्मत (टो/रेकर) वाहन"],"explanation":"NMSA 1978, Section 66-7-332(B) स्थिर-वाहन के 'हटें और धीमे हों' कर्तव्य को चमकती आपातकालीन या हैज़र्ड बत्तियाँ दिखा रहे स्थिर अधिकृत आपातकालीन वाहन या रिकवरी या मरम्मत वाहन तक विस्तारित करता है।"},"74":{"q":"न्यू मैक्सिको के Move Over कानून के तहत, जब कोई चालक किसी स्थिर आपातकालीन या रिकवरी वाहन के पास पहुँचता है लेकिन निकटवर्ती लेन से हटना उचित रूप से सुरक्षित नहीं है, तो चालक को:","options":["यात्रा लेन में पूरी तरह रुक जाना चाहिए","परिस्थितियों के अनुसार उचित और विवेकपूर्ण गति तक धीमा होना चाहिए, सावधानी से आगे बढ़ना चाहिए, और रुकने के लिए तैयार रहना चाहिए","दृश्य को जल्दी साफ़ करने के लिए तेज़ी से आगे निकल जाना चाहिए","क्षेत्र से होकर पोस्ट की गई गति सीमा पर चलते रहना चाहिए"],"explanation":"NMSA 1978, Section 66-7-332(B)(2) प्रावधान करता है कि यदि स्थिर वाहन के निकटवर्ती न होने वाली लेन में गाड़ी चलाना उचित रूप से सुरक्षित नहीं है, तो चालक परिस्थितियों के अनुसार उचित और विवेकपूर्ण गति तक गति कम करेगा, सावधानी से आगे बढ़ेगा, और रुकने के लिए तैयार रहेगा।"},"75":{"q":"यदि किसी न्यू मैक्सिको वाणिज्यिक वाहन को एकतरफा या विभाजित राजमार्ग पर रुकना पड़े, तो CDL मैनुअल तीन चेतावनी उपकरणों (परावर्तक त्रिकोणों) को कहाँ रखने की अपेक्षा करता है?","options":["केवल वाहन के ठीक पीछे 100 फीट पर","आ रहे यातायात की ओर 10 फीट, 50 फीट, और 150 फीट पर","केवल 100 फीट आगे और 100 फीट पीछे","आ रहे यातायात की ओर 10 फीट, 100 फीट, और 200 फीट पर"],"explanation":"न्यू मैक्सिको CDL मैनुअल (Sec. 2.5) संघीय CMV मानक (49 CFR 392.22) का पालन करता है: एकतरफा या विभाजित राजमार्ग पर, रुकने के 10 मिनट के भीतर, आ रहे यातायात की ओर 10 फीट, 100 फीट, और 200 फीट पर चेतावनी उपकरण रखें।"},"76":{"q":"न्यू मैक्सिको में दो-लेन, दो-तरफा (अविभाजित) सड़क पर, CDL मैनुअल रुके हुए वाणिज्यिक वाहन के चेतावनी त्रिकोणों को कहाँ रखने की अपेक्षा करता है?","options":["वाहन के 10 फीट के भीतर, और वाहन से 100 फीट पीछे एवं 100 फीट आगे","केवल वाहन से 10, 100, और 200 फीट पीछे","केवल 50 फीट पीछे और 50 फीट आगे","केवल 200 फीट पीछे और 200 फीट आगे"],"explanation":"न्यू मैक्सिको CDL मैनुअल (Sec. 2.5) निर्देश देता है कि दोनों दिशाओं में यातायात ले जाने वाली दो-लेन सड़क या अविभाजित राजमार्ग पर, एक उपकरण आगे या पीछे के 10 फीट के भीतर, और एक 100 फीट पीछे तथा एक 100 फीट आगे वाहन से रखें।"},"77":{"q":"न्यू मैक्सिको में, यदि कोई वाणिज्यिक वाहन ऐसी जगह रुका हो जहाँ कोई पहाड़ी, मोड़, या अन्य रुकावट चेतावनी त्रिकोणों को 500 फीट के भीतर दिखने से रोकती हो, तो चालक को:","options":["तीनों त्रिकोण पिछले बंपर के 50 फीट के भीतर रखने चाहिए","सभी त्रिकोण मानक 10, 100, और 200 फीट पर ही छोड़ देने चाहिए","त्रिकोणों के बजाय केवल फोर-वे फ्लैशर का उपयोग करना चाहिए","सबसे पीछे वाले त्रिकोण को रुकावट से आगे, वाहन से 500 फीट तक पीछे ले जाना चाहिए"],"explanation":"न्यू मैक्सिको CDL मैनुअल (Sec. 2.5) निर्देश देता है कि यदि कोई पहाड़ी, मोड़, या रुकावट 500 फीट के भीतर दृष्टि-रेखा को रोकती है, तो सबसे पीछे वाले त्रिकोण को सड़क पर पीछे, 500 फीट तक ले जाना चाहिए ताकि अन्य चालकों को चेतावनी मिले। NMSA 1978, Section 66-3-853 भी इसी प्रकार ऐसी रुकावटों के पास 100 से 500 फीट दूर रखने की अपेक्षा करता है।"},"78":{"q":"न्यू मैक्सिको कानून 66-3-849 बसों और बड़े ट्रकों से कौन-से आपातकालीन चेतावनी उपकरणों का सेट साथ रखने की अपेक्षा करता है?","options":["तीन लाल आपातकालीन परावर्तक (या फ्लेयर/फ्यूज़ी) साथ ही दो लाल कपड़े के झंडे","एक अकेली लाल लालटेन और एक झंडा","केवल दो एम्बर स्ट्रोब और एक अग्निशामक यंत्र","चार नारंगी शंकु और एक परावर्तक बनियान"],"explanation":"NMSA 1978, Section 66-3-849 के अनुसार कवर किए गए वाहनों (बसें, ट्रक, ट्रक ट्रैक्टर, आदि) को चेतावनी उपकरण साथ रखने होंगे जैसे तीन लाल आपातकालीन परावर्तक, दो लाल कपड़े के झंडे, और तीन फ्यूज़ी (या समकक्ष फ्लेयर/लालटेन)। न्यू मैक्सिको CDL मैनुअल भी आवश्यक खड़े-वाहन चेतावनी उपकरणों के रूप में तीन परावर्तक त्रिकोण, छह फ्यूज़ी, या तीन तरल-दहन फ्लेयर सूचीबद्ध करता है।"},"79":{"q":"न्यू मैक्सिको में कौन-सी राज्य एजेंसी वाणिज्यिक चालक लाइसेंस (CDL) जारी करती है?","options":["Motor Vehicle Division (MVD)","New Mexico Department of Transportation (NMDOT)","State Police का Commercial Vehicle Bureau","Public Regulation Commission (PRC)"],"explanation":"न्यू मैक्सिको में, CDL Motor Vehicle Division (MVD) द्वारा जारी किए जाते हैं, जो Taxation and Revenue Department का हिस्सा है। NMDOT सड़कों और ओवरसाइज़/ओवरवेट परमिट को संभालता है, चालक लाइसेंसिंग को नहीं। स्रोत: MVD New Mexico, Commercial Driver's Licenses (CDL) पेज और Chapter 5: Commercial Driver License।"},"80":{"q":"न्यू मैक्सिको CDL के लिए आवेदन करते समय, आवेदकों को कितनी चालक श्रेणियों में से किसी एक में स्वयं-प्रमाणन करना होगा?","options":["चार श्रेणियाँ","दो श्रेणियाँ","तीन श्रेणियाँ","छह श्रेणियाँ"],"explanation":"न्यू मैक्सिको CDL आवेदकों को चार श्रेणियों में से किसी एक में स्वयं-प्रमाणन करना होगा जो उस प्रकार के वाणिज्य का वर्णन करती है जिसमें वे संचालन की अपेक्षा करते हैं: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), और Excepted Intrastate (EA)। स्रोत: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.71।"},"81":{"q":"ऐसा न्यू मैक्सिको CDL चालक जो राज्य की सीमाओं के पार संचालन करता है और संघीय शारीरिक-योग्यता नियमों से छूट प्राप्त नहीं है, उसे किस श्रेणी में स्वयं-प्रमाणन करना होगा?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"अंतरराज्यीय वाणिज्य में संचालन करने वाला चालक जिसे संघीय DOT चिकित्सा मानकों को पूरा करना आवश्यक है, वह Non-Excepted Interstate (NI) के रूप में स्वयं-प्रमाणन करता है और उसे MVD के पास एक वर्तमान Medical Examiner's Certificate फ़ाइल में रखना होगा। स्रोत: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.71।"},"82":{"q":"न्यू मैक्सिको CDL Medical Examiner's Certificate के लिए शारीरिक परीक्षण करने के लिए कौन अधिकृत है?","options":["National Registry of Certified Medical Examiners पर सूचीबद्ध कोई चिकित्सा पेशेवर","न्यू मैक्सिको में कोई भी लाइसेंस प्राप्त चिकित्सक","किसी भी अर्जेंट-केयर क्लिनिक का नर्स प्रैक्टिशनर","MVD फ़ील्ड कार्यालय का चिकित्सा अधिकारी"],"explanation":"न्यू मैक्सिको में सभी Commercial Driver Medical Certifications किसी ऐसे चिकित्सा पेशेवर द्वारा पूरे किए जाने चाहिए जो FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध हो। अकेले एक सामान्य चिकित्सा लाइसेंस पर्याप्त नहीं है। स्रोत: MVD New Mexico, Commercial Driver's Licenses (CDL) पेज; FMCSA National Registry।"},"83":{"q":"कोई न्यू मैक्सिको CDL धारक DOT Medical Examiner's Certificate को राज्य के रिकॉर्ड में कैसे दर्ज कराता है?","options":["प्रमाणपत्र की एक प्रति MVD को जमा करके, जो चिकित्सा स्थिति को ड्राइविंग रिकॉर्ड पर पोस्ट करता है","इसे सीधे वॉशिंगटन, डी.सी. में FMCSA को डाक से भेजकर","केवल मूल कार्ड वाहन में रखकर; MVD को कोई प्रति नहीं दी जाती","इसे New Mexico Department of Health के पास दाखिल करके"],"explanation":"न्यू मैक्सिको CDL धारकों को MVD (State Driver Licensing Agency) को अपने Medical Examiner's Certificate की एक प्रति देनी होगी; इसके बाद MVD चिकित्सा प्रमाणन स्थिति को वाणिज्यिक ड्राइविंग रिकॉर्ड (CDLIS) पर पोस्ट करता है। अकेले वाहन में रखा गया कार्ड राज्य की फाइलिंग आवश्यकता को पूरा नहीं करता। स्रोत: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.71(h)।"},"84":{"q":"CDL के लिए परीक्षण से पहले, पहली बार आवेदन करने वाले न्यू मैक्सिको आवेदक को आम तौर पर कौन-सा संघीय रूप से आवश्यक प्रशिक्षण पूरा करना होगा?","options":["FMCSA Training Provider Registry पर मौजूद किसी प्रदाता से Entry-Level Driver Training (ELDT)","40 घंटे का OSHA वाणिज्यिक वाहन सुरक्षा पाठ्यक्रम","एक न्यू मैक्सिको रक्षात्मक-ड्राइविंग कक्षा पाठ्यक्रम","किसी लाइसेंस प्राप्त वाहक के साथ कम से कम 90 दिनों की अप्रेंटिसशिप"],"explanation":"पहली बार CDL आवेदकों (और कुछ अपग्रेड/एंडोर्समेंट) को कौशल या ज्ञान परीक्षण देने से पहले FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता के माध्यम से Entry-Level Driver Training (ELDT) पूरा करना होगा। यह नियम 7 फरवरी 2022 को या उसके बाद आवेदन करने वालों पर लागू होता है। स्रोत: MVD New Mexico Chapter 5; FMCSA ELDT rule, 49 CFR Part 380।"},"85":{"q":"न्यू मैक्सिको Commercial Learner's Permit (CLP) की प्रारंभिक जारी होने के कितने समय बाद धारक को CDL कौशल परीक्षण देने के योग्य होने से पहले प्रतीक्षा करनी होगी?","options":["कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 10 दिन","कम से कम 60 दिन"],"explanation":"CLP धारक CLP की प्रारंभिक जारी होने के कम से कम 14 दिन बाद तक CDL कौशल परीक्षण देने के योग्य नहीं होता। यह संघीय न्यूनतम न्यू मैक्सिको MVD द्वारा लागू किया जाता है। स्रोत: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.25(a)(3)।"},"86":{"q":"न्यू मैक्सिको Commercial Learner's Permit (CLP) कितने समय के लिए वैध होता है?","options":["1 वर्ष (बिना पुनः परीक्षण के एक नवीनीकरण की अनुमति के साथ)","90 दिन","6 महीने","2 वर्ष"],"explanation":"न्यू मैक्सिको CLP 1 वर्ष के लिए जारी किया जाता है। संघीय मानक के तहत इसे उस अवधि के भीतर सामान्य ज्ञान परीक्षण दोबारा दिए बिना एक बार नवीनीकृत किया जा सकता है। स्रोत: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.25(c)।"},"87":{"q":"न्यू मैक्सिको CDL कौशल परीक्षण कितने भागों से मिलकर बनता है, और वे क्या हैं?","options":["तीन भाग: प्री-ट्रिप वाहन निरीक्षण, बुनियादी वाहन नियंत्रण, और ऑन-रोड ड्राइविंग","दो भाग: एक लिखित परीक्षा और एक ऑन-रोड ड्राइव","तीन भाग: एयर-ब्रेक परीक्षण, बैकिंग परीक्षण, और रात्रि ड्राइविंग","चार भाग: निरीक्षण, बैकिंग, हाईवे, और पैरेलल पार्किंग"],"explanation":"CDL कौशल परीक्षण के तीन भाग होते हैं जिन्हें क्रम से पास करना होता है: प्री-ट्रिप वाहन निरीक्षण, बुनियादी वाहन नियंत्रण (कम-गति की युक्तियाँ), और ऑन-रोड ड्राइविंग परीक्षण। स्रोत: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.113।"},"88":{"q":"न्यू मैक्सिको CDL ज्ञान (लिखित) परीक्षणों पर न्यूनतम उत्तीर्णांक क्या है?","options":["80 प्रतिशत","70 प्रतिशत","75 प्रतिशत","90 प्रतिशत"],"explanation":"न्यू मैक्सिको CDL ज्ञान परीक्षण कम से कम 80 प्रतिशत के स्कोर के साथ पास किए जाने चाहिए, जो संघीय मानक के अनुरूप है। स्रोत: MVD New Mexico Chapter 5; FMCSA 49 CFR 383.135।"},"89":{"q":"न्यू मैक्सिको CDL के लिए आवेदन करने से पहले किसी व्यक्ति के पास पहले से कौन-सी पूर्व-शर्त होनी चाहिए?","options":["एक वैध New Mexico Class D (नियमित) चालक लाइसेंस या एक वैध आउट-ऑफ-स्टेट CDL","किसी भी राज्य में प्राप्त किया गया यात्री (P) एंडोर्समेंट","TSA से एक संघीय हैज़मैट क्लीयरेंस","किसी न्यू मैक्सिको लाइसेंस पर मोटरसाइकिल एंडोर्समेंट"],"explanation":"न्यू मैक्सिको CDL के लिए आवेदन करने हेतु आपके पास पहले से एक वैध गैर-वाणिज्यिक (Class D) न्यू मैक्सिको चालक लाइसेंस या एक वैध आउट-ऑफ-स्टेट CDL होना चाहिए। स्रोत: MVD New Mexico, न्यू मैक्सिको CDL प्राप्त करने की आवश्यकताएँ।"},"90":{"q":"न्यू मैक्सिको MVD नियमों के तहत, किसी CDL आवेदक को न्यू मैक्सिको में भौतिक निवास के कितने प्रमाण प्रस्तुत करने होंगे?","options":["भौतिक निवास के दो प्रमाण","भौतिक निवास का एक प्रमाण","भौतिक निवास के तीन प्रमाण","किसी निवास प्रमाण की आवश्यकता नहीं है"],"explanation":"न्यू मैक्सिको CDL आवेदक को राज्य में भौतिक निवास के दो प्रमाण प्रस्तुत करने होंगे। प्रमाण के रूप में उपयोग किए जाने वाले मासिक दस्तावेज़ जैसे उपयोगिता बिल या बैंक विवरण आवेदन के 60 दिनों के भीतर के होने चाहिए। स्रोत: MVD New Mexico, Commercial Driver's Licenses (CDL) पेज।"},"91":{"q":"न्यू मैक्सिको CDL के लिए कौन-से नवीनीकरण चक्र विकल्प प्रदान करता है?","options":["एक 4-वर्षीय या एक 8-वर्षीय क्रेडेंशियल","एक 1-वर्षीय या एक 5-वर्षीय क्रेडेंशियल","केवल एक 5-वर्षीय क्रेडेंशियल","एक 2-वर्षीय या एक 6-वर्षीय क्रेडेंशियल"],"explanation":"न्यू मैक्सिको CDL को 4-वर्षीय या 8-वर्षीय नवीनीकरण चक्र पर प्रदान करता है। स्रोत: MVD New Mexico FAQ और Chapter 5।"},"92":{"q":"किसी न्यू मैक्सिको CDL धारक को 8-वर्षीय के बजाय 4-वर्षीय क्रेडेंशियल तक क्यों सीमित किया जा सकता है?","options":["क्योंकि उनके पास Hazardous Materials (Hazmat) एंडोर्समेंट है","क्योंकि उनके पास यात्री (P) एंडोर्समेंट है","क्योंकि वे केवल अंतःराज्यीय गाड़ी चलाते हैं","क्योंकि वे 30 वर्ष से कम उम्र के हैं"],"explanation":"Hazardous Materials (Hazmat) एंडोर्समेंट रखने वाले चालक 8-वर्षीय CDL प्राप्त नहीं कर सकते; Hazmat से जुड़ी आवधिक TSA पृष्ठभूमि जाँच उन्हें 4-वर्षीय चक्र तक सीमित करती है। स्रोत: MVD New Mexico FAQ; TSA/FMCSA Hazmat एंडोर्समेंट नियम।"},"93":{"q":"पुनः परीक्षण के संबंध में न्यू मैक्सिको CDL ज्ञान परीक्षण कैसे निर्धारित किए जाते हैं?","options":["आवेदक CDL लिखित परीक्षण सप्ताह में दो बार तक दे सकते हैं","आवेदक लिखित परीक्षण हर 30 दिन में केवल एक बार दे सकते हैं","आवेदकों को असीमित उसी-दिन पुनः परीक्षण मिलते हैं","आवेदक लिखित परीक्षण प्रति कैलेंडर वर्ष में केवल एक बार दे सकते हैं"],"explanation":"न्यू मैक्सिको CDL आवेदकों को CDL लिखित (ज्ञान) परीक्षण प्रति सप्ताह दो बार तक देने की अनुमति देता है। स्रोत: MVD New Mexico, Commercial Driver's Licenses (CDL) पेज।"},"94":{"q":"केवल अंतःराज्यीय (राज्य के भीतर) ड्राइविंग तक सीमित न्यू मैक्सिको CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["18 वर्ष","16 वर्ष","21 वर्ष","19 वर्ष"],"explanation":"कोई व्यक्ति 18 वर्ष की आयु में अंतःराज्यीय ड्राइविंग के लिए न्यू मैक्सिको CDL प्राप्त कर सकता है; 18-20 आयु का आवेदक राज्य के भीतर संचालन तक सीमित होता है। अंतरराज्यीय वाणिज्य में संचालन के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: MVD New Mexico Chapter 5; FMCSA 49 CFR 391.11।"},"95":{"q":"जब कोई चालक एक वैध आउट-ऑफ-स्टेट CDL को उसी क्लास और एंडोर्समेंट के न्यू मैक्सिको CDL के बदले में विनिमय करता है, तो आम तौर पर कौन-सा परीक्षण आवश्यक होता है?","options":["समतुल्य क्लास और एंडोर्समेंट के लिए किसी लिखित परीक्षण की आवश्यकता नहीं है","लिखित और कौशल दोनों परीक्षण दोबारा देने होंगे","केवल ऑन-रोड कौशल परीक्षण दोबारा देना होगा","केवल प्री-ट्रिप निरीक्षण दोहराना होगा"],"explanation":"न्यू मैक्सिको एक वैध आउट-ऑफ-स्टेट CDL को उसी क्लास और एंडोर्समेंट के न्यू मैक्सिको CDL के बदले विनिमय करने के लिए लिखित परीक्षण आवश्यक नहीं करता। (Hazmat एंडोर्समेंट के लिए अब भी अपना परीक्षण और TSA पृष्ठभूमि जाँच आवश्यक है।) स्रोत: MVD New Mexico, न्यू मैक्सिको CDL प्राप्त करने की आवश्यकताएँ।"},"96":{"q":"एक लिखित ज्ञान परीक्षण के अलावा, Hazardous Materials (Hazmat) एंडोर्समेंट चाहने वाले न्यू मैक्सिको CDL आवेदक को और क्या पूरा करना होगा?","options":["फ़िंगरप्रिंटिंग और एक TSA security threat assessment (पृष्ठभूमि जाँच)","एक अलग ऑन-रोड रात्रि ड्राइविंग परीक्षण","एक 10-दिवसीय रक्षात्मक ड्राइविंग पाठ्यक्रम","किसी राज्य-संचालित क्लिनिक में एक नेत्र परीक्षण"],"explanation":"Hazmat एंडोर्समेंट चाहने वाले न्यू मैक्सिको चालक को एंडोर्समेंट दिए जाने से पहले Hazmat ज्ञान परीक्षण पास करना होगा और एक TSA security threat assessment (पृष्ठभूमि जाँच) के लिए फ़िंगरप्रिंट कराने होंगे। स्रोत: MVD New Mexico, न्यू मैक्सिको CDL प्राप्त करने की आवश्यकताएँ; TSA Hazmat Endorsement Threat Assessment Program।"},"97":{"q":"जब कोई न्यू मैक्सिको CDL आवेदक कौशल परीक्षण पास करने के बाद CDL प्राप्त करने के लिए MVD वापस जाता है, तो परीक्षण परिणाम आम तौर पर किस रूप में दिए जाते हैं?","options":["एक सीलबंद लिफ़ाफ़ा जिसमें कौशल परीक्षण के अंक होते हैं, जो CLP और आवश्यक दस्तावेज़ों के साथ प्रस्तुत किया जाता है","परीक्षक द्वारा सीधे FMCSA को भेजा गया एक ईमेल","केवल परीक्षक के पर्यवेक्षक को दी गई एक मौखिक रिपोर्ट","रोड टेस्ट वाहन के पंजीकरण के पीछे छपा एक स्कोर"],"explanation":"किसी अनुमोदित CDL परीक्षक द्वारा संचालित कौशल परीक्षण पास करने के बाद, आवेदक CDL जारी कराने के लिए अपने चालक लाइसेंस, CLP, और कौशल परीक्षण के अंक वाले एक सीलबंद लिफ़ाफ़े के साथ MVD वापस जाता है। स्रोत: MVD New Mexico, न्यू मैक्सिको CDL प्राप्त करने की आवश्यकताएँ।"}},"ar":{"0":{"q":"على طرق ولاية نيومكسيكو السريعة، ما هو الحد الأقصى القانوني لعرض المركبة التجارية أو حمولتها (باستثناء المرايا وبعض أجهزة السلامة) من دون تصريح للحجم الزائد؟","options":["8 أقدام و6 بوصات (102 inches)","8 أقدام (96 inches)","9 أقدام (108 inches)","10 أقدام (120 inches)"],"explanation":"تحدّ ولاية نيومكسيكو إجمالي العرض الخارجي للمركبة أو الحمولة بـ 8 أقدام و6 بوصات (102 inches)، باستثناء المرايا وأجهزة السلامة المعتمدة. وتتطلب الحمولة الأعرض من ذلك تصريحاً للحجم الزائد. المصدر: NMSA 1978, Section 66-7-402 (عرض المركبات)؛ NM CDL Manual."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة وحمولتها على طرق نيومكسيكو السريعة من دون تصريح؟","options":["14 feet","13 feet 6 inches","15 feet","13 feet"],"explanation":"تحدد ولاية نيومكسيكو الحد الأقصى لارتفاع المركبة والحمولة بـ 14 feet. وتتطلب الحمولات التي يزيد ارتفاعها عن 14 feet تصريحاً للحجم الزائد (الارتفاع الزائد). المصدر: NMSA 1978, Section 66-7-404 (ارتفاع وطول المركبات والحمولات)."},"2":{"q":"ما هو الحد الأقصى للوزن الإجمالي على أي محور مفرد واحد لمركبة تجارية بموجب قانون نيومكسيكو؟","options":["21,600 pounds","20,000 pounds","22,400 pounds","18,000 pounds"],"explanation":"يبلغ حد المحور المفرد في نيومكسيكو 21,600 pounds، وهو أعلى من حد المحور المفرد الفيدرالي على الطرق السريعة بين الولايات البالغ 20,000 pounds. المصدر: NMSA 1978, Section 66-7-409 (حدود الحمل على المحاور المفردة والعجلات والإطارات)."},"3":{"q":"بموجب قانون نيومكسيكو، ما هو الوزن الأقصى المسموح به على مجموعة محاور مزدوجة (محوران تفصل بينهما مسافة 4 feet)؟","options":["34,320 pounds","34,000 pounds","36,000 pounds","32,000 pounds"],"explanation":"يسمح جدول أوزان مجموعات المحاور في نيومكسيكو بـ 34,320 pounds على المحور المزدوج (محوران تفصل بينهما نحو 4 feet)، وهو أعلى قليلاً من الحد الفيدرالي للمحور المزدوج على الطرق السريعة بين الولايات البالغ 34,000 pounds. المصدر: NMSA 1978, Section 66-7-410 (الوزن الإجمالي للمركبات والحمولات)."},"4":{"q":"ما هو الطول الإجمالي الأقصى لتركيبة شاحنة ومقطورة على طرق نيومكسيكو السريعة من دون تصريح؟","options":["65 feet","60 feet","70 feet","75 feet"],"explanation":"تحدّ ولاية نيومكسيكو الطول الإجمالي للتركيبة (الشاحنة مع المقطورة) بـ 65 feet على الطرق السريعة عموماً؛ وتتطلب التركيبات الأطول تصريحاً للحجم الزائد. المصدر: NMSA 1978, Section 66-7-404 (ارتفاع وطول المركبات والحمولات)."},"5":{"q":"على نظام الطرق السريعة بين الولايات (الممولة فيدرالياً) في نيومكسيكو، ما هو الحد الأقصى للوزن الإجمالي للمركبة المسموح به من دون تصريح للوزن الزائد؟","options":["80,000 pounds","86,400 pounds","84,000 pounds","90,000 pounds"],"explanation":"على نظام الطرق السريعة بين الولايات، تطبق نيومكسيكو السقف الفيدرالي البالغ 80,000 pounds للوزن الإجمالي. ويسمح الجدول القانوني الخاص بالولاية بقدر أكبر إلى حدٍ ما على بعض الطرق السريعة غير الفيدرالية بين الولايات، لكن 80,000 pounds هو الحد الأقصى على الطرق بين الولايات من دون تصريح. المصدر: 23 U.S.C. 127 كما هو مطبق في نيومكسيكو؛ NMSA 1978, Section 66-7-410."},"6":{"q":"بموجب جدول الوزن الإجمالي القانوني في نيومكسيكو، ما هو الحد الأقصى للوزن الإجمالي المسموح به (مع تباعد كافٍ للمحاور يبلغ نحو 56 feet أو أكثر) على طريق سريعة في الولاية من غير الطرق بين الولايات من دون تصريح خاص؟","options":["86,400 pounds","80,000 pounds","94,000 pounds","84,000 pounds"],"explanation":"يصل جدول الوزن الإجمالي في نيومكسيكو إلى حد أقصى قدره 86,400 pounds عندما تكون المسافة بين المحورين الأول والأخير نحو 56 feet أو أكثر على الطرق السريعة في الولاية من غير الطرق بين الولايات. ويبقى نظام الطرق بين الولايات محدوداً بالسقف الفيدرالي البالغ 80,000 pounds. المصدر: NMSA 1978, Section 66-7-410 (الوزن الإجمالي للمركبات والحمولات)."},"7":{"q":"ما هو الطول الأقصى لنصف المقطورة العاملة على طرق نيومكسيكو السريعة المحددة (الشبكة الوطنية) من دون تصريح؟","options":["57 feet 6 inches","53 feet","48 feet","60 feet"],"explanation":"تسمح ولاية نيومكسيكو بنصف مقطورة يصل طولها إلى 57 feet 6 inches على مسارات الشبكة الوطنية المحددة. المصدر: NMSA 1978, Section 66-7-404 (ارتفاع وطول المركبات والحمولات)؛ NM CDL Manual."},"8":{"q":"في نيومكسيكو، أي معادلة تُستخدم على نظام الطرق بين الولايات لتحديد الحد الأقصى للوزن الإجمالي المسموح به على مجموعة من المحاور المتتالية؟","options":["معادلة الجسر الفيدرالية (The Federal Bridge Formula)","قاعدة صافي الحمولة (The Net-Tonnage Rule)","حاصل تباعد المحاور (The Axle-Spacing Quotient)","نسبة التركيبة الإجمالية (The Gross-Combination Ratio)"],"explanation":"على نظام الطرق بين الولايات، تطبق نيومكسيكو معادلة الجسر الفيدرالية (Federal Bridge Formula): W = 500[(LN/(N-1)) + 12N + 36]، التي تحدّ الوزن على أي مجموعة من المحاور بناءً على المسافة بينها (L) وعددها (N). المصدر: 23 U.S.C. 127 / FBF كما هي مطبقة في نيومكسيكو؛ NM CDL Manual."},"9":{"q":"من الذي يصدر تصاريح الحجم الزائد/الوزن الزائد للمركبات التجارية العاملة على الطرق السريعة في ولاية نيومكسيكو؟","options":["وزارة النقل في ولاية نيومكسيكو (NMDOT)","مكتب مأمور المقاطعة (شريف المقاطعة)","الإدارة الفيدرالية لسلامة ناقلي البضائع بالشاحنات (FMCSA)","قسم الأشغال العامة في المدينة المحلية"],"explanation":"تُصدِر تصاريح الحجم الزائد والوزن الزائد في نيومكسيكو وزارة النقل في ولاية نيومكسيكو (NMDOT)، وتُدار من خلال وحدة منافذ الدخول / إصدار التصاريح ونظام التصاريح الإلكتروني التابع لها. المصدر: NMDOT Permits / Ports of Entry؛ NMSA 1978, Section 66-7-413."},"10":{"q":"يحتاج ناقل إلى نقل حمولة مفردة غير قابلة للتجزئة تتجاوز حدود الوزن القانونية في نيومكسيكو. ما الذي يجب على الناقل الحصول عليه قبل الرحلة؟","options":["تصريح وزن زائد (خاص) من NMDOT","مصادقة جديدة على CDL","إعفاء فيدرالي للطرق بين الولايات من FMCSA","إثبات تأمين على الحمولة فقط"],"explanation":"يتطلب نقل حمولة تتجاوز حدود الحجم أو الوزن القانونية في نيومكسيكو تصريحاً خاصاً (للحجم الزائد/الوزن الزائد) من NMDOT، وعادةً للحمولات غير القابلة للتجزئة. المصدر: NMSA 1978, Section 66-7-413؛ NMDOT Permits."},"11":{"q":"بموجب قواعد المحور المفرد في نيومكسيكو، ما هو الوزن الأقصى المسموح به على أي عجلة مفردة؟","options":["11,000 pounds","10,000 pounds","12,500 pounds","9,000 pounds"],"explanation":"تحدّ ولاية نيومكسيكو الحمل على أي عجلة مفردة بـ 11,000 pounds، كجزء من قواعدها لحدود الحمل على المحور المفرد والعجلة والإطار. المصدر: NMSA 1978, Section 66-7-409 (حدود الحمل على المحاور المفردة والعجلات والإطارات)."},"12":{"q":"تحدّ قاعدة حمل الإطارات في نيومكسيكو الوزن إلى كم لكل بوصة من عرض الإطار؟","options":["600 pounds لكل بوصة من عرض الإطار","500 pounds لكل بوصة من عرض الإطار","800 pounds لكل بوصة من عرض الإطار","1,000 pounds لكل بوصة من عرض الإطار"],"explanation":"تحدّ ولاية نيومكسيكو تحميل الإطارات إلى 600 pounds لكل بوصة من عرض الإطار كجزء من حدود الحمل على المحور والعجلة والإطار. المصدر: NMSA 1978, Section 66-7-409 (حدود الحمل على المحاور المفردة والعجلات والإطارات)."},"13":{"q":"يُصدَر تصريح الحجم الزائد/الوزن الزائد في نيومكسيكو في الغالب لأي من المدد التالية؟","options":["لرحلة واحدة أو لفترة سنوية","لرحلة واحدة فقط، وليس لأطول من ذلك أبداً","بحد أقصى 30 days فقط","بشكل دائم، بلا انتهاء صلاحية"],"explanation":"تُصدَر تصاريح الحجم الزائد/الوزن الزائد في نيومكسيكو عادةً إما كتصاريح لرحلة واحدة أو كتصاريح سنوية، حسب طبيعة النقل. المصدر: NMDOT Permits / Ports of Entry؛ NMSA 1978, Section 66-7-413."},"14":{"q":"بموجب معادلة الجسر الفيدرالية كما هي مطبقة على الطرق بين الولايات في نيومكسيكو، ماذا يمثل المتغيران L وN؟","options":["L = المسافة بالأقدام بين المحورين الخارجيين لمجموعة؛ N = عدد المحاور في المجموعة","L = الحمل بالأرطال؛ N = عدد الإطارات","L = طول المقطورة؛ N = الوزن الصافي بالأطنان","L = الحد القانوني؛ N = عدد التصاريح المملوكة"],"explanation":"في معادلة الجسر الفيدرالية، L هي المسافة بالأقدام بين الطرفين (المحورين الأول والأخير) لأي مجموعة من محورين متتاليين أو أكثر، وN هي عدد المحاور في تلك المجموعة. المصدر: 23 U.S.C. 127 / FBF كما هي مطبقة في نيومكسيكو؛ NM CDL Manual."},"15":{"q":"تبلغ حمولة نصف مقطورة عرضاً قدره 8 feet 8 inches. ما المطلوب لنقلها بشكل قانوني على طرق نيومكسيكو السريعة؟","options":["تصريح حجم زائد (عرض زائد) من NMDOT","لا شيء؛ فهي ضمن العرض القانوني","علم حمولة عريضة فقط، دون تصريح","تغيير إلى CDL من الفئة Class A"],"explanation":"الحد القانوني للعرض في نيومكسيكو هو 8 feet 6 inches؛ وعند 8 feet 8 inches تتجاوز الحمولة هذا الحد، لذا يلزم تصريح حجم زائد (عرض زائد) من NMDOT. المصدر: NMSA 1978, Section 66-7-402؛ NMDOT Permits."},"16":{"q":"عند تجاوز حدود العرض أو الطول، قد تتطلب نيومكسيكو مركبات مرافِقة (مركبات إرشاد). فوق أي عرض تتطلب نيومكسيكو عموماً مركبات مرافِقة لحمولة متحركة؟","options":["أكثر من 14 feet عرضاً","أكثر من 10 feet عرضاً","أكثر من 8 feet 6 inches عرضاً","أكثر من 20 feet عرضاً"],"explanation":"تتطلب نيومكسيكو عموماً مركبات مرافِقة/إرشاد للحمولات التي يتجاوز عرضها 14 feet (وللحمولات التي يتجاوز طولها نحو 90 feet). المصدر: متطلبات حركة تصاريح الحجم الزائد لدى NMDOT."},"17":{"q":"كيف يتقدم الناقل في الغالب اليوم بطلب الحصول على تصريح حجم زائد/وزن زائد في نيومكسيكو؟","options":["من خلال نظام التصاريح الإلكتروني التابع لـ NMDOT","بإرسال نموذج ورقي بالبريد إلى مكتب الحاكم","بالاتصال بـ FMCSA في واشنطن العاصمة","شخصياً فقط في محكمة المقاطعة"],"explanation":"تُستخرَج تصاريح الحجم الزائد/الوزن الزائد في نيومكسيكو بشكل رئيسي من خلال نظام التصاريح الإلكتروني التابع لـ NMDOT، حيث يُدخل الناقلون أبعاد الحمولة ووزنها والمسار وتواريخ السفر. المصدر: NMDOT Permits / Ports of Entry."},"18":{"q":"تختلف أرقام الوزن الإجمالي في نيومكسيكو عن المعيار الفيدرالي للطرق بين الولايات. بالمقارنة مع حد المحور المفرد الفيدرالي للطرق بين الولايات البالغ 20,000 pounds، فإن حد المحور المفرد القانوني في نيومكسيكو هو:","options":["أعلى، عند 21,600 pounds","أدنى، عند 18,000 pounds","مطابق، عند 20,000 pounds","أعلى، عند 25,000 pounds"],"explanation":"حد المحور المفرد القانوني في نيومكسيكو هو 21,600 pounds، وهو أعلى من حد المحور المفرد الفيدرالي للطرق بين الولايات البالغ 20,000 pounds. ويبقى الرقم الفيدرالي الأدنى هو الحاكم على نظام الطرق بين الولايات نفسه. المصدر: NMSA 1978, Section 66-7-409؛ 23 U.S.C. 127."},"19":{"q":"في نيومكسيكو، يلزم CDL من الفئة Class A لتشغيل أي تركيبة من المركبات ذات تصنيف وزن تركيبة إجمالي (GCWR) لا يقل عن أي قيمة، عندما تتجاوز الوحدة/الوحدات المقطورة 10,000 lbs من تصنيف GVWR؟","options":["26,001 رطلاً أو أكثر","10,001 رطلاً أو أكثر","18,001 رطلاً أو أكثر","33,001 رطلاً أو أكثر"],"explanation":"يخوّل CDL من الفئة Class A في نيومكسيكو قيادة أي تركيبة من المركبات ذات GCWR قدره 26,001 رطلاً أو أكثر، شريطة أن يتجاوز تصنيف GVWR للوحدة/الوحدات المقطورة 10,000 pounds. المصدر: NM MVD Driver Manual Chapter 5 (رخصة قيادة المركبات التجارية)."},"20":{"q":"أي فئة من فئات CDL في نيومكسيكو تخوّل قيادة مركبة مفردة ذات GVWR قدره 26,001 رطلاً أو أكثر، أو مثل هذه المركبة وهي تقطر وحدة لا يتجاوز تصنيف GVWR لها 10,000 lbs؟","options":["Class B","Class A","Class C","Class D"],"explanation":"يغطي CDL من الفئة Class B في نيومكسيكو أي مركبة مفردة ذات GVWR قدره 26,001 رطلاً أو أكثر، أو مثل هذه المركبة وهي تقطر وحدة لا يتجاوز تصنيف GVWR لها 10,000 pounds. أما التركيبة التي يتجاوز GCWR لها 26,001 وتقطر أكثر من 10,000 lbs فتتطلب الفئة Class A. المصدر: NM MVD Driver Manual Chapter 5."},"21":{"q":"ينطبق CDL من الفئة Class C في نيومكسيكو على مركبة يقل تصنيف GVWR لها عن 26,001 lbs فقط عندما تُستخدم لأي غرض؟","options":["نقل 16 راكباً أو أكثر (بمن فيهم السائق) أو مواد خطرة موسومة بلوحات","قطر أي مقطورة تزيد عن 5,000 lbs","نقل 9 ركاب أو أكثر مقابل أجر","العمل عبر حدود الولايات لأي نوع من البضائع"],"explanation":"ينطبق CDL من الفئة Class C في نيومكسيكو على مركبة مفردة يقل تصنيف GVWR لها عن 26,001 lbs (أو تقطر وحدة لا تتجاوز 10,000 lbs) فقط عندما تكون مصممة لنقل 16 راكباً أو أكثر بمن فيهم السائق، أو عندما تكون موسومة بلوحات للمواد الخطرة. المصدر: NM MVD Driver Manual Chapter 5."},"22":{"q":"بموجب القواعد الفيدرالية التي اعتمدتها نيومكسيكو، لا يجوز لحامل تصريح المتعلم التجاري (CLP) أن يخضع لاختبار مهارات CDL إلا بعد مرور كم يوماً على الأقل من الإصدار الأولي لـ CLP؟","options":["14 days","7 days","30 days","10 days"],"explanation":"لا يكون حامل CLP مؤهلاً لإجراء اختبار مهارات CDL خلال أول 14 days بعد الإصدار الأولي لـ CLP. وتطبق نيومكسيكو فترة الانتظار الفيدرالية هذه البالغة 14 يوماً. المصدر: NM MVD Driver Manual Chapter 5؛ 49 CFR 383.25."},"23":{"q":"ما هو الحد الأدنى للسن لإصدار CDL في نيومكسيكو مقيّد بالتجارة داخل الولاية (ضمن نيومكسيكو) فقط؟","options":["18 عاماً","21 عاماً","16 عاماً","19 عاماً"],"explanation":"يجب أن يكون عمر المتقدم 18 عاماً على الأقل ليحمل CDL في نيومكسيكو مقتصراً على التجارة داخل الولاية. ويحصل السائق الذي يتراوح عمره بين 18 و20 عاماً على قيد 'K' يقصره على القيادة ضمن نيومكسيكو فقط. المصدر: NM MVD Driver Manual Chapter 5."},"24":{"q":"ما هو الحد الأدنى للسن لإصدار CDL في نيومكسيكو للتجارة بين الولايات (عبر حدود الولايات)؟","options":["21 عاماً","18 عاماً","23 عاماً","25 عاماً"],"explanation":"يجب أن يكون عمر السائق 21 عاماً على الأقل لتشغيل مركبة تجارية في التجارة بين الولايات. ويقتصر سائقو نيومكسيكو الذين تتراوح أعمارهم بين 18 و20 عاماً على العمل داخل الولاية. المصدر: NM MVD Driver Manual Chapter 5؛ 49 CFR 391.11."},"25":{"q":"على CDL في نيومكسيكو، ماذا يشير القيد 'K' بشأن السائق؟","options":["مقتصر على التجارة داخل الولاية فقط","مقيّد بالمركبات من دون فرامل هوائية","مقيّد بالمركبات ذات ناقل الحركة الأوتوماتيكي","لا يجوز له نقل الركاب"],"explanation":"تضع نيومكسيكو قيد 'K' على رخص CDL الصادرة للمتقدمين الذين تتراوح أعمارهم بين 18 و20 عاماً، مما يقصر السائق على التجارة داخل الولاية (ضمن نيومكسيكو) فقط. المصدر: NM MVD Driver Manual Chapter 5."},"26":{"q":"أي مصادقة مطلوبة على CDL في نيومكسيكو لتشغيل مركبة صهريجية تنقل مواد سائلة أو غازية بكميات سائبة؟","options":["N (مركبة صهريجية)","T (مقطورات مزدوجة/ثلاثية)","H (مواد خطرة)","P (ركاب)"],"explanation":"تخوّل مصادقة N تشغيل مركبة صهريجية تُستخدم لنقل مواد سائلة أو غازية بكميات سائبة. ويمكن إضافة مصادقة N على CLP بعد اجتياز اختبار المعرفة المطلوب. المصدر: NM MVD Driver Manual Chapter 5."},"27":{"q":"أي مصادقة على CDL في نيومكسيكو مطلوبة لقطر مقطورتين أو ثلاث مقطورات خلف وحدة قدرة واحدة؟","options":["T (مقطورات مزدوجة/ثلاثية)","N (مركبة صهريجية)","S (حافلة مدرسية)","X (تركيبة)"],"explanation":"تخوّل مصادقة T قطر مقطورات مزدوجة أو ثلاثية وتتطلب اجتياز اختبار معرفة. المصدر: NM MVD Driver Manual Chapter 5؛ 49 CFR 383.93."},"28":{"q":"أي مصادقة يحتاجها حامل CDL في نيومكسيكو لقيادة مركبة تجارية مصممة لنقل 16 شخصاً أو أكثر، بمن فيهم السائق؟","options":["P (ركاب)","S (حافلة مدرسية)","N (مركبة صهريجية)","T (مقطورات مزدوجة/ثلاثية)"],"explanation":"تُطلب مصادقة P (الركاب) لقيادة مركبة مصممة لنقل 16 راكباً أو أكثر بمن فيهم السائق. ويجب إجراء اختبار المهارات في مركبة ممثلة لتلك الفئة. المصدر: NM MVD Driver Manual Chapter 5؛ 49 CFR 383.93."},"29":{"q":"قبل إصدار مصادقة H (المواد الخطرة)، يجب على المتقدم في نيومكسيكو اجتياز أي فحص أمني؟","options":["تقييم خلفية/تهديد قائم على بصمات الأصابع من TSA عبر Universal Enroll","مقارنة بقائمة المطلوبين الأكثر بحثاً لدى مكتب التحقيقات الفيدرالي فقط","فحص سجلات جنائية من شرطة الولاية فقط","مقابلة مع NM MVD من دون بصمات أصابع"],"explanation":"لا يجوز لـ NM MVD إصدار مصادقة المواد الخطرة (H) حتى يُكمل المتقدم فحص خلفية قائماً على بصمات الأصابع من TSA (تقييم تهديد مصادقة المواد الخطرة) من خلال نظام Universal Enroll وتقرر TSA أن المتقدم لا يشكل تهديداً أمنياً. المصدر: صفحة مصادقة المواد الخطرة لدى NM MVD؛ 49 CFR 1572."},"30":{"q":"بالنسبة لمصادقة المواد الخطرة (H) لأول مرة في نيومكسيكو، يتطلب ELDT من المتقدم إكمال أي تدريب قبل اختبار المعرفة؟","options":["تدريب نظري على المواد الخطرة لدى مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA","تدريب على الميدان خلف عجلة القيادة فقط","دورة طرق للمواد الخطرة حضورياً مدتها 40 ساعة","لا تدريب؛ فقط فحص خلفية TSA"],"explanation":"يجب على المتقدمين لمصادقة H لأول مرة إكمال تدريب نظري على المواد الخطرة (لا يُطلب عنصر خلف عجلة القيادة لمصادقة H) من مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA قبل إجراء اختبار المعرفة. المصدر: NM MVD Driver Manual Chapter 5؛ 49 CFR 380.725."},"31":{"q":"تنطبق متطلبات ELDT على المتقدمين لأول مرة في نيومكسيكو الذين تقدّموا بطلب الحصول على CLP أولي في أو بعد أي تاريخ؟","options":["February 7, 2022","January 1, 2020","September 30, 2021","July 1, 2023"],"explanation":"يجب على جميع المتقدمين للحصول على CLP لأول مرة في أو بعد February 7, 2022 الامتثال للقواعد الفيدرالية لتدريب السائقين المبتدئين (ELDT) الواردة في 49 CFR 380.600-380.603. المصدر: NM MVD Driver Manual Chapter 5."},"32":{"q":"أين يجب على المتقدم لـ ELDT في نيومكسيكو الحصول على تدريب السائق المبتدئ المطلوب لكي يُحتسب ضمن أهلية CDL/المصادقة؟","options":["من مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA (TPR)","من أي مدرسة قيادة تجارية يختارها المتقدم","من مكتب NM MVD الميداني مباشرةً","من برنامج داخلي لصاحب العمل، من دون اشتراط السجل"],"explanation":"يجب إكمال ELDT لدى مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA (TPR) على tpr.fmcsa.dot.gov؛ ويقدّم المزوّد الشهادة إلى FMCSA. المصدر: NM MVD Driver Manual Chapter 5؛ FMCSA TPR."},"33":{"q":"إن المصادقة الذاتية في نيومكسيكو على أنها 'بين الولايات غير المعفاة' (NI) تعني أن السائق يعمل في التجارة بين الولايات و:","options":["يجب أن يستوفي متطلبات البطاقة الطبية الفيدرالية لـ DOT","لا يتعين عليه استيفاء أي متطلبات طبية","يستوفي فقط المتطلبات الطبية لولاية نيومكسيكو","معفى لأنه يقود مركبة زراعية"],"explanation":"إن اختيار 'بين الولايات غير المعفاة' (NI) يصادق على أن السائق يعمل في التجارة بين الولايات ومطالب باستيفاء متطلبات شهادة الفاحص الطبي الفيدرالية لـ DOT. المصدر: NM MVD Driver Manual Chapter 5 (المصادقة الطبية الذاتية)."},"34":{"q":"أي فئة من فئات المصادقة الطبية الذاتية في نيومكسيكو تنطبق على سائق يعمل ضمن نيومكسيكو فقط وغير مطالب باستيفاء المتطلبات الطبية لنيومكسيكو؟","options":["EA (داخل الولاية معفاة)","NA (داخل الولاية غير معفاة)","NI (بين الولايات غير معفاة)","EI (بين الولايات معفاة)"],"explanation":"إن 'داخل الولاية معفاة' (EA) تعني أن السائق يعمل ضمن نيومكسيكو فقط وغير مطالب باستيفاء المتطلبات الطبية لولاية نيومكسيكو. أما NA فتتطلب استيفاء المتطلبات الطبية لنيومكسيكو. المصدر: NM MVD Driver Manual Chapter 5."},"35":{"q":"إلى جانب الهوية والوجود القانوني، أي مجموعة من المستندات يجب على المتقدم لـ CDL في نيومكسيكو تقديمها لإثبات الإقامة؟","options":["إثباتان للإقامة الفعلية يظهران عنواناً في نيومكسيكو","فاتورة خدمات واحدة أقدم من سنة واحدة","اتفاقية إيجار واحدة من خارج الولاية","بطاقة تسجيل ناخب من أي ولاية"],"explanation":"تتطلب نيومكسيكو إثباتين للإقامة الفعلية يظهران عنواناً في نيومكسيكو، إلى جانب إثبات الهوية والوجود القانوني/المواطنة الأمريكية ورقم الضمان الاجتماعي. المصدر: NM MVD Driver Manual Chapter 5؛ قائمة المستندات المقبولة لـ CDL في نيومكسيكو."},"36":{"q":"لتوثيق رقم الضمان الاجتماعي لـ CDL في نيومكسيكو، ينبغي على المتقدم تقديم أي مما يلي؟","options":["بطاقة ضمان اجتماعي أو إثبات صالح لرقم الضمان الاجتماعي","صفحة صورة جواز السفر فقط","فاتورتي خدمات","شهادة ميلاد بمفردها"],"explanation":"تتطلب نيومكسيكو بطاقة ضمان اجتماعي أو إثباتاً صالحاً آخر لرقم الضمان الاجتماعي كجزء من مستندات طلب CDL (إلى جانب الهوية والوجود القانوني وإثباتين للإقامة). المصدر: NM MVD Driver Manual Chapter 5؛ المستندات المقبولة لـ CDL في نيومكسيكو."},"37":{"q":"ما هو الحد الأدنى لدرجة النجاح في كل اختبار معرفة (تحريري) لـ CDL في نيومكسيكو؟","options":["80%","70%","75%","90%"],"explanation":"يجب أن يحصل المتقدم على 80% على الأقل لاجتياز كل اختبار معرفة لـ CDL في نيومكسيكو. ويجوز للمتقدم إجراء اختبار المعرفة حتى مرتين في الأسبوع، لكن النظام يمنع المحاولة الثالثة بعد إخفاقين خلال فترة 7 days. المصدر: NM MVD Driver Manual Chapter 5."},"38":{"q":"أي مصادقة لا يمكن للمتقدم لأول مرة إضافتها إلى تصريح المتعلم التجاري (CLP) في نيومكسيكو؟","options":["H (مواد خطرة)","N (مركبة صهريجية)","P (ركاب)","S (حافلة مدرسية)"],"explanation":"لا يمكن الحصول على مصادقة H (المواد الخطرة) على CLP؛ فهي تتطلب تقييم تهديد من TSA ولا تُضاف إلا إلى CDL كامل. أما مصادقات N وP وS فيمكن حملها على CLP (مع القيود المطبقة). المصدر: NM MVD Driver Manual Chapter 5؛ 49 CFR 383.25."},"39":{"q":"في نيومكسيكو، ما هو الحد الأقصى القانوني لتركيز الكحول في الدم (BAC) لسائق يشغّل مركبة تجارية (CMV)؟","options":["0.08%","0.04%","0.02%","0.00%"],"explanation":"تتبع نيومكسيكو المعيار الفيدرالي للمركبات التجارية: من غير القانوني تشغيل CMV بتركيز BAC قدره 0.04% أو أكثر (نصف حد 0.08% المقرر للسائقين غير التجاريين). المصدر: NM CDL Manual section 1.3.2؛ NMSA 66-5-68."},"40":{"q":"بموجب قاعدة الموافقة الضمنية في نيومكسيكو، ماذا يحدث لحامل CDL يشغّل مركبة تجارية CMV؟","options":["يجب أن يحمل تصريح اختبار نفَس منفصلاً","يُعدّ أنه قد أعطى موافقته على اختبار الكحول","يجوز له رفض الاختبار دون أي عقوبة","يوافق فقط إذا تم القبض عليه رسمياً أولاً"],"explanation":"ينص NM CDL Manual على أنك بتشغيل CMV 'تُعدّ قد أعطيت موافقتك على اختبار الكحول'. ويحمل الرفض الحرمان نفسه الذي تحمله المخالفة الكبرى. المصدر: NM CDL Manual section 1.3.2؛ NMSA 66-5-68 / قانون الموافقة الضمنية."},"41":{"q":"في نيومكسيكو، كم من الوقت يفقد السائق رخصته CDL لأول مخالفة كبرى، مثل مخالفة BAC قدرها 0.04%، في مركبة CMV غير موسومة بلوحات؟","options":["60 days","120 days","سنة واحدة على الأقل","3 سنوات على الأقل"],"explanation":"تفرض نيومكسيكو حرماناً من CDL لمدة سنة واحدة كحد أدنى لأول مخالفة كبرى (مثل BAC قدره 0.04%، أو القيادة تحت تأثير الكحول، أو رفض الاختبار، أو مغادرة موقع حادث). المصدر: NM CDL Manual section 1.3.2؛ NMSA 66-5-68."},"42":{"q":"إذا ارتكب حامل CDL في نيومكسيكو أول مخالفة كبرى أثناء تشغيل مركبة CMV موسومة بلوحات للمواد الخطرة، فكم تبلغ مدة الحرمان؟","options":["سنة واحدة على الأقل","سنتان على الأقل","3 سنوات على الأقل","مدى الحياة"],"explanation":"ترفع نيومكسيكو الحرمان عن أول مخالفة إلى 3 سنوات على الأقل إذا وقعت المخالفة الكبرى أثناء تشغيل مركبة CMV موسومة بلوحات للمواد الخطرة. المصدر: NM CDL Manual section 1.3.2؛ NMSA 66-5-68."},"43":{"q":"ما هي مدة حرمان CDL في نيومكسيكو لمخالفة كبرى ثانية (مثل قيادة ثانية تحت تأثير الكحول في مركبة CMV)؟","options":["3 سنوات","5 سنوات","10 سنوات","مدى الحياة"],"explanation":"تحرم نيومكسيكو السائق من حمل CDL مدى الحياة عند ارتكاب مخالفة كبرى ثانية. (قد تكون إعادة الترخيص ممكنة بموجب القاعدة بعد 10 سنوات، لكن الحرمان نفسه هو حظر مدى الحياة.) المصدر: NM CDL Manual section 1.3.2؛ NMSA 66-5-68."},"44":{"q":"في نيومكسيكو، يُعامَل رفض الخضوع لاختبار الكحول في الدم أثناء تشغيل مركبة CMV على أنه أي مما يلي؟","options":["مخالفة ورقية بسيطة","مخالفة مرورية خطيرة (من نوع 60 يوماً)","مخالفة كبرى (حرمان سنة واحدة)","مخالفة أمر إخراج من الخدمة"],"explanation":"تعامل نيومكسيكو رفض الخضوع لاختبار الكحول في الدم على أنه مخالفة كبرى، تحمل الحد الأدنى نفسه للحرمان من CDL لمدة سنة واحدة الذي تحمله إدانة BAC قدرها 0.04%. المصدر: NM CDL Manual section 1.3.2؛ NMSA 66-5-68."},"45":{"q":"يُسجّل سائق مركبة CMV في نيومكسيكو كمية قابلة للكشف من الكحول تقل عن 0.04%. ما هي العاقبة الفورية؟","options":["لا عاقبة دون 0.04%","الإخراج من الخدمة لمدة 24 ساعة","حرمان من CDL لمدة سنة واحدة","حرمان من CDL لمدة 60 يوماً"],"explanation":"تُخرِج نيومكسيكو سائق مركبة CMV من الخدمة لمدة 24 ساعة لأي كمية كحول قابلة للكشف تقل عن 0.04%. أما قراءة 0.04% أو أكثر فهي بدلاً من ذلك مخالفة كبرى موجبة للحرمان. المصدر: NM CDL Manual section 1.3.2."},"46":{"q":"أي مما يلي يُصنّف على أنه 'مخالفة مرورية خطيرة' لحامل CDL في نيومكسيكو؟","options":["القيادة بسرعة تزيد 5 mph عن الحد","السرعة المفرطة بمقدار 15 mph أو أكثر فوق الحد المعلن","مخالفة وقوف في مركبة CMV","ملصق تسجيل منتهي الصلاحية"],"explanation":"تدرج نيومكسيكو السرعة المفرطة (15 mph أو أكثر فوق الحد المعلن) ضمن المخالفات المرورية الخطيرة، إلى جانب القيادة المتهورة والتغيير غير السليم للمسارات والاقتراب الشديد من المركبة الأمامية. المصدر: NM CDL Manual section 1.3.3."},"47":{"q":"أي مما يلي ليس من المخالفات المرورية الخطيرة المدرجة في نيومكسيكو لحاملي CDL؟","options":["القيادة المتهورة","الاقتراب الشديد من مركبة أمامية","تغيير المسارات بشكل غير سليم أو غير منتظم","قيادة مركبة CMV بمصباح أمامي محترق"],"explanation":"تشمل قائمة المخالفات المرورية الخطيرة في نيومكسيكو القيادة المتهورة والاقتراب الشديد من مركبة أمامية وتغيير المسارات بشكل غير سليم/غير منتظم؛ أما المصباح الأمامي المحترق فهو مشكلة معدات وليس مخالفة خطيرة مدرجة. المصدر: NM CDL Manual section 1.3.3."},"48":{"q":"في نيومكسيكو، كم من الوقت يفقد السائق رخصته CDL لارتكاب مخالفتين مروريتين خطيرتين في مركبة CMV خلال فترة ثلاث سنوات؟","options":["30 يوماً على الأقل","60 يوماً على الأقل","120 يوماً على الأقل","سنة واحدة على الأقل"],"explanation":"تحرم نيومكسيكو حامل CDL لمدة 60 يوماً على الأقل لارتكاب مخالفتين مروريتين خطيرتين في مركبة CMV خلال فترة ثلاث سنوات. المصدر: NM CDL Manual section 1.3.3؛ NMSA 66-5-68."},"49":{"q":"في نيومكسيكو، كم من الوقت يفقد السائق رخصته CDL لارتكاب ثلاث مخالفات مرورية خطيرة أو أكثر في مركبة CMV خلال فترة ثلاث سنوات؟","options":["60 days","90 days","120 يوماً على الأقل","سنة واحدة على الأقل"],"explanation":"تحرم نيومكسيكو حامل CDL لمدة 120 يوماً على الأقل لارتكاب ثلاث مخالفات مرورية خطيرة أو أكثر في مركبة CMV خلال فترة ثلاث سنوات. المصدر: NM CDL Manual section 1.3.3؛ NMSA 66-5-68."},"50":{"q":"يُعدّ قيادة مركبة CMV في نيومكسيكو من دون الفئة الصحيحة من CDL و/أو المصادقات المطلوبة بمثابة ماذا؟","options":["مخالفة مرورية خطيرة","مخالفة كبرى (سنة واحدة)","مخالفة إخراج من الخدمة","مجرد تحذير، وليس مخالفة"],"explanation":"تدرج نيومكسيكو قيادة مركبة CMV من دون الفئة الصحيحة من CDL و/أو المصادقات (أو من دون حمل CDL في الحوزة) كمخالفة مرورية خطيرة. المصدر: NM CDL Manual section 1.3.3."},"51":{"q":"ما هو الحد الأدنى للحرمان من CDL في نيومكسيكو لأول مخالفة من السائق لأمر إخراج من الخدمة؟","options":["30 يوماً على الأقل","60 يوماً على الأقل","90 يوماً على الأقل","سنة واحدة على الأقل"],"explanation":"تحرم نيومكسيكو حامل CDL لمدة 90 يوماً على الأقل لأول مخالفة لأمر إخراج من الخدمة. المصدر: NM CDL Manual section 1.3.4؛ NMSA 66-5-68."},"52":{"q":"في نيومكسيكو، كم تبلغ مدة الحرمان من CDL لمخالفة ثانية لأمر إخراج من الخدمة خلال فترة عشر سنوات؟","options":["90 يوماً على الأقل","سنة واحدة على الأقل","3 سنوات على الأقل","5 سنوات على الأقل"],"explanation":"تحرم نيومكسيكو حامل CDL لمدة سنة واحدة على الأقل لمخالفتين لأمر إخراج من الخدمة خلال فترة عشر سنوات. المصدر: NM CDL Manual section 1.3.4؛ NMSA 66-5-68."},"53":{"q":"في نيومكسيكو، ما هو الحد الأدنى للحرمان من CDL لثلاث مخالفات أو أكثر لأمر إخراج من الخدمة خلال فترة عشر سنوات؟","options":["سنة واحدة","3 سنوات على الأقل","5 سنوات","مدى الحياة"],"explanation":"تحرم نيومكسيكو حامل CDL لمدة 3 سنوات على الأقل لثلاث مخالفات أو أكثر لأمر إخراج من الخدمة خلال فترة عشر سنوات. المصدر: NM CDL Manual section 1.3.4؛ NMSA 66-5-68."},"54":{"q":"في نيومكسيكو، ما هو الحد الأدنى للحرمان من CDL لأول مخالفة من السائق عند معبر السكة الحديدية مع الطريق السريع؟","options":["30 يوماً على الأقل","60 يوماً على الأقل","120 يوماً على الأقل","سنة واحدة على الأقل"],"explanation":"تحرم نيومكسيكو حامل CDL لمدة 60 يوماً على الأقل لأول مخالفة عند معبر السكة الحديدية مع الطريق السريع. المصدر: NM CDL Manual section 1.3.5؛ NMSA 66-5-68."},"55":{"q":"ما هو حرمان CDL في نيومكسيكو لمخالفة ثالثة عند معبر السكة الحديدية مع الطريق السريع خلال فترة ثلاث سنوات؟","options":["120 days","180 days","سنة واحدة على الأقل","3 سنوات"],"explanation":"تحرم نيومكسيكو حامل CDL لمدة سنة واحدة على الأقل لمخالفة ثالثة عند معبر السكة الحديدية مع الطريق السريع خلال فترة ثلاث سنوات (60 يوماً للأولى و120 يوماً للثانية). المصدر: NM CDL Manual section 1.3.5؛ NMSA 66-5-68."},"56":{"q":"بموجب قواعد نيومكسيكو/الفيدرالية، متى يصبح CDL لسائق مركبة CMV عرضة للحرمان بسبب استخدام هاتف محمول باليد أثناء القيادة؟","options":["بعد إدانة أولى واحدة","بعد إدانتين أو أكثر","فقط بعد تصادم يكون السائق مسؤولاً عنه","استخدام الهاتف باليد لا يؤدي أبداً إلى الحرمان"],"explanation":"يُحرَم CDL في نيومكسيكو بعد إدانتين أو أكثر باستخدام الهاتف المحمول باليد أثناء تشغيل مركبة CMV: 60 يوماً لمخالفة ثانية خلال 3 سنوات و120 يوماً لثلاث مخالفات أو أكثر خلال 3 سنوات. المصدر: NM CDL Manual section 2.9.4."},"57":{"q":"ما هو الحد الأقصى للغرامة المدنية التي قد يواجهها سائق مركبة CMV في نيومكسيكو لانتهاك حظر استخدام الهاتف المحمول باليد / المراسلة النصية؟","options":["حتى $750","حتى $2,750","حتى $5,000","حتى $11,000"],"explanation":"بموجب القيد الفيدرالي المطبق في نيومكسيكو، يخضع السائق الذي ينتهك حظر الهاتف باليد/المراسلة النصية لغرامة مدنية تصل إلى $2,750؛ أما صاحب العمل الذي يسمح بذلك أو يطلبه فيواجه حتى $11,000. المصدر: NM CDL Manual section 2.9.4."},"58":{"q":"في نيومكسيكو، قد تفرض المحكمة غرامة على شخص تصل إلى أي مبلغ لقيادة مركبة تجارية من دون CDL أو لحمل أكثر من رخصة واحدة؟","options":["حتى $1,000","حتى $2,750","حتى $5,000","حتى $11,000"],"explanation":"تنص نيومكسيكو على أنه يجوز للمحكمة أن تفرض غرامة على السائق تصل إلى $5,000 (أو أن تفرض السجن) لقيادة مركبة CMV من دون CDL أو لحمل أكثر من رخصة واحدة. المصدر: NM CDL Manual sections 1.3.7 and 1.4."},"59":{"q":"بموجب قانون نيومكسيكو، عندما تتوقف حافلة مدرسية على الطريق وإشارات الحافلة المدرسية الخاصة بها تعمل لتحميل الأطفال أو إنزالهم، على أي مسافة قبل الحافلة يجب على السائق المقترب منها أن يتوقف؟","options":["على بُعد 10 أقدام على الأقل قبل الوصول إلى الحافلة","على بُعد 25 قدمًا على الأقل قبل الوصول إلى الحافلة","على بُعد 20 قدمًا على الأقل قبل الوصول إلى الحافلة","على بُعد 15 قدمًا على الأقل قبل الوصول إلى الحافلة"],"explanation":"تتطلب المادة 66-7-347(A) من قانون نيومكسيكو لعام 1978 من السائق المقترب من حافلة مدرسية متوقفة أو الذي يتجاوزها وإشاراتها تعمل أن يوقف المركبة على بُعد عشرة أقدام على الأقل قبل الوصول إلى الحافلة وألا يتابع السير حتى تُطفأ الإشارات أو تتحرك الحافلة أو يشير السائق بالمتابعة."},"60":{"q":"في نيومكسيكو، أي شرط محدد بالضبط يسمح للسائق بالمرور أمام حافلة مدرسية متوقفة تقوم بتحميل الأطفال دون أن يتوقف؟","options":["وجود مساريْن أو أكثر في اتجاه سير السائق","أن تكون الحافلة على بُعد أكثر من 100 قدم عند رؤيتها لأول مرة","أن تكون الحافلة المدرسية على طريق مختلف من طريق سريع ذي مسارات منفصلة","أن يكون السائق يسير بسرعة أقل من 25 ميلًا في الساعة"],"explanation":"تنص المادة 66-7-347(C) من قانون نيومكسيكو لعام 1978 على الاستثناء الوحيد الخاص بالطرق المقسومة: لا يلزم السائق على طريق سريع ذي مسارات منفصلة التوقف لحافلة على طريق مختلف (أو على طريق سريع ذي وصول محكوم تكون فيه الحافلة في منطقة تحميل ولا يُسمح للمشاة بالعبور). مجرد وجود مسارات إضافية أو سرعة منخفضة لا يعفي من التوقف."},"61":{"q":"على طريق سريع في نيومكسيكو، يجب على حافلة مدرسية تنقل أطفالًا، أو حافلة تنقل ركابًا مقابل أجر، أو مركبة تحمل لافتات مواد خطرة أن تتوقف قبل تقاطع السكة الحديدية مع الطريق على أي مسافة من أقرب قضيب؟","options":["ليس أقل من 25 قدمًا وليس أكثر من 75 قدمًا","ليس أقل من 10 أقدام وليس أكثر من 40 قدمًا","ليس أقل من 15 قدمًا وليس أكثر من 50 قدمًا","ليس أقل من 5 أقدام وليس أكثر من 25 قدمًا"],"explanation":"تتطلب المادة 66-7-343(A) من قانون نيومكسيكو لعام 1978 من هذه المركبات التوقف على مسافة لا تقل عن 15 قدمًا ولا تزيد عن 50 قدمًا من أقرب قضيب قبل دخول التقاطع. وينص دليل CDL لنيومكسيكو (القسم 2.15) على قاعدة الـ 15 إلى 50 قدمًا ذاتها."},"62":{"q":"يتطلب قانون التوقف عند تقاطع السكة الحديدية في نيومكسيكو (66-7-343) من السائق المشمول، أثناء توقفه عند التقاطع، وضع المركبة في ترس منخفض بما يكفي بحيث:","options":["يمكن اختيار الرجوع للخلف إذا اقترب قطار","لن تكون هناك حاجة لتغيير التروس قبل اجتياز التقاطع","يمكن تشغيل مكبح المحرك على الجانب الآخر","يمكن للمركبة أن تعاود الانطلاق على منحدر بنسبة 5%"],"explanation":"تتطلب المادة 66-7-343(B)(3) من قانون نيومكسيكو لعام 1978 اختيار ترس منخفض بما يكفي بحيث لا تكون هناك حاجة لتغيير التروس قبل الخروج من التقاطع، وتحظر الفقرة الفرعية (C) تغيير التروس أثناء التواجد في التقاطع. ويكرر دليل CDL لنيومكسيكو: «لا تغيّر التروس أثناء عبور قضبان السكة الحديدية»."},"63":{"q":"أي من هذه ليس من الاستثناءات المدرجة في نيومكسيكو التي تعفي حافلة أو مركبة تحمل لافتات مواد خطرة من التوقف عند تقاطع السكة الحديدية مع الطريق؟","options":["تقاطع يعمل فيه ضوء أحمر وامض وجرس","تقاطع يوجّه فيه ضابط شرطة المرور بالمتابعة","تقاطع يتحكم فيه ضوء مرور للتوقف والسير","تقاطع مُعلَّم بلافتة «تقاطع معفى»"],"explanation":"تسرد المادة 66-7-343(D) من قانون نيومكسيكو لعام 1978 الاستثناءات: ضابط يوجّه المرور، وضوء مرور للتوقف والسير، وتقاطع مناورة صناعية ضمن منطقة تجارية، وتقاطع مهجور مُعلَّم بذلك، ولافتة «تقاطع معفى». أما التقاطع الذي يعمل فيه ضوء أحمر وامض وجرس فليس استثناءً؛ فيجب على المركبة أن تتوقف رغم ذلك."},"64":{"q":"ما هو الحد الأقصى العام للسرعة الذي يحدده قانون نيومكسيكو لأي مركبة على طريق سريع لا يوجد عليه حد أدنى معلن؟","options":["65 ميلًا في الساعة","75 ميلًا في الساعة","80 ميلًا في الساعة","70 ميلًا في الساعة"],"explanation":"تحدد المادة 66-7-301(A)(3) من قانون نيومكسيكو لعام 1978 الحد الأقصى القانوني العام عند خمسة وسبعين ميلًا في الساعة. ينطبق هذا الرقم في غياب حد أدنى معلن أو منطقة غرامة مضاعفة محددة."},"65":{"q":"هل تفرض نيومكسيكو حدًا أقصى قانونيًا للسرعة على جرارات الشاحنات (الشاحنات الكبيرة) أدنى من ذلك المفروض على السيارات؟","options":["نعم - الشاحنات محدودة بـ 60 ميلًا في الساعة بموجب القانون","لا - ينطبق نفس الحد الأقصى القانوني البالغ 75 ميلًا في الساعة على الشاحنات والسيارات","نعم - الشاحنات محدودة بـ 55 ميلًا في الساعة ليلًا بموجب القانون","نعم - الشاحنات محدودة بـ 65 ميلًا في الساعة بموجب القانون"],"explanation":"نيومكسيكو ليست ولاية ذات حد سرعة منقسم. ينطبق الحد الأقصى البالغ 75 ميلًا في الساعة في المادة 66-7-301 من قانون نيومكسيكو لعام 1978 على جميع المركبات. وقد مات مشروع قانون عام 2025 (SB226) الذي اقترح حدًا قدره 65 ميلًا في الساعة لجرارات الشاحنات في اللجنة ولم يصبح قانونًا قط، لذا لا يوجد سقف قانوني للسرعة خاص بالشاحنات."},"66":{"q":"وفقًا لقانون نيومكسيكو، ما هو الحد الأقصى للسرعة عند المرور بمدرسة بينما يكون الأطفال ذاهبين إلى المدرسة أو خارجين منها وتكون منطقة المدرسة معلنة بشكل صحيح؟","options":["25 ميلًا في الساعة","20 ميلًا في الساعة","30 ميلًا في الساعة","15 ميلًا في الساعة"],"explanation":"تحدد المادة 66-7-301(A)(1) من قانون نيومكسيكو لعام 1978 حدًا قدره 15 ميلًا في الساعة على جميع الطرق السريعة عند المرور بمدرسة بينما يكون الأطفال ذاهبين إلى المدرسة أو خارجين منها وتكون المنطقة معلنة بشكل صحيح."},"67":{"q":"في غياب حد معلن، ما السرعة التي يحددها قانون نيومكسيكو للقيادة في منطقة تجارية أو سكنية؟","options":["20 ميلًا في الساعة","35 ميلًا في الساعة","30 ميلًا في الساعة","25 ميلًا في الساعة"],"explanation":"تحدد المادة 66-7-301(A)(2) من قانون نيومكسيكو لعام 1978 حدًا قدره 30 ميلًا في الساعة في منطقة تجارية أو سكنية حيث لا يوجد حد آخر معلن."},"68":{"q":"اعتبارًا من 1 يوليو 2023، يقيّد قانون السير في المسارات في نيومكسيكو (66-7-376) عمومًا استخدام المسار الأيسر على طريق متعدد المسارات في أي حالة؟","options":["فقط بين شروق الشمس وغروبها","فقط عند نقل مواد خطرة تحمل لافتات","فقط عند تجاوز مركبة أخرى وتخطيها","فقط عند السير بسرعة تزيد عن 65 ميلًا في الساعة"],"explanation":"تحظر المادة 66-7-376(A)(4) من قانون نيومكسيكو لعام 1978، التي سُنّت بموجب SB102 (قوانين 2023) والنافذة اعتبارًا من 1 يوليو 2023، القيادة في المسار الأيسر من الطريق إلا عند التجاوز والتخطي، ما لم تتطلب حركة المرور أو انسيابها أو تكوين الطريق (مثل اندماج حركة المرور) استخدام المسار الأيسر."},"69":{"q":"قيد المسار الأيسر في نيومكسيكو في المادة 66-7-376 لا ينطبق في أي من هذه المواقع؟","options":["على أي طريق سريع تابع للولاية بثلاثة مسارات في كل اتجاه","ضمن حدود بلدية، على طريق ليس طريقًا بين الولايات","على طريق سريع أمريكي مقسوم بأربعة مسارات بين المدن","على امتداد ريفي من الطريق بين الولايات Interstate 40"],"explanation":"تنص المادة 66-7-376(A)(4) من قانون نيومكسيكو لعام 1978 صراحةً على أن حظر المسار الأيسر لا ينطبق ضمن حدود بلدية أو على طريق تابع لمقاطعة، ما دام الطريق ليس جزءًا من النظام الوطني للطرق السريعة بين الولايات وطرق الدفاع."},"70":{"q":"بموجب قانون استخدام المسارات في نيومكسيكو، يجب على السائق الذي يغيّر المسار أن يشير إلى نيته تغيير المسار خلال آخر كم قدمًا مقطوعة على الأقل؟","options":["100 قدم","150 قدمًا","200 قدم","50 قدمًا"],"explanation":"تتطلب المادة 66-7-376(A)(2) من قانون نيومكسيكو لعام 1978 أن يشير السائق، قبل الانتقال من مسار، إلى نيته تغيير المسار خلال ما لا يقل عن آخر مئة قدم تقطعها المركبة."},"71":{"q":"تعلّم نيومكسيكو مسار الانعطاف لليسار في الاتجاهين بخطوط صفراء مزدوجة متوازية (الداخلية متقطعة والخارجية متصلة). لا يجوز قيادة مركبة تستعد للانعطاف لليسار أو تنفذه في ذلك المسار لأكثر من أي مسافة؟","options":["300 قدم","500 قدم","200 قدم","100 قدم"],"explanation":"تنص المادة 66-7-376(B) من قانون نيومكسيكو لعام 1978 على أن المركبات المنعطفة لليسار من الطريق يجب ألا تُقاد في مسار الانعطاف لليسار في الاتجاهين لأكثر من مئتي قدم أثناء الاستعداد للانعطاف وتنفيذه."},"72":{"q":"بموجب قانون الإفساح (Move Over) في نيومكسيكو، عندما تقترب مركبة طوارئ مرخصة بأضواء وامضة أو صفارة إنذار، يجب على سائق كل مركبة أخرى أن:","options":["ينتقل مسارًا واحدًا إلى اليسار ويحافظ على سرعته","يبطئ إلى 20 ميلًا في الساعة ويبقى في مساره الحالي","يتوقف فورًا في مساره الحالي بغض النظر عن موقعه","ينحرف بأقرب ما يمكن إلى الحافة اليمنى أو الرصيف ويتوقف حتى تمر"],"explanation":"تتطلب المادة 66-7-332(A) من قانون نيومكسيكو لعام 1978 من السائقين، عند الاقتراب الفوري لمركبة طوارئ مرخصة، إفساح الطريق والقيادة فورًا بموازاة الحافة اليمنى أو الرصيف وبأقرب ما يمكن إليهما، بعيدًا عن أي تقاطع، والتوقف حتى تمر، ما لم يوجّه ضابط بخلاف ذلك."},"73":{"q":"ينطبق قانون الإفساح (Move Over) في نيومكسيكو على مركبة متوقفة تعرض أضواء طوارئ أو خطر وامضة. إلى جانب مركبات الطوارئ المرخصة، أي المركبات مشمولة على وجه التحديد؟","options":["الحافلات المدرسية عند موقف الحافلة","مركبات توصيل البريد","المعدات الزراعية على الكتف","مركبات الإنقاذ أو الإصلاح (السحب/الونش)"],"explanation":"توسّع المادة 66-7-332(B) من قانون نيومكسيكو لعام 1978 واجب «الإفساح والإبطاء» الخاص بالمركبات المتوقفة ليشمل مركبة طوارئ مرخصة متوقفة أو مركبة إنقاذ أو إصلاح تعرض أضواء طوارئ أو خطر وامضة."},"74":{"q":"بموجب قانون الإفساح (Move Over) في نيومكسيكو، عندما يقترب السائق من مركبة طوارئ أو إنقاذ متوقفة ولكن ليس من الآمن بشكل معقول الخروج من المسار المجاور، يجب على السائق أن:","options":["يتوقف توقفًا تامًا في مسار السير","يبطئ إلى سرعة معقولة وحكيمة في ظل الظروف، ويتابع بحذر، ويكون مستعدًا للتوقف","يسرّع لتجاوز الموقع لإخلائه بسرعة","يتابع بالسرعة المعلنة عبر المنطقة"],"explanation":"تنص المادة 66-7-332(B)(2) من قانون نيومكسيكو لعام 1978 على أنه إذا لم يكن من الآمن بشكل معقول القيادة في مسار غير مجاور للمركبة المتوقفة، فيجب على السائق أن يخفض السرعة إلى سرعة معقولة وحكيمة في ظل الظروف، ويتابع بحذر، ويكون مستعدًا للتوقف."},"75":{"q":"إذا اضطرت مركبة تجارية في نيومكسيكو للتوقف على طريق سريع أحادي الاتجاه أو مقسوم، أين يتطلب دليل CDL وضع أجهزة التحذير الثلاثة (المثلثات العاكسة)؟","options":["فقط خلف المركبة مباشرة على بُعد 100 قدم","على بُعد 10 أقدام و50 قدمًا و150 قدمًا باتجاه حركة المرور المقتربة","على بُعد 100 قدم أمامًا و100 قدم خلفًا فقط","على بُعد 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور المقتربة"],"explanation":"يتبع دليل CDL لنيومكسيكو (القسم 2.5) المعيار الفيدرالي للمركبات التجارية (49 CFR 392.22): على طريق سريع أحادي الاتجاه أو مقسوم، توضع أجهزة التحذير على بُعد 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور المقتربة، خلال 10 دقائق من التوقف."},"76":{"q":"على طريق ثنائي المسار وثنائي الاتجاه (غير مقسوم) في نيومكسيكو، أين يتطلب دليل CDL وضع مثلثات التحذير لمركبة تجارية متوقفة؟","options":["في حدود 10 أقدام من المركبة، و100 قدم خلف المركبة و100 قدم أمامها","على بُعد 10 و100 و200 قدم خلف المركبة فقط","على بُعد 50 قدمًا خلفًا و50 قدمًا أمامًا فقط","على بُعد 200 قدم خلفًا و200 قدم أمامًا فقط"],"explanation":"يوجّه دليل CDL لنيومكسيكو (القسم 2.5) إلى أنه على طريق ثنائي المسار يحمل حركة مرور في الاتجاهين أو طريق سريع غير مقسوم، يوضع جهاز واحد في حدود 10 أقدام من المقدمة أو المؤخرة، وواحد على بُعد 100 قدم خلف المركبة وواحد على بُعد 100 قدم أمامها."},"77":{"q":"في نيومكسيكو، إذا توقفت مركبة تجارية في مكان يمنع فيه تلٌّ أو منعطف أو عائق آخر رؤية مثلثات التحذير ضمن 500 قدم، فينبغي على السائق أن:","options":["يضع المثلثات الثلاثة جميعها في حدود 50 قدمًا من المصد الخلفي","يترك جميع المثلثات على المسافات القياسية 10 و100 و200 قدم","يستخدم الأضواء الرباعية الوامضة فقط بدلًا من المثلثات","يحرّك المثلث الأخلفي إلى الوراء بعد العائق، حتى مسافة 500 قدم من المركبة"],"explanation":"يوجّه دليل CDL لنيومكسيكو (القسم 2.5) إلى أنه إذا حجب تلٌّ أو منعطف أو عائق خط الرؤية ضمن 500 قدم، فينبغي تحريك المثلث الأخلفي إلى الوراء على الطريق، حتى مسافة 500 قدم، ليحصل السائقون الآخرون على تحذير. وتتطلب المادة 66-3-853 من قانون نيومكسيكو لعام 1978 بالمثل الوضع على مسافة 100 إلى 500 قدم بالقرب من مثل هذه العوائق."},"78":{"q":"تتطلب المادة 66-3-849 من قانون نيومكسيكو من الحافلات والشاحنات الكبيرة حمل أي مجموعة من معدات التحذير في حالات الطوارئ؟","options":["ثلاثة عاكسات طوارئ حمراء (أو شعلات/فيوزيز) إضافة إلى عَلَمين قماشيين أحمرين","فانوس أحمر واحد وعَلَم واحد","وميضان كهرمانيان وطفاية حريق فقط","أربعة مخاريط برتقالية وسترة عاكسة"],"explanation":"تتطلب المادة 66-3-849 من قانون نيومكسيكو لعام 1978 من المركبات المشمولة (الحافلات والشاحنات وجرارات الشاحنات، إلخ) حمل أجهزة تحذير مثل ثلاثة عاكسات طوارئ حمراء، وعَلَمين قماشيين أحمرين، وثلاث فيوزيز (أو ما يعادلها من شعلات/فوانيس). كما يدرج دليل CDL لنيومكسيكو بالمثل ثلاثة مثلثات عاكسة، أو ست فيوزيز، أو ثلاث شعلات تعمل بالوقود السائل كأجهزة التحذير المطلوبة للمركبة المتوقفة."},"79":{"q":"أي وكالة حكومية تصدر رخص القيادة التجارية (CDLs) في نيومكسيكو؟","options":["شعبة المركبات الآلية (MVD)","وزارة النقل في نيومكسيكو (NMDOT)","مكتب المركبات التجارية التابع لشرطة الولاية","لجنة التنظيم العامة (PRC)"],"explanation":"في نيومكسيكو، تصدر رخص القيادة التجارية CDLs عن شعبة المركبات الآلية (MVD)، وهي جزء من وزارة الضرائب والإيرادات. أما NMDOT فتتولى الطرق وتصاريح الحجم الزائد/الوزن الزائد، وليس ترخيص السائقين. المصدر: MVD New Mexico، صفحة رخص القيادة التجارية (CDL) والفصل 5: رخصة القيادة التجارية."},"80":{"q":"عند التقدم بطلب للحصول على CDL في نيومكسيكو، يجب على المتقدمين التصديق الذاتي ضمن فئة واحدة من كم فئة من فئات السائقين؟","options":["أربع فئات","فئتان","ثلاث فئات","ست فئات"],"explanation":"يجب على المتقدمين للحصول على CDL في نيومكسيكو التصديق الذاتي ضمن واحدة من أربع فئات تصف نوع التجارة التي يتوقعون العمل فيها: بين الولايات غير معفى (NI)، وبين الولايات معفى (EI)، وداخل الولاية غير معفى (NA)، وداخل الولاية معفى (EA). المصدر: MVD New Mexico الفصل 5؛ FMCSA 49 CFR 383.71."},"81":{"q":"سائق CDL في نيومكسيكو يعمل عبر حدود الولايات وليس معفى من قواعد التأهيل البدني الفيدرالية يجب أن يصدّق ذاتيًا ضمن أي فئة؟","options":["بين الولايات غير معفى (NI)","بين الولايات معفى (EI)","داخل الولاية غير معفى (NA)","داخل الولاية معفى (EA)"],"explanation":"السائق الذي يعمل في التجارة بين الولايات والمطلوب منه استيفاء المعايير الطبية الفيدرالية لـ DOT يصدّق ذاتيًا بوصفه بين الولايات غير معفى (NI) ويجب أن يحتفظ بشهادة فاحص طبي سارية في ملفه لدى MVD. المصدر: MVD New Mexico الفصل 5؛ FMCSA 49 CFR 383.71."},"82":{"q":"من المخوّل بإجراء الفحص البدني لشهادة الفاحص الطبي لـ CDL في نيومكسيكو؟","options":["مهني طبي مدرج في السجل الوطني للفاحصين الطبيين المعتمدين","أي طبيب مرخص في نيومكسيكو","ممرض ممارس في أي عيادة رعاية عاجلة","الضابط الطبي في مكتب MVD الميداني"],"explanation":"يجب إكمال جميع الشهادات الطبية للسائقين التجاريين في نيومكسيكو بواسطة مهني طبي مدرج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA. ولا يكفي مجرد امتلاك ترخيص طبي عام. المصدر: MVD New Mexico، صفحة رخص القيادة التجارية (CDL)؛ السجل الوطني لـ FMCSA."},"83":{"q":"كيف يُدخل حامل CDL في نيومكسيكو شهادة الفاحص الطبي لـ DOT في سجل الولاية؟","options":["بتقديم نسخة من الشهادة إلى MVD، التي تسجّل الحالة الطبية في سجل القيادة","بإرسالها بالبريد مباشرة إلى FMCSA في واشنطن العاصمة","بالاحتفاظ بالبطاقة الأصلية في المركبة فقط؛ دون تقديم نسخة إلى MVD","بإيداعها لدى وزارة الصحة في نيومكسيكو"],"explanation":"يجب على حاملي CDL في نيومكسيكو تزويد MVD (وكالة ترخيص السائقين في الولاية) بنسخة من شهادة الفاحص الطبي الخاصة بهم؛ ثم تسجّل MVD حالة التصديق الطبي في سجل القيادة التجارية (CDLIS). والبطاقة المحمولة في المركبة وحدها لا تفي بمتطلب الإيداع لدى الولاية. المصدر: MVD New Mexico الفصل 5؛ FMCSA 49 CFR 383.71(h)."},"84":{"q":"قبل الاختبار للحصول على CDL، يجب على المتقدم لأول مرة في نيومكسيكو عمومًا إكمال أي تدريب مطلوب فيدراليًا؟","options":["تدريب السائقين المبتدئين (ELDT) من مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA","دورة سلامة مركبات تجارية مدتها 40 ساعة من OSHA","دورة دراسية للقيادة الدفاعية في نيومكسيكو","تدرّب لا يقل عن 90 يومًا مع ناقل مرخص"],"explanation":"يجب على المتقدمين للحصول على CDL لأول مرة (وبعض الترقيات/التظهيرات) إكمال تدريب السائقين المبتدئين (ELDT) عبر مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA قبل إجراء اختبار المهارات أو المعرفة. تنطبق القاعدة على المتقدمين في 7 فبراير 2022 أو بعده. المصدر: MVD New Mexico الفصل 5؛ قاعدة ELDT الخاصة بـ FMCSA، 49 CFR Part 380."},"85":{"q":"كم يجب أن ينتظر حامل تصريح المتعلم التجاري (CLP) في نيومكسيكو بعد الإصدار الأولي قبل أن يصبح مؤهلاً لإجراء اختبار المهارات لـ CDL؟","options":["14 يومًا على الأقل","30 يومًا على الأقل","10 أيام على الأقل","60 يومًا على الأقل"],"explanation":"لا يكون حامل CLP مؤهلاً لإجراء اختبار المهارات لـ CDL إلا بعد مرور 14 يومًا على الأقل من الإصدار الأولي لـ CLP. ويُطبَّق هذا الحد الأدنى الفيدرالي من قبل MVD نيومكسيكو. المصدر: MVD New Mexico الفصل 5؛ FMCSA 49 CFR 383.25(a)(3)."},"86":{"q":"ما مدة صلاحية تصريح المتعلم التجاري (CLP) في نيومكسيكو؟","options":["سنة واحدة (مع السماح بتجديد واحد دون إعادة اختبار)","90 يومًا","6 أشهر","سنتان"],"explanation":"يصدر CLP في نيومكسيكو لمدة سنة واحدة. وبموجب المعيار الفيدرالي يمكن تجديده مرة واحدة خلال تلك الفترة دون إعادة إجراء اختبار المعرفة العامة. المصدر: MVD New Mexico الفصل 5؛ FMCSA 49 CFR 383.25(c)."},"87":{"q":"يتألف اختبار المهارات لـ CDL في نيومكسيكو من كم جزء، وما هي؟","options":["ثلاثة أجزاء: فحص المركبة قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","جزءان: اختبار تحريري وقيادة على الطريق","ثلاثة أجزاء: اختبار المكابح الهوائية، واختبار الرجوع للخلف، والقيادة الليلية","أربعة أجزاء: الفحص، والرجوع للخلف، والطريق السريع، والركن الموازي"],"explanation":"يتكون اختبار المهارات لـ CDL من ثلاثة أجزاء يجب اجتيازها بالترتيب: فحص المركبة قبل الرحلة، والتحكم الأساسي بالمركبة (مناورات بطيئة السرعة)، واختبار القيادة على الطريق. المصدر: MVD New Mexico الفصل 5؛ FMCSA 49 CFR 383.113."},"88":{"q":"ما هو الحد الأدنى للدرجة للنجاح في اختبارات المعرفة (التحريرية) لـ CDL في نيومكسيكو؟","options":["80 بالمئة","70 بالمئة","75 بالمئة","90 بالمئة"],"explanation":"يجب اجتياز اختبارات المعرفة لـ CDL في نيومكسيكو بدرجة لا تقل عن 80 بالمئة، بما يتوافق مع المعيار الفيدرالي. المصدر: MVD New Mexico الفصل 5؛ FMCSA 49 CFR 383.135."},"89":{"q":"أي شرط مسبق يجب أن يمتلكه الشخص بالفعل قبل التقدم بطلب للحصول على CDL في نيومكسيكو؟","options":["رخصة قيادة نيومكسيكو سارية من الفئة D (العادية) أو CDL سارية من ولاية أخرى","تظهير ركاب (P) حُصِل عليه في أي ولاية","تصريح مواد خطرة فيدرالي من TSA","تظهير دراجة نارية على رخصة نيومكسيكو"],"explanation":"للتقدم بطلب للحصول على CDL في نيومكسيكو يجب أن تمتلك بالفعل رخصة قيادة نيومكسيكو غير تجارية سارية (الفئة D) أو CDL سارية من ولاية أخرى. المصدر: MVD New Mexico، متطلبات الحصول على CDL في نيومكسيكو."},"90":{"q":"بموجب قواعد MVD في نيومكسيكو، كم إثباتًا للإقامة الفعلية في نيومكسيكو يجب على المتقدم للحصول على CDL أن يقدّم؟","options":["إثباتان للإقامة الفعلية","إثبات واحد للإقامة الفعلية","ثلاثة إثباتات للإقامة الفعلية","لا يُطلب إثبات إقامة"],"explanation":"يجب على المتقدم للحصول على CDL في نيومكسيكو تقديم إثباتين للإقامة الفعلية في الولاية. والمستندات الشهرية مثل فواتير الخدمات أو كشوف الحساب المصرفي المستخدمة كإثبات يجب أن تكون مؤرخة خلال 60 يومًا من الطلب. المصدر: MVD New Mexico، صفحة رخص القيادة التجارية (CDL)."},"91":{"q":"أي خيارات دورة تجديد تقدمها نيومكسيكو لـ CDL؟","options":["وثيقة لمدة 4 سنوات أو لمدة 8 سنوات","وثيقة لمدة سنة واحدة أو 5 سنوات","وثيقة لمدة 5 سنوات فقط","وثيقة لمدة سنتين أو 6 سنوات"],"explanation":"تقدم نيومكسيكو رخص CDL بدورة تجديد لمدة 4 سنوات أو 8 سنوات. المصدر: الأسئلة الشائعة لـ MVD New Mexico والفصل 5."},"92":{"q":"لماذا قد يقتصر حامل CDL في نيومكسيكو على الوثيقة لمدة 4 سنوات (بدلًا من 8 سنوات)؟","options":["لأنه يحمل تظهير المواد الخطرة (Hazmat)","لأنه يحمل تظهير ركاب (P)","لأنه يقود داخل الولاية فقط","لأنه دون سن 30"],"explanation":"لا يستطيع السائقون الحاملون لتظهير المواد الخطرة (Hazmat) الحصول على CDL لمدة 8 سنوات؛ إذ يقتصرون على دورة الـ 4 سنوات بسبب فحص خلفية TSA الدوري المرتبط بـ Hazmat. المصدر: الأسئلة الشائعة لـ MVD New Mexico؛ قواعد تظهير Hazmat الخاصة بـ TSA/FMCSA."},"93":{"q":"كيف تُجدوَل اختبارات المعرفة لـ CDL في نيومكسيكو فيما يتعلق بإعادة المحاولة؟","options":["يمكن للمتقدمين إجراء الاختبارات التحريرية لـ CDL حتى مرتين في الأسبوع","يمكن للمتقدمين إجراء الاختبارات التحريرية مرة واحدة فقط كل 30 يومًا","يحصل المتقدمون على إعادة محاولات غير محدودة في اليوم نفسه","يمكن للمتقدمين إجراء الاختبارات التحريرية مرة واحدة فقط في السنة التقويمية"],"explanation":"تسمح نيومكسيكو للمتقدمين للحصول على CDL بإجراء الاختبارات التحريرية (المعرفة) لـ CDL حتى مرتين في الأسبوع. المصدر: MVD New Mexico، صفحة رخص القيادة التجارية (CDL)."},"94":{"q":"ما هو الحد الأدنى للعمر للحصول على CDL في نيومكسيكو المقيدة بالقيادة داخل الولاية فقط؟","options":["18 عامًا","16 عامًا","21 عامًا","19 عامًا"],"explanation":"يجوز للشخص الحصول على CDL في نيومكسيكو للقيادة داخل الولاية في سن 18؛ ويقتصر المتقدم الذي تتراوح أعماره بين 18 و20 على العمل داخل الولاية. أما العمل في التجارة بين الولايات فيتطلب سن 21. المصدر: MVD New Mexico الفصل 5؛ FMCSA 49 CFR 391.11."},"95":{"q":"عندما يستبدل سائق CDL سارية من ولاية أخرى بـ CDL في نيومكسيكو من الفئة والتظهيرات نفسها، ما الاختبار المطلوب عمومًا؟","options":["لا تُطلب أي اختبارات تحريرية للفئة والتظهيرات المعادلة","يجب إعادة كل من الاختبار التحريري واختبار المهارات","يجب إعادة اختبار المهارات على الطريق فقط","يجب تكرار فحص ما قبل الرحلة فقط"],"explanation":"لا تتطلب نيومكسيكو اختبارات تحريرية لاستبدال CDL سارية من ولاية أخرى بـ CDL في نيومكسيكو من الفئة والتظهيرات نفسها. (لا يزال تظهير Hazmat يتطلب اختباره الخاص وفحص خلفية TSA.) المصدر: MVD New Mexico، متطلبات الحصول على CDL في نيومكسيكو."},"96":{"q":"إضافة إلى اختبار المعرفة التحريري، يجب على المتقدم للحصول على CDL في نيومكسيكو الساعي للحصول على تظهير المواد الخطرة (Hazmat) أن يكمل أيضًا ماذا؟","options":["أخذ البصمات وتقييم تهديد أمني من TSA (فحص خلفية)","اختبار قيادة ليلية منفصل على الطريق","دورة قيادة دفاعية مدتها 10 أيام","فحص نظر في عيادة تديرها الولاية"],"explanation":"يجب على السائق في نيومكسيكو الساعي للحصول على تظهير Hazmat اجتياز اختبار معرفة Hazmat وأخذ بصماته لإجراء تقييم تهديد أمني من TSA (فحص خلفية) قبل منح التظهير. المصدر: MVD New Mexico، متطلبات الحصول على CDL في نيومكسيكو؛ برنامج تقييم تهديد تظهير Hazmat التابع لـ TSA."},"97":{"q":"عندما يعود المتقدم للحصول على CDL في نيومكسيكو إلى MVD لاستلام الـ CDL بعد اجتياز اختبار المهارات، تُقدَّم نتائج الاختبار عادةً بأي شكل؟","options":["مظروف مختوم يحتوي على درجات اختبار المهارات، يُقدَّم مع CLP والمستندات المطلوبة","بريد إلكتروني يُرسَل مباشرة من الفاحص إلى FMCSA","تقرير شفهي يُعطى فقط لمشرف الفاحص","درجة مطبوعة على ظهر تسجيل مركبة اختبار الطريق"],"explanation":"بعد اجتياز اختبار المهارات الذي يجريه فاحص CDL معتمد، يعود المتقدم إلى MVD ومعه رخصة القيادة الخاصة به، وCLP، ومظروف مختوم يحتوي على درجات اختبار المهارات لإصدار الـ CDL. المصدر: MVD New Mexico، متطلبات الحصول على CDL في نيومكسيكو."}}};
